INSERT INTO effects (scope, an_an_id, body)
SELECT
  'character' AS scope,
  v.an_id AS an_an_id,
  jsonb_build_object(
    'set',
    jsonb_build_array(
      jsonb_build_object('var', 'characterRaw.money.crowns'),
      jsonb_build_object(
        'jsonlogic_expression',
        jsonb_build_object(
          'if',
          jsonb_build_array(
            jsonb_build_object(
              'in',
              jsonb_build_array(
                'dlc_wt',
                jsonb_build_object('var', jsonb_build_array('dlcs', jsonb_build_array()))
              )
            ),
            jsonb_build_object(
              '*',
              jsonb_build_array(
                10,
                jsonb_build_object('d6', jsonb_build_array())
              )
