  ) AS body;

-- Эффекты: добавление начальных навыков в characterRaw.skills.initial[]
WITH skill_mapping (skill_name) AS ( VALUES
    ('resist_coercion'),      -- Сопротивление убеждению
    ('courage'),              -- Храбрость
