                , 'answer_options' AS entity)
-- Базовые правила видимости (профессия "Маг" только для расы Human или Elf)
, rule_parts AS (
  SELECT
    (SELECT r.body FROM rules r WHERE r.name = 'is_human' ORDER BY r.ru_id LIMIT 1) AS is_human_expr,
    (SELECT r.body FROM rules r WHERE r.name = 'is_elf' ORDER BY r.ru_id LIMIT 1) AS is_elf_expr
)
, vis_rules AS (
  INSERT INTO rules (ru_id, name, body)
  SELECT
    ck_id('witcher_cc.rules.wcc_profession.mage') AS ru_id,
    'wcc_profession_mage' AS name,
    jsonb_build_object(
      'or',
      jsonb_build_array(
        rule_parts.is_human_expr,
        rule_parts.is_elf_expr
      )
    ) AS body
  FROM rule_parts
  ON CONFLICT (ru_id) DO NOTHING
  RETURNING ru_id
)
