                       , meta.entity, 'body', v.lang, v.text
                    FROM (VALUES
                            ('ru', 'Выберете родину вашего персонажа.'),
                            ('en', 'Choose your character''s homeland.')) AS v(lang, text)
                    CROSS JOIN meta)
, c_vals(lang, num, text) AS (VALUES ('ru', 1, 'Шанс'),
                                     ('ru', 2, 'Регион'),
                                     ('ru', 3, 'Место'),
                                     ('ru', 4, 'Эффект'),
                                     ('en', 1, 'Chance'),
