, vals AS (
           SELECT ('<td>' || to_char(probability*100, 'FM990.00') || '%</td>' ||
                   '<td>' || region || '</td>' ||
                   '<td>' || place_name || '</td>' ||
                   '<td>' || effect || '</td>') AS text,
