VALUES ('lifeEventsCounter_is_valid',
'{
  "<=":
    [
      {
        "+":
          [
            {
              "var":"counters.lifeEventsCounter"
            },
            10
          ]
      },
      {
        "var": "characterRaw.age"
      }
    ]
}'::jsonb);
-- <<< END sql/013_ch_age.sql

