              ) AS raw_data_en(num, group_id)
)
INSERT INTO effects (scope, an_an_id, body)
SELECT 'character', 'wcc_past_family_fate_o' || to_char(vals.group_id, 'FM9900') || to_char(vals.num, 'FM9900'),
