      jsonb_build_object('var','characterRaw.lore.friend'),
      jsonb_build_object('i18n_uuid', ck_id(meta.su_su_id ||'.'|| meta.qu_id ||'_o'|| to_char(100*raw_data.group_id+raw_data.num, 'FM0000') ||'.'|| meta.entity ||'.'|| 'friend')::text)
    )
  )
