      'label' AS entity_field
  )
, vals AS (
  SELECT v.*
    FROM (VALUES
      ('ru', 1, 'Медведь'),
      ('ru', 2, 'Кабан'),
      ('ru', 3, 'Птица'),
      ('ru', 4, 'Змея'),
      ('ru', 5, 'Насекомое'),
      ('en', 1, 'Bear'),
      ('en', 2, 'Boar'),
