      jsonb_build_object('var', 'characterRaw.lore.witcher_initiation_moment'),
      jsonb_build_object('i18n_uuid', ck_id(meta.su_su_id ||'.'|| meta.qu_id ||'_o02.'|| meta.entity ||'.description')::text)
    )
  )
FROM meta
UNION ALL
SELECT 'character', 'wcc_witcher_when_o03',
