      jsonb_build_object('i18n_uuid', ck_id(meta.su_su_id ||'.'|| meta.qu_id ||'_o03.'|| meta.entity ||'.description')::text)
    )
  )
FROM meta;


-- Связи
INSERT INTO transitions (from_qu_qu_id, to_qu_qu_id)
