           SELECT jsonb_agg(ck_id('witcher_cc' ||'.'|| 'wcc_witcher_events_benefit' ||'.'|| to_char(num, 'FM9900') ||'.'|| 'questions' ||'.'|| 'column_name')::text ORDER BY num)
           FROM (SELECT DISTINCT num FROM c_vals) AS cols
         ),
         'path', jsonb_build_array(
