-- Эффект: добавление события в lifeEvents (привязан к вопросу)
WITH
  meta AS (SELECT 'witcher_cc' AS su_su_id
                , 'wcc_witcher_events_ally_death_reason' AS qu_id
                , 'character' AS entity)
-- i18n для description "Союзник"
, ins_desc_ally AS (
