-- >>> BEGIN sql/items/005_wcc_item_weapons.sql

\echo '005_wcc_item_weapons.sql'
CREATE TABLE IF NOT EXISTS wcc_item_weapons (
    w_id            varchar(10) PRIMARY KEY,          -- e.g. 'W001'
    dlc_dlc_id      varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id), -- source_id (core, hb, dlc_*, exp_*)
    weapon_class_id uuid NOT NULL,                    -- ck_id('weapons.'||class_id) where class_id is wt_crossbow, wt_sword, etc.

    name_id         uuid NOT NULL,                    -- ck_id('witcher_cc.items.weapon.name.'||w_id)

    is_piercing     uuid NULL,                        -- ck_id('witcher_cc.items.weapon.damage_type.P')
    is_slashing     uuid NULL,                        -- ck_id('witcher_cc.items.weapon.damage_type.S')
    is_bludgeoning  uuid NULL,                        -- ck_id('witcher_cc.items.weapon.damage_type.B')
    is_elemental    uuid NULL,                        -- ck_id('witcher_cc.items.weapon.damage_type.E')

    accuracy        integer NOT NULL,                 -- can be negative
    crafted_by_id      uuid NULL,                        -- ck_id('witcher_cc.items.weapon.crafted_by.Humans'|'Non-humans'|'Witchers')
    availability_id    uuid NULL,                        -- ck_id('witcher_cc.items.weapon.availability.E'|'C'|'P'|'R'|'U')
    dmg             varchar(32) NULL,                 -- e.g. '4d6+3' (kept as text)

    damage_dices    integer NULL,
    damage_modifier integer NULL,

    reliability     integer NOT NULL,
    hands           integer NULL,

    range           varchar(32) NULL,                 -- e.g. '100' or 'Тел*4' (as text)
    concealment_id     uuid NULL,                        -- ck_id('witcher_cc.items.weapon.concealment.T'|'S'|'L'|'N/A')
    enhancements    integer NOT NULL DEFAULT 0,

    weight           numeric(12,1) NULL,               -- stored after REPLACE(',', '.')
    price           integer NULL,               -- stored after REPLACE(',', '.')

    description_id  uuid NOT NULL                     -- ck_id('witcher_cc.items.weapon.description.'||w_id)
);

COMMENT ON TABLE wcc_item_weapons IS
  'Оружие/боеприпасы/бомбы и т.п. Хранит локализуемые поля как i18n UUID.';

COMMENT ON COLUMN wcc_item_weapons.dlc_dlc_id IS
  'FK на wcc_dlcs.dlc_id (источник/пакет: core/hb/dlc_*/exp_*).';

COMMENT ON COLUMN wcc_item_weapons.weapon_class_id IS
  'i18n UUID для класса оружия. Генерируется детерминированно: ck_id(''weapons.''||class_id) где class_id это wt_crossbow, wt_sword и т.д.';

COMMENT ON COLUMN wcc_item_weapons.name_id IS
  'i18n UUID для названия оружия. Генерируется детерминированно: ck_id(''witcher_cc.items.weapon.name.''||w_id).';

COMMENT ON COLUMN wcc_item_weapons.description_id IS
  'i18n UUID для описания оружия. Генерируется детерминированно: ck_id(''witcher_cc.items.weapon.description.''||w_id).';

COMMENT ON COLUMN wcc_item_weapons.availability_id IS
  'i18n UUID для доступности оружия. Использует ключи из словаря: ck_id(''availability.''||<E|C|P|R|U>). Значения: Повсеместный (E), Обычный (C), Редкий (P), Редкий (R), Уникальный (U).';

COMMENT ON COLUMN wcc_item_weapons.crafted_by_id IS
  'i18n UUID для производителя оружия. Использует ключи из словаря: ck_id(''crafted_by.''||<humans|non-humans|witchers>). Значения: Люди (humans), Нелюди (non-humans), Ведьмаки (witchers).';

COMMENT ON COLUMN wcc_item_weapons.concealment_id IS
  'i18n UUID для скрытности оружия. Использует ключи из словаря: ck_id(''concealment.''||<T|S|L|N/A>). Значения: М (T), Н (S), К (L), Н/C (N/A).';

COMMENT ON COLUMN wcc_item_weapons.is_piercing IS
  'i18n UUID для типа урона: колющий. Использует ключи из словаря: ck_id(''damage_type.P''). Значения: К (P).';

COMMENT ON COLUMN wcc_item_weapons.is_slashing IS
  'i18n UUID для типа урона: рубящий. Использует ключи из словаря: ck_id(''damage_type.S''). Значения: Р (S).';

COMMENT ON COLUMN wcc_item_weapons.is_bludgeoning IS
  'i18n UUID для типа урона: дробящий. Использует ключи из словаря: ck_id(''damage_type.B''). Значения: Д (B).';

COMMENT ON COLUMN wcc_item_weapons.is_elemental IS
  'i18n UUID для типа урона: стихийный. Использует ключи из словаря: ck_id(''damage_type.E''). Значения: С (E).';

WITH raw_data (w_id, source_id, class_id, name_ru, name_en, is_piercing, is_slashing, is_bludgeoning, is_elemental, accuracy, crafted_by_id, availability_id , dmg, damage_dices, damage_modifier, reliability, hands, range, concealment_id, enhancements, weight, price, description_ru) AS ( VALUES
    ('W001', 'core', 'wt_crossbow', 'Арбалет', 'Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'humans', 'E', '4d6+3', 4, 3, 5, 2, '100', 'XL', 1, '3', '455', 'Крепкий, точный, мощный. Да, я предвзято говорю, но арбалет я обожаю. На перезарядку требуется время, это да, но хороший стрелок нашпигует противника болтами с точностью, которая большинству человеческих лучников и не снилась. Ложе можно к плечу приложить, чтобы вдоль него прицелиться, - так выстрел точнее будет. Я с таким арбалетом прошёл всю Вторую войну - добрую он сослужил мне службу.'),
    ('W002', 'core', 'wt_crossbow', 'Арбалет охотника на чудовищ', 'Monster Hunter’s Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'humans', 'R', '6d6', 6, NULL, 15, 2, '200', 'XL', 1, '4', '1125', 'В наши дни чудовищ не так уж много. Я, пожалуй, могу пересчитать встреченных тварей по пальцам одной руки. Но всё же чудовища раз от раза вылезают, а поскольку ведьмаков тоже совсем мало соталось, какой-то сукин сын с юга придумал вот такую игрушку. Больше метра длиной, столько же в плечах. Говорят, что арбалет этот надо воротом взводить, а выстрел у него силой в 136 килограмм. Решили, видать, что раз уж для убийства чудовища надо нехило так приложить силушки, чего б не сделать, курва, ручную баллисту, чтобы издалека их отстреливать.'),
    ('W003', 'hb', 'wt_crossbow', 'Арбалет школы Волка', 'Wolven Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 5, 1, '50', 'L', 1, '0,5', NULL, ''),
    ('W004', 'dlc_wt', 'wt_crossbow', 'Арбалет школы Грифона', 'Griffin Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 5, 1, '50', 'L', 1, '0,5', NULL, ''),
    ('W005', 'hb', 'wt_crossbow', 'Арбалет школы Змеи', 'Serpentine Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 5, 1, '50', 'L', 1, '0,5', NULL, ''),
    ('W006', 'dlc_wt', 'wt_crossbow', 'Арбалет школы Кота', 'Feline Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 5, 1, '50', 'L', 1, '0,5', NULL, ''),
    ('W007', 'hb', 'wt_crossbow', 'Арбалет школы Мантикоры', 'Manticore Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 5, 1, '50', 'L', 1, '0,5', NULL, ''),
    ('W008', 'dlc_wt', 'wt_crossbow', 'Арбалет школы Медведя', 'Ursine Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'witchers', 'R', '4d6+2', 4, 2, 5, 1, '50', 'L', 1, '0,5', NULL, ''),
    ('W009', 'core', 'wt_crossbow', 'Гномий ручной арбалет', 'Gnomish Hand Crossbow', 'TRUE', NULL, NULL, NULL, 3, 'non-humans', 'R', '2d6', 2, NULL, 10, 1, '100', 'M', 1, '1', '425', 'Не особо люблю ручные арбалеты, но вот такое оружие гномей работы мне нравится. Настоящее произведение искусства: тонкая работа по металлу да чёрное травлёное дерево с изящной резьбой.'),
    ('W010', 'core', 'wt_crossbow', 'Краснолюдский тяжёлый арбалет', 'Dwarven Heavy Crossbow', 'TRUE', NULL, NULL, NULL, 3, 'non-humans', 'R', '5d6', 5, NULL, 15, 2, '300', 'XL', 2, '3,5', '850', 'Мы, краснолюды, будем посильнее людей. Может, мы и ниже, чем люди и эльфы, но уж точно крепче. Краснолюдский арбалет создан как раз с учётом нашей силушки - когда мы их продаём людям и эльфам, приходится ещё и рычаг им впаривать, чтобы натянуть могли.'),
    ('W011', 'exp_bot', 'wt_crossbow', 'Охотничий арбалет', 'Huntsman’s Crossbow', 'TRUE', NULL, NULL, NULL, 2, 'humans', 'C', '5d6', 5, 0, 10, 2, '150', 'L', 1, '3', '600', ''),
    ('W012', 'core', 'wt_crossbow', 'Ручной арбалет', 'Hand Crossbow', 'TRUE', NULL, NULL, NULL, 1, 'humans', 'E', '2d6+2', 2, 2, 5, 1, '50', 'L', 1, '0,5', '285', 'Не знаю точно, где они впервые появились. Думается мне, изначально это оружие было для гражданских. Думается мне, изначально это оружие было для гражданских. Такой арбалетик небольшой, заметно слабее обычного, зато держать его можно одной рукой, да и стреляешь из такого поточнее. В наши дни их используют для защиты родной хаты: немногие могут себе позволить учиться боевому делу, а чтобы стрелять из арбалета, много ума не надо.'),
    ('W013', 'dlc_rw2', 'wt_crossbow', 'Скорпио', 'Scorpio', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'R', '10d6', 10, 0, 20, 2, '200', 'XL', 0, '40', '2500', ''),
    ('W014', 'core', 'wt_crossbow', 'Красная Смерть', 'Red Death', 'TRUE', NULL, NULL, NULL, 2, 'humans', 'U', '10d6', 10, NULL, 15, 2, '300', 'XL', 3, '2,5', NULL, ''),
    ('W015', 'core', 'wt_ammo', 'Бронебойная стрела', 'Bodkin Arrow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'C', NULL, NULL, NULL, 10, NULL, NULL, 'S', NULL, '0,1', '15', 'Боеприпасы с затупленным или широким наконечником хороши, если у твоего противника брони нет. Проблема в том, что большинству ума хватает хотя бы самую плохонькую броньку-то надеть, так что приходится изрядно постараться, чтобы их достать. Вот для таких ситуаций и нужны бронебойные наконечники - длинные, узкие, закалённые в огне. Прекрасно пробивают как кожу, так и сталь.'),
    ('W016', 'core', 'wt_ammo', 'Взрывная стрела', 'Explosive Arrow', NULL, NULL, NULL, 'TRUE', 0, 'humans', 'R', '4d6', 4, NULL, 1, NULL, NULL, 'S', NULL, '0,1', '108', 'К взырвному боеприпасу прикреплена скляночка с бахающей химозой. При столкновениий склянка лопается да как жахнет по всем частям тела любого в радиусе пары метров!'),
    ('W017', 'core', 'wt_ammo', 'Выслеживающая стрела', 'Tracking Arrow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'R', NULL, NULL, NULL, 1, NULL, NULL, 'S', NULL, '0,1', '22', 'Вонючей дрянью они измазаны. Советую хранить в чехольчике. Зато коль засадишь в кого, то без усилий выследишь след с твоим то нюхом! Ну по крайней мере в первые пол суток.'),
    ('W018', 'hb', 'wt_ammo', 'Гавенкарская разбрызгивающая стрела', 'HavenKar Bloom Arrow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'R', '+3', NULL, 3, 5, NULL, NULL, 'S', NULL, '0,1', '130', ''),
    ('W019', 'core', 'wt_ammo', 'Краснолюдская пробивная стрела', 'Dwarven Impact Arrow', NULL, NULL, 'TRUE', NULL, 0, 'non-humans', 'R', NULL, NULL, NULL, 15, NULL, NULL, 'S', NULL, '0,1', '50', 'По слухам, мы стали пользоваться такими стрелами и болтами, чтобы ломать камни в копях, но ныне краснолюбским наёмникам эти наконечники служат для того, чтобы пробивать латные доспехи.'),
    ('W020', 'core', 'wt_ammo', 'Разделяющаяся стрела', 'Split Arrow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'R', NULL, NULL, NULL, 1, NULL, NULL, 'S', NULL, '0,3', '54', 'Убойная вещь, прям уважаю. Эдакая связка боеприпасов, связанная едва держащимся хлыстиком. После выстрела он лопается и вот в тебя летят уж три снаряда по цене одного! {devider} За каждый пункт свыше защиты цели (до 3-х) вы наносите полный урон в случайную часть тела.'),
    ('W021', 'core', 'wt_ammo', 'Стрела с затупленным наконечником', 'Blunt Arrow', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'C', NULL, NULL, NULL, 10, NULL, NULL, 'S', NULL, '0,1', '5', 'Стрелы  и болты с затупленным наконечником - штучки любопытные. Сам я такими никогда не пользовался. Да и не сражался толком с теми, кого широкий наконечник не возьмет. У таких боеприпасов здоровенный деревянный наконечник, похожий на кулак. Говорят, даже если таким в полнатяга стрелять, можно издалека вырубить противника.'),
    ('W022', 'core', 'wt_ammo', 'Стрела с широким наконечником', 'Broadhead Arrow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'C', NULL, NULL, NULL, 10, NULL, NULL, 'S', NULL, '0,1', '10', 'Боеприпасы с широким наконечником - одни из лучших. Они во многом похожи на стандартные стрелы и болты, только наконечник у них широкий, плоский и заострённый по краям. Форма и размер разными бывают: есть листья, ромбики, в форме буквы V, но все они всаживаются куда глубже обычных стрел, оставляя кровоточащие раны.'),
    ('W023', 'hb', 'wt_ammo', 'Серебряная стрела', 'Silver Arrow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'P', NULL, NULL, NULL, 10, NULL, NULL, 'S', NULL, '0,1', '16', ''),
    ('W024', 'core', 'wt_ammo', 'Стандартные стрелы (х10)', 'Standard Arrows (x10)', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'E', NULL, NULL, NULL, 10, NULL, NULL, 'S', NULL, '0,5', '10', 'Если есть стрелковое оружие, нужны и боеприпасы. Стандартнвые боеприпасы - стрелы да болты. Вторые обычно меньше первых, но и у тех, и у других, есть оперение и острый мталлический наконечник.'),
    ('W025', 'core', 'wt_ammo', 'Эльфские ввинчивающаяся стрела', 'Elven Burrower Arrow', 'TRUE', NULL, NULL, NULL, 0, 'non-humans', 'R', NULL, NULL, NULL, 10, NULL, NULL, 'S', NULL, '0,1', '50', 'Скоя''таэли пару лет назад приобрели их у человеческих торговцев и стали активно использовать. Наконечник по форме напоминает винт, из-за чего снаряд буквально ввинчивается в плоть, и вытащить его становится тяжеловато.'),
    ('W026', 'dlc_rw2', 'wt_ammo', 'Бронебойный болт для Скорпио', 'Piercing Scorpio Bolt (x5)', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'R', NULL, NULL, NULL, 10, NULL, NULL, 'M', NULL, '2', '75', ''),
    ('W027', 'dlc_rw2', 'wt_ammo', 'Разрушающий болт для Скорпио', 'Breaker Scorpio Bolt (x5)', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'R', NULL, NULL, NULL, 10, NULL, NULL, 'M', NULL, '2', '75', ''),
    ('W028', 'dlc_rw2', 'wt_ammo', 'Стандартный болт для Скорпио', 'Standard Scorpio Bolt (x5)', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'R', NULL, NULL, NULL, 10, NULL, NULL, 'M', NULL, '2', '50', ''),
