    ('W042', 'hb', 'wt_tool', 'Кочерга', 'Poker', 'TRUE', NULL, 'TRUE', NULL, 0, 'humans', 'E', '2d6+2', 2, 2, 10, 1, '2', 'L', 0, '2', '137', ''),
