    ('W044', 'exp_lal', 'wt_tool', 'Ламия', 'Lamia', NULL, 'TRUE', NULL, NULL, -1, 'humans', 'R', '3d6+1', 3, 1, 5, 1, '2', 'M', 1, '0,5', '600', ''),
    ('W045', 'hb', 'wt_tool', 'Ледоруб', 'Ice Axe', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'E', '1d6+2', 1, 2, 10, 1, NULL, 'S', 0, '1', '77', ''),
    ('W046', 'dlc_rw1', 'wt_tool', 'Лопата', 'Shovel', NULL, NULL, 'TRUE', NULL, -2, 'humans', 'E', '2d6', 2, NULL, 15, 2, NULL, 'L', 0, '1,5', '15', ''),
    ('W047', 'exp_bot', 'wt_tool', 'Пятиметровая цепь', '5m Chain', 'TRUE', NULL, NULL, NULL, -2, 'humans', 'E', '2d6+4', 2, 4, 15, 2, NULL, 'XL', 0, '2', '80', ''),
    ('W048', 'dlc_prof_peasant', 'wt_tool', 'Серп', 'Sickle', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'E', '1d6+2', 1, 2, 10, 1, NULL, 'S', 0, '1', '76', ''),
    ('W049', 'dlc_rw2', 'wt_tool', 'Утяжелённая сеть', 'Weighted Net', NULL, NULL, NULL, NULL, 0, 'humans', 'E', NULL, 0, NULL, 5, 2, NULL, 'L', 0, '4', '125', ''),
    ('W050', 'dlc_rw2', 'wt_tool', 'Сеть охотника на монстров', 'Monster Catcher’s Net', NULL, NULL, NULL, NULL, 0, 'humans', 'R', NULL, 0, NULL, 5, 2, NULL, 'L', 0, '4', '500', ''),
    ('W051', 'dlc_rw1', 'wt_tool', 'Факел', 'Torch', NULL, NULL, 'TRUE', NULL, -1, 'humans', 'E', '1d6', 1, NULL, 5, 1, NULL, 'M', 0, '0,1', '1', ''),
    ('W052', 'dlc_rw2', 'wt_tool', 'Шприц полевого врача', 'Field Doctor’s Syringe', 'TRUE', NULL, NULL, NULL, 1, 'humans', 'P', '1d6', 1, NULL, 5, 1, NULL, 'S', 0, '0,5', '350', ''),
    ('W053', 'hb', 'wt_pole', 'Алебарда-секач', 'Cleaving Halberd', 'TRUE', 'TRUE', 'TRUE', NULL, 0, 'humans', 'P', '5d6+2', 5, 2, 10, 2, '2', 'XL', 1, '3', '568', ''),
    ('W054', 'exp_bot', 'wt_pole', 'Боевое копьё', 'War Lance', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'P', '2d6', 2, NULL, 10, 1, '2', 'XL', 0, '3,5', '550', ''),
    ('W055', 'core', 'wt_pole', 'Копьё', 'Spear', 'TRUE', NULL, 'TRUE', NULL, 0, 'humans', 'E', '3d6', 3, NULL, 10, 2, '2', 'XL', 1, '3,5', '375', 'Любимое оружие пехоты. Не маленькое, в среднем два метра в длину, зато поможет врага удержать подальше, да и кавалерии не даст тебя затоптать. Служа арбалетчиком в армии, я копья полюбил: нас от кавалерии нильфов как раз защищал отряд копейщиков.'),
    ('W056', 'dlc_prof_peasant', 'wt_pole', 'Коса', 'Scythe', 'TRUE', 'TRUE', NULL, NULL, -3, 'humans', 'E', '3d6', 3, NULL, 10, 2, NULL, 'XL', 0, '3,5', '126', ''),
    ('W057', 'core', 'wt_pole', 'Красная алебарда', 'Red Halberd', 'TRUE', 'TRUE', 'TRUE', NULL, 0, 'humans', 'P', '6d6+3', 6, 3, 10, 2, '2', 'XL', 1, '4', '865', 'Реданские алебардщики - одни из самых организованных и опасных воинов на Севере. Эти шлюхины дети сдерживают атаку кавалерии и пехоты на раз-два. Алебарды, которыми они вооружены, - настоящие произведения искусства. Двухметровое древко с тяжёлым широким лезвием и с шипами сзади и сверху.'),
    ('W058', 'core', 'wt_pole', 'Краснолюдский боевой молот', 'Dwarven Pole Hammer', 'TRUE', NULL, 'TRUE', NULL, 0, 'non-humans', 'R', '5d6+2', 5, 2, 15, 2, '2', 'XL', 1, '4', '835', 'Махакамские краснолюды выковали первые боевые молоты несколько веков тому назад для защиты от любого сукина сына, которому духу хватит напасть. На крепкой двухметровой рукояти закреплена сложная головка с длинным шипом сверху и крюком сзади. Универсальное оружие. Прям-таки машина для убийства.'),
    ('W059', 'dlc_prof_peasant', 'wt_pole', 'Палка', 'Quarter Staff', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'E', '2d6', 2, NULL, 10, 2, '2', 'XL', 0, '3', '96', ''),
    ('W060', 'dlc_prof_peasant', 'wt_pole', 'Пастуший посох', 'Shepherd’s Crook', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'E', '1d6-2', 1, -2, 10, 1, NULL, 'L', 0, '1', '14', ''),
    ('W061', 'exp_bot', 'wt_pole', 'Протазан', 'Partisan', 'TRUE', 'TRUE', 'TRUE', NULL, 1, 'humans', 'C', '4d6+2', 4, 2, 10, 2, '2', 'XL', 1, '3,5', '750', ''),
    ('W062', 'core', 'wt_pole', 'Секира', 'Pole Axe', 'TRUE', 'TRUE', 'TRUE', NULL, 0, 'humans', 'P', '4d6+2', 4, 2, 10, 2, '2', 'XL', 0, '3', '460', 'Эту лёгкую секиру выковал кузнец-краснолюд из Повисса. На длинном древке закреплён увесистый доёк: с одной стороны у него топор, а с другой - молот. А сверху острый шип торчит. Это универсальное оружие создано, чтобы разбираться с любой бронёй. Если хочешь держать нейтралитет, надо иметь хорошее оружие.'),
    ('W063', 'exp_bot', 'wt_pole', 'Турнирное копьё', 'Blunted Lance', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'P', '2d6', 2, NULL, 5, 1, '2', 'XL', 0, '3,5', '500', ''),
    ('W064', 'hb', 'wt_pole', 'Фальшарда', 'Fauchard', 'TRUE', 'TRUE', 'TRUE', NULL, 0, 'humans', 'E', '3d6+2', 3, 2, 10, 2, '2', 'XL', 1, '1,5', '412', ''),
    ('W065', 'exp_lal', 'wt_pole', 'Человеколов', 'Mancatcher', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'P', '3d6+3', 3, 3, 15, 2, '2', 'XL', 0, '3', '463', ''),
    ('W066', 'core', 'wt_pole', 'Эльфская глефа', 'Elven Glaive', 'TRUE', 'TRUE', 'TRUE', NULL, 2, 'non-humans', 'R', '4d6+3', 4, 3, 10, 2, '2', 'XL', 2, '3', '925', 'Слыхал я, что глефы были самым популярным оружием в золотой век эльфов, еще до прибытия людей. Полагаю, их использовала дворцовая стража. Длинное древко, на котором сверху закреплено бритвенно острое лезвие. Учитывая то, что большинство эльфов на севере сейчас пряутся, они, скорее всего, не могут себе позволить таскать такие большие штуки, как глефа.'),
    ('W067', 'core', 'wt_pole', 'Страж Бездны', 'The Abyss Guard', 'TRUE', NULL, 'TRUE', NULL, 2, 'humans', 'U', '7d6+4', 7, 4, 10, 2, '2', 'XL', 3, '4', NULL, ''),
    ('W068', 'exp_bot', 'wt_bludgeon', 'Крестьянский молот', 'Peasant’s Maul', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'E', '5d6', 5, NULL, 5, 2, NULL, 'XL', 0, '3', '375', ''),
    ('W069', 'core', 'wt_bludgeon', 'Булава', 'Mace', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'C', '5d6', 5, NULL, 15, 1, NULL, 'L', 0, '2', '525', 'Серьёзная игрушка. Цельный кусок металла с выступающими лопастями и шипами. Удар булавой способен переломать кости. Знаю многих наёмников, которые с собой это оружие таскают только ради того, чтобы пробивать броню.'),
    ('W070', 'hb', 'wt_bludgeon', 'Дубинка', 'Club', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'E', '2d6+2', 2, 2, 10, 1, NULL, 'S', 0, '1', '83', ''),
    ('W071', 'exp_bot', 'wt_bludgeon', 'Клевец', 'Horseman’s Hammer', 'TRUE', NULL, 'TRUE', NULL, 0, 'humans', 'C', '2d6', 2, NULL, 10, 1, NULL, 'XL', 1, '2,5', '860', ''),
    ('W072', 'core', 'wt_bludgeon', 'Кастет', 'Brass Knuckles', NULL, NULL, 'TRUE', NULL, 1, 'humans', 'E', '1d6', 1, NULL, 15, 1, NULL, 'S', 1, '0,5', '50', 'Друже, мир - место несправедливое. И некоторым просто не повезло родиться слабыми. Обычно мне не приходится идти с врагом врукопашную - да-да, преимущество арбалетчика, - но если бы мне надо было регулярно чистить рожи, я бы обазвёлся кастетом, чтобы кулаком большее бить.'),
    ('W073', 'exp_lal', 'wt_bludgeon', 'Кистень', 'Flail', 'TRUE', NULL, 'TRUE', NULL, -1, 'humans', 'P', '4d6+2', 4, 2, 10, 1, NULL, 'L', 1, '2', '562', ''),
    ('W074', 'core', 'wt_bludgeon', 'Кистень из метеоритной стали', 'Meteorite Chain Mace', NULL, NULL, 'TRUE', NULL, 2, 'non-humans', 'R', '6d6', 6, NULL, 20, 1, NULL, 'XL', 2, '4', '900', 'Стильная игрушка. Шипастый шар из метеоритной стали на цепочке, которая крепится к обмотанной кожей рукояти. На полной скорости шар проламывает шлем вместе с черепом, примерно как если бы в голову попал настоящий метеорит. А цепью можно не только оружие ловить...'),
    ('W075', 'core', 'wt_bludgeon', 'Махакамский мартель', 'Mahakaman Martell', NULL, NULL, 'TRUE', NULL, 0, 'non-humans', 'R', '5d6', 5, NULL, 15, 2, NULL, 'L', 1, '3,5', '750', 'Мартель - краснолюдское оружие, достаточно редкое. Нечасто видишь, как с ним люди шастают. По сути, это молот с длинным шипом с обратной стороны, насаженный на метровую рукоять. Многие краснолюды предпочитают укорачивать рукоять и носить это оружие за голенищем сапога.'),
    ('W076', 'core', 'wt_bludgeon', 'Молот горца', 'Highland Mauler', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'R', '6d6+2', 6, 2, 20, 2, NULL, 'XL', 1, '3', '1100', 'Каэдвенцы - ребята крупные. Если бы меня попросили назвать самых крепких засранцев в мире, то я толчно выбрал бы островитян со Скеллиге, каэдвенцев и геммерцев. Но вот эти вот молоты дают каэдвенцам преимущество. За свою жизнь я продал только два таких, но они действительно огромны. Почти два метра длиной, со здоровенным навершием, выложенным метеоритной сталью.'),
    ('W077', 'hb', 'wt_bludgeon', 'Нагайка', 'Riding Whip', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'E', '2d6', 2, NULL, 10, 1, NULL, 'S', 0, '1', '115', ''),
    ('W078', 'core', 'wt_bludgeon', 'Огх''р', 'Ogh’r', NULL, NULL, 'TRUE', NULL, 0, 'non-humans', 'U', '10d6', 10, NULL, 15, 2, NULL, 'XL', 3, '5', NULL, ''),
    ('W079', 'exp_lal', 'wt_sblade', 'Дага', 'Parrying Dagger', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'C', '2d6', 2, NULL, 10, 1, NULL, 'M', 1, '1', '350', ''),
    ('W080', 'core', 'wt_sblade', 'Джамбия', 'Jambiya', 'TRUE', 'TRUE', NULL, NULL, 2, 'humans', 'R', '2d6', 2, NULL, 10, 1, NULL, 'M', 1, '0,5', '440', 'Друже, даже в далёокй Зеррикании смерть - самая твёрдая валюта. И именно там куют один из лучших кинжалов в мире. Впервые эти странные кривые штуки мы заметили у ассасинов из Мехта во время Первой войны.'),
    ('W081', 'dlc_wt', 'wt_sblade', 'Змеиный клык', 'Viper’s Fang', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 10, 1, NULL, 'M', 1, '0,5', NULL, ''),
    ('W082', 'core', 'wt_sblade', 'Кинжал', 'Dagger', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'E', '1d6+2', 1, 2, 10, 1, NULL, 'M', 0, '0,5', '50', 'Кинжалы бывают разной формы и размеров, но обычно они достаточно малы, чтобы влезать в карман. Кинжал при себе носят все, от рыцарей до крестьян.'),
    ('W083', 'core', 'wt_sblade', 'Короткий кинжал', 'Poniard', 'TRUE', 'TRUE', NULL, NULL, 1, 'humans', 'P', '2d6+2', 2, 2, 10, 1, NULL, 'M', 0, '1', '350', 'Оружие старой доброй темерской работы. Длинное, тонкое и лёгкое. В битве под Содденом я с чёрным дрался, а из оружия у меня был лишь этот вот ножик. Нильф мне шесть рёбер переломал, вот только я то жив-здоров, а он - нет.'),
    ('W084', 'core', 'wt_sblade', 'Краснолюдский секач', 'Dwarven Cleaver', NULL, 'TRUE', 'TRUE', NULL, 2, 'non-humans', 'R', '3d6', 3, NULL, 15, 1, NULL, 'M', 1, '1,5', '500', 'Ха! Вот кто-кто, а краснолюды могут притащить секач на бой на ножах. Если тебе надо прорубиться... да, честно говоря, через что угодно, то бери краснолюдский секач. Он недлинный, но прекрасно и конечности людям рубит, и ветки деревьев.'),
    ('W085', 'exp_toc', 'wt_sblade', 'Кинжал из кровавого камня', 'Bloodstone Dagger', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'R', '2d6', 2, NULL, 5, 1, NULL, 'M', 1, '0,5', NULL, ''),
    ('W086', 'dlc_rw2', 'wt_sblade', 'Ловец Мечей', 'Sword Catcher', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'P', '2d6', 2, NULL, 10, 1, NULL, 'M', 1, '1', '500', ''),
    ('W087', 'core', 'wt_sblade', 'Низушечий рондель', 'Halfling Rondel', 'TRUE', 'TRUE', NULL, NULL, 2, 'non-humans', 'R', '2d6+2', 2, 2, 10, 1, NULL, 'M', 1, '1', '485', 'Низушки куда ниже людей и куда хрупче краснолюдов. Не скажу, что они слабаки, но что-то не видно армий низушков. Этот кинжал для низушков в самый раз: тонкий и крепкий, с круглой головкой и гардой. Им очень легко колоть в стыки брони, оставляя кровоточащие раны.'),
    ('W088', 'hb', 'wt_sblade', 'Серебряный змеиный клык', 'Silver Viper Fang', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '1d6+2', 1, 2, 10, 1, NULL, 'M', 1, '0,5', NULL, ''),
    ('W089', 'core', 'wt_sblade', 'Стилет', 'Stiletto', 'TRUE', 'TRUE', NULL, NULL, 2, 'humans', 'C', '1d6', 1, NULL, 5, 1, NULL, 'S', 1, '0,5', '275', 'Вот уж кто-кто, а чёрные могут даже из обычного кинжала сделать ещё более подлое оружие. Длинный тонкий клинок этого кинжала убирается в рукоять, так что спрятать эту дрянь можно где угодно.'),
    ('W090', 'core', 'wt_sblade', 'Шип', 'Thorn', 'TRUE', 'TRUE', NULL, NULL, 3, 'non-humans', 'U', '3d6', 3, NULL, 15, 1, NULL, 'M', 3, '0,5', NULL, ''),
    ('W091', 'core', 'wt_trap', 'Бешенство', 'Fury', NULL, NULL, NULL, 'TRUE', 0, 'humans', 'P', NULL, NULL, NULL, 8, NULL, NULL, NULL, NULL, '2', '114', ''),
    ('W092', 'core', 'wt_trap', 'Капкан', 'Bear trap', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'C', '3d6', 3, NULL, 1, NULL, NULL, NULL, NULL, '2', '72', ''),
    ('W093', 'core', 'wt_trap', 'Когтезуб', 'Clawer', NULL, 'TRUE', NULL, NULL, 0, 'humans', 'P', '5d6', 5, NULL, 4, NULL, NULL, NULL, NULL, '2', '111', ''),
    ('W094', 'core', 'wt_trap', 'Кусач', 'Biter', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'P', '7d6', 7, NULL, 4, NULL, NULL, NULL, NULL, '2', '144', ''),
    ('W095', 'core', 'wt_trap', 'Метка', 'Marker', NULL, NULL, NULL, 'TRUE', 0, 'humans', 'P', NULL, NULL, NULL, 8, NULL, NULL, NULL, NULL, '2', '57', ''),
    ('W096', 'dlc_rw1', 'wt_trap', 'Мешочек с шариками', 'Bag of Marbles', NULL, NULL, NULL, NULL, 0, 'humans', 'E', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, '0,1', '18', ''),
    ('W097', 'core', 'wt_trap', 'Пожарище', 'Conflagration', NULL, NULL, NULL, 'TRUE', 0, 'humans', 'P', '5d6', 5, NULL, 4, NULL, NULL, NULL, NULL, '2', '121', ''),
    ('W098', 'core', 'wt_trap', 'Талгарская зима', 'Talgar Winter', NULL, NULL, NULL, 'TRUE', 0, 'humans', 'P', NULL, NULL, NULL, 4, NULL, NULL, NULL, NULL, '2', '126', ''),
    ('W099', 'core', 'wt_bow', 'Армейский лук', 'War Bow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'C', '6d6', 6, NULL, 15, 2, '300', 'XL', 1, '3', '835', 'Убойная штука. Создан для того, чтобы отстреливать рыцарей в крепких латах. Эта дура два метра высотой, с силой натяжения до 77 килограмм. Такие луки на поле боя часто встречаются - а что, стой себе и постреливай в небо, поливая врага дождём из стрел. Я то предпочитаю арбалетом орудовать, но уважаю бойцов, способных стрелять из этой громадины.'),
    ('W100', 'core', 'wt_bow', 'Длинный лук', 'Long Bow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'E', '4d6', 4, NULL, 10, 2, '200', 'XL', 1, '2', '475', 'Длинный лук - предок арбалета. Для меня они слишком громоздкие, держать их трудно. Но это я ростом не выдался. А вот эльфы на длинные луки чуть ли не молятся. В их руках это второе по смертоносности дальнобойное оружие после, мать её, баллисты. Люди в основном предпочитают арбалеты, хотя в Нильфгаарде полным-полно лучников, готовых наглядно доказать своё смертоносное мастерство.'),
    ('W101', 'hb', 'wt_bow', 'Ковирский ламинированный лук', 'Kovirian Laminated Bow', 'TRUE', NULL, NULL, NULL, 3, 'humans', 'R', '6d6', 6, NULL, 10, 2, '370', 'XL', 2, '1,5', '1371', ''),
    ('W102', 'core', 'wt_bow', 'Короткий лук', 'Short Bow', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'E', '3d6+3', 3, 3, 10, 2, '100', 'L', 0, '1', '290', 'На войне коротких луков раз-два и обчёлся. Они слишком маленькие, чтобы быть полезными на поле боя, да и дальность стрельбы у них не очень. Впрочем, такое оружие идеально подходит для охоты на оленя... или на проезжего купца.'),
    ('W103', 'core', 'wt_bow', 'Эльфский зефар', 'Elven Zefhar', 'TRUE', NULL, NULL, NULL, 2, 'non-humans', 'R', '6d6', 6, NULL, 10, 2, '350', 'XL', 2, '2,5', '1100', 'Гордость и отрада эльфов. Это длинный лук с четырьмя плечами, на который натянута крепкая вощёная тетива. Две пары плеч у зефара увеличивают силы выстрела в два раза. Что приятно, лук от этого тяжелее не становится.'),
    ('W104', 'core', 'wt_bow', 'Эльфский походный лук', 'Elven Travel Bow', 'TRUE', NULL, NULL, NULL, 1, 'non-humans', 'R', '4d6', 4, NULL, 10, 2, '200', 'L', 1, '1', '575', 'По сути, это просто уменьшенный зефар. Отличные в том, что с походного лука можно спокойно снять тетиву и согнуть его, чтобы запихнуть в сумку.'),
    ('W105', 'hb', 'wt_bow', 'Эльфский сдвоенный лук', 'Elven Double Bow', 'TRUE', NULL, NULL, NULL, 1, 'non-humans', 'R', '5d6', 5, NULL, 10, 2, '250', 'XL', 1, '2', '816', ''),
    ('W106', 'core', 'wt_bow', 'Лунный лук', 'The Moon Bow', 'TRUE', NULL, NULL, NULL, 1, 'non-humans', 'U', '8d6+2', 8, 2, 10, 2, '200', 'XL', 3, '2', NULL, ''),
    ('W107', 'core', 'wt_thrown', 'Метательный нож', 'Throwing Knife', 'TRUE', NULL, NULL, NULL, 0, 'humans', 'E', '1d6', 1, NULL, 5, 1, 'Тел*4', 'S', 0, '0,5', '50', 'Ножички эти - весьма занимательные штучки. Они маленькие (так что их легко спрятать) и сбалансированы для метания. Придётся попрактиковаться, чтобы запомнить скорость вращения и прочее, но оно того стоит. Хорошее оружие для убийцы.'),
    ('W108', 'core', 'wt_thrown', 'Метательный топор', 'Throwing Axe', NULL, 'TRUE', NULL, NULL, 0, 'humans', 'E', '2d6', 2, NULL, 10, 1, 'Тел*2', 'M', 0, '1', '75', 'Но летит куда дальше топора, зато топором по голове прилетит покрепче. Нет ничего страшнее, чем несущаяся тебе в рыло металическая штуковина с ручкой.'),
    ('W109', 'core', 'wt_thrown', 'Орион', 'Orion', NULL, 'TRUE', NULL, NULL, 1, 'humans', 'P', '1d6', 1, NULL, 5, 1, 'Тел*4', 'S', 0, '0,1', '100', 'Чёрные стали ими пользоваться пару десятилетий назад. Это что-то вроде метательного ножа, только формой напоминает звёздочку. Странновато выглядит, но вещь опасная. Да и летит быстро.'),
    ('W110', 'dlc_rw2', 'wt_thrown', 'Отравленный коготь гарпии', 'Poisoned Harpy Claw', 'TRUE', NULL, NULL, NULL, 1, 'humans', 'P', '1d6', 1, NULL, 10, 1, 'Тел*4', 'S', 0, '0,5', '450', ''),
    ('W111', 'exp_bot', 'wt_sword', 'Герцогский меч', 'Ducal Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'R', '5d6', 5, NULL, 10, 1, NULL, 'L', 1, '1,5', '800', ''),
    ('W112', 'core', 'wt_sword', 'Гледдиф', 'Gleddyf', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'C', '3d6+2', 3, 2, 5, 2, NULL, 'L', 0, '3', '285', 'Это один из самых тяжёлых и тонких клинков на Континенте. Весь его вес сосредоточен в вычурной гарде и навершии. Но сделать его достаточно просто. Потому-то чёрные его и предпочитают, учитывая, как быстро у них армия множится.'),
    ('W113', 'core', 'wt_sword', 'Гномий гвихир', 'Gnomish Gwyhyr', 'TRUE', 'TRUE', NULL, NULL, 3, 'non-humans', 'R', '5d6+3', 5, 3, 15, 2, NULL, 'XL', 2, '2,5', '1090', 'Долгое время гвихиры считались лучшими мечами в мире. Они до сих пор одни из лучших. Длинный чёрный клинок настолько острый, что им бриться можно. Настолько лёгкий, что им спокойно можно размахивать одной рукой на полной скорости. Обожаю эти игрушки, но они чертовски редкие.'),
    ('W114', 'hb', 'wt_sword', 'Деревянный меч', 'Wooden Sword', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'E', '2d6', 2, NULL, 10, 2, NULL, 'L', 0, '1', '67', ''),
    ('W115', 'hb', 'wt_sword', 'Железный меч', 'Iron Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'E', '2d6', 2, NULL, 10, 1, NULL, 'L', 0, '1', '167', ''),
    ('W116', 'core', 'wt_sword', 'Железный полуторный меч', 'Iron Long Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'E', '2d6+2', 2, 2, 10, 2, NULL, 'L', 0, '1,5', '160', 'Полуторный меч. Из железа. Скажу тебе, как краснолюд: от одной мысли об этой дряни мне дурно становится. Им чёрта с два кого прирежешь. Но зато его делать просто и достать можно всюду'),
    ('W117', 'core', 'wt_sword', 'Клинок бригады "Врихед"', 'Vrihedd Cavalry Sword', 'TRUE', 'TRUE', NULL, NULL, 3, 'non-humans', 'R', '4d6+4', 4, 4, 15, 1, NULL, 'L', 0, '2,5', '745', 'Когда-то кавалерийской бригады "Врихедд" боялись по всему миру. Как-то раз мне довелось с ними столкнуться. Мне и моим парням. Вот эти вот мечи из синей стали в руках всадников снесут башку даже самому крепкому краснолюду. Мне повезло выжить.'),
    ('W118', 'core', 'wt_sword', 'Клинок из Виковаро', 'Vicovarian Blade', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'R', '5d6+4', 5, 4, 15, 2, NULL, 'XL', 1, '1,5', '955', 'Такие мечи можно узнать по тяжёлой гарде. Обычно ими дерутся рыцари из Виковаро, но из-за войны их можно найти чуть ли не всюду. Вот что я тебе скажу: видал я, как на эти мечи обрушивались целые замки, и даже после такого этим оружием рубили руки-ноги.'),
    ('W119', 'exp_bot', 'wt_sword', 'Клинок из Вироледы', 'Viroledan Blade', 'TRUE', 'TRUE', NULL, NULL, 1, 'humans', 'R', '4d6+4', 4, 4, 10, 2, NULL, 'XL', 0, '2,5', '995', ''),
    ('W120', 'core', 'wt_sword', 'Клинок из Тир Тохаира', 'Tir Tochair Blade', 'TRUE', 'TRUE', NULL, NULL, 3, 'non-humans', 'R', '6d6', 6, NULL, 15, 2, NULL, 'XL', 2, '3', '1175', 'Гномы Тир Тохаира начали ковать мечи за много веков до того, как эльфы высадились на Континенте. Столь долгий опыт пошёл им на пользу. Клинки из Тыр Тохаира длинные и острые, словно бритва, и по всей длине покрыты тончайшими гномьими письменами.'),
    ('W121', 'core', 'wt_sword', 'Корд', 'Kord', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'R', '5d6', 5, NULL, 15, 1, NULL, 'XL', 1, '1,5', '725', 'Корды куют для моряков в прибрежном цидарском городе. Крепкий и простой клинок с изогнутым лезвием. Слыхал я, что клинки эти вывозят на Север, а то и вовсе в море выбрасывают, лишь бы чёрные их к рукам не прибрали.'),
    ('W122', 'core', 'wt_sword', 'Кригсверд', 'Krigsværd', 'TRUE', 'TRUE', NULL, NULL, 2, 'humans', 'C', '4d6+4', 4, 4, 10, 1, NULL, 'L', 0, '2', '570', 'Говаривают, что жители Скеллиге закаляют клинки в крови сирен и утопцев. Скажу так, друже: это правда. Ну, или было правдой. Благодаря закалённой стали и облегчённой конструкции эти клинки бьют невероятно точно.'),
    ('W123', 'hb', 'wt_sword', 'Махакамский сигилль', 'Mahakaman Sigil', 'TRUE', 'TRUE', NULL, NULL, 2, 'non-humans', 'R', '5d6+2', 5, 2, 15, 2, NULL, 'XL', 2, '2', '924', ''),
    ('W124', 'core', 'wt_sword', 'Меч из метеоритной стали', 'Meteorite Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'non-humans', 'R', '5d6', 5, NULL, 20, 2, NULL, 'XL', 2, '3', '875', 'Метеоритная сталь - один из лучших материалов для оружия. Выкованные из неё мечи поблёскивают разными цветами, да ещё и крепкие донельзя. И удивительно лёгкие.'),
    ('W125', 'hb', 'wt_sword', 'Меч охотника за колдуньями', 'Witch Hunter’s Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'P', '5d6', 5, NULL, 15, 2, NULL, 'XL', 1, '2', '679', ''),
    ('W126', 'core', 'wt_sword', 'Охотничий фальшион', 'Hunter’s Falchion', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'C', '3d6', 3, NULL, 15, 1, NULL, 'L', 0, '2', '325', 'Таким оружием охотники пользуются для разделки подстреленной животины. Если тебе нужен хороший клинок, чтобы и дрова рубить, и конечности, лучше не найдешь. Оружие такое встречается часто.'),
    ('W127', 'core', 'wt_sword', 'Рыцарский меч', 'Arming Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'C', '2d6+4', 2, 4, 15, 1, NULL, 'L', 0, '2,5', '270', 'Реданский рыцарский меч - это одноручное оружие с простой изогнутой гардой и острой режущей кромкой. Учитывая то, как реданцы расползаются по всему Северу, чтобы нас "защитить", этих мечей хоть жопой жуй.'),
    ('W128', 'core', 'wt_sword', 'Серебряный ведьмачий меч', 'Witcher’s Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'witchers', 'R', '1d6+2', 1, 2, 10, 1, NULL, 'XL', 2, '1,5', NULL, 'Каких только жутей не видали ведьмаки. А таким вот клинком они орудуют при охоте на особо отвратительных тварей. У кого другого такой почти не реально найти, ведь он куда менее острый и твердый чем даже обычная железяка, но уж больно твари это серебро не любят. От того почти невозможно встретить ведьмака без своего серебряного клинка.'),
    ('W129', 'dlc_wt', 'wt_sword', 'Серебряный ведьмачий меч школы Волка', 'Wolven Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 10, 1, NULL, 'XL', 3, '1,5', NULL, ''),
    ('W130', 'dlc_wt', 'wt_sword', 'Серебряный ведьмачий меч школы Грифона', 'Griffin Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 10, 1, NULL, 'XL', 2, '1,5', NULL, ''),
    ('W131', 'dlc_wt', 'wt_sword', 'Серебряный ведьмачий меч школы Змеи', 'Serpentine Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 2, 'witchers', 'R', '1d6+2', 1, 2, 10, 1, NULL, 'XL', 2, '1,5', NULL, ''),
    ('W132', 'dlc_wt', 'wt_sword', 'Серебряный ведьмачий меч школы Кота', 'Feline Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 2, 'witchers', 'R', '1d6+2', 1, 2, 10, 1, NULL, 'XL', 2, '1,5', NULL, ''),
    ('W133', 'dlc_wt', 'wt_sword', 'Серебряный ведьмачий меч школы Мантикоры', 'Manticore Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '2d6+2', 2, 2, 10, 1, NULL, 'XL', 2, '1,5', NULL, ''),
    ('W134', 'dlc_wt', 'wt_sword', 'Серебряный ведьмачий меч школы Медведя', 'Ursine Silver Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'witchers', 'R', '3d6+2', 3, 2, 10, 1, NULL, 'XL', 2, '1,5', NULL, ''),
    ('W135', 'core', 'wt_sword', 'Стальной ведьмачий меч', 'Witcher’s Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'witchers', 'R', '4d6+2', 4, 2, 15, 1, NULL, 'XL', 2, '2,5', NULL, 'По сей день ведьмаки - единственные, кто постоянно носит при себе пару мечей из метеоритной стали и серебра. Это тот, который сделан из метеоритной стали. Весьма редкая вещица, не каждый день с неба камни падают. Но такой меч - практически часть ведьмака!'),
    ('W136', 'dlc_wt', 'wt_sword', 'Стальной ведьмачий меч школы Волка', 'Wolven Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '5d6+2', 5, 2, 15, 1, NULL, 'XL', 3, '2,5', NULL, ''),
    ('W137', 'dlc_wt', 'wt_sword', 'Стальной ведьмачий меч школы Грифона', 'Griffin Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '5d6+2', 5, 2, 15, 1, NULL, 'XL', 2, '2,5', NULL, ''),
    ('W138', 'dlc_wt', 'wt_sword', 'Стальной ведьмачий меч школы Змеи', 'Serpentine Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 2, 'witchers', 'R', '4d6+2', 4, 2, 15, 1, NULL, 'XL', 2, '2,5', NULL, ''),
    ('W139', 'dlc_wt', 'wt_sword', 'Стальной ведьмачий меч школы Кота', 'Feline Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 2, 'witchers', 'R', '4d6+2', 4, 2, 15, 1, NULL, 'XL', 2, '2,5', NULL, ''),
    ('W140', 'dlc_wt', 'wt_sword', 'Стальной ведьмачий меч школы Мантикоры', 'Manticore Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 1, 'witchers', 'R', '5d6+2', 5, 2, 15, 1, NULL, 'XL', 2, '2,5', NULL, ''),
    ('W141', 'dlc_wt', 'wt_sword', 'Стальной ведьмачий меч школы Медведя', 'Ursine Steel Sword', 'TRUE', 'TRUE', NULL, NULL, 0, 'witchers', 'R', '5d6+2', 5, 2, 15, 1, NULL, 'XL', 2, '2,5', NULL, ''),
    ('W142', 'hb', 'wt_sword', 'Счетовод', 'The Abacus', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'C', '4d6', 4, NULL, 15, 1, NULL, 'L', 1, '1,5', '481', ''),
    ('W143', 'core', 'wt_sword', 'Торрур', 'Torwyr', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'R', '6d6', 6, NULL, 15, 2, NULL, 'XL', 2, '2', '1075', 'Если на тебя бежит мужик с торруром, притворись мёртвым. Во время последней войны я видел, как здоровяк ростом с небольшую гору попросту отрубил этой штукой башку скачущей лошади. Геммерцы вообще больные на голову сукины дети. Смотрят на тебя так, словно сожрать готовы.'),
    ('W144', 'exp_bot', 'wt_sword', 'Фламберг', 'Flamberge', 'TRUE', 'TRUE', NULL, NULL, -1, 'humans', 'P', '6d6', 6, NULL, 15, 2, '2', 'XL', 1, '3,5', '1025', ''),
    ('W145', 'core', 'wt_sword', 'Эльфский мессер', 'Elven Messer', 'TRUE', 'TRUE', NULL, NULL, 2, 'non-humans', 'R', '3d6+4', 3, 4, 15, 1, NULL, 'L', 2, '2', '595', 'Поговаривают, что этот клинок выдумали назаирцы, которым чёрные запретили мечи носить. Вот и выковали нож-переросток - технически-то это не меч. Закончилось всё не очень хорошо, но в итоге эльфы взяли ту конструкцию и доработали.'),
    ('W146', 'core', 'wt_sword', 'Эсбода', 'Esboda', 'TRUE', 'TRUE', NULL, NULL, 1, 'humans', 'P', '5d6', 5, NULL, 10, 1, NULL, 'XL', 1, '1,5', '650', 'Торговцам порой приходится забыть о своих предубеждениях, когда речь заходит о хорошем товаре. Метинская эсбода - один из самых лёгких и острых ковалерийских клинков, какие мне только доводилось видеть. Как гледдиф, только лучше. И чёрные не брезгуют заставить "вассалов" такое оружие для армии ковать.'),
    ('W147', 'core', 'wt_sword', 'Волк', 'Wolf', 'TRUE', 'TRUE', NULL, NULL, 2, 'humans', 'U', '7d6', 7, NULL, 15, 2, NULL, 'XL', 3, '4', NULL, ''),
    ('W148', 'core', 'wt_sword', 'Девин', 'Devine', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'U', '10d6', 10, NULL, 20, 2, NULL, 'XL', 3, '2', NULL, ''),
    ('W149', 'core', 'wt_sword', 'Каролина', 'Caroline', 'TRUE', 'TRUE', NULL, NULL, 3, 'humans', 'U', '9d6', 9, NULL, 15, 2, NULL, 'XL', 3, '3', NULL, ''),
    ('W150', 'core', 'wt_sword', 'Лунный клинок', 'Moon Blade', 'TRUE', 'TRUE', NULL, NULL, 1, 'humans', 'U', '3d6', 3, NULL, 10, 2, NULL, 'XL', 3, '4', NULL, ''),
    ('W151', 'core', 'wt_sword', 'Могрим', 'Maugrim', 'TRUE', 'TRUE', NULL, NULL, 0, 'witchers', 'U', '2d6', 2, NULL, 10, 2, NULL, 'XL', 3, '6', NULL, ''),
    ('W152', 'core', 'wt_sword', 'Сорвишапка', 'Cleaver Hood', 'TRUE', 'TRUE', NULL, NULL, 0, 'humans', 'U', '8d6+2', 8, 2, 20, 2, NULL, 'XL', 3, '3', NULL, ''),
    ('W153', 'core', 'wt_sword', 'Судьба', 'Fate', 'TRUE', 'TRUE', NULL, NULL, 3, 'non-humans', 'U', '2d6+1', 2, 1, 10, 2, NULL, 'XL', 3, '4', NULL, ''),
    ('W154', 'core', 'wt_staff', 'Гномий посох', 'Gnomish Staff', NULL, NULL, 'TRUE', NULL, 1, 'non-humans', 'R', '3d6+2', 3, 2, 15, 2, '2', 'L', 2, '2,5', '910', 'Как и любое изделие гномей работы, эти посохи впечатляют. Они сделаны из тёмной травлёной древесины и покрыты рунами сверху донизу. Обычно ещё местами в них вправлены самоцветы.'),
    ('W155', 'core', 'wt_staff', 'Железный посох', 'Iron Staff', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'P', '3d6', 3, NULL, 15, 2, '2', 'XL', 1, '4', '675', 'Иногда магу требуется чуть больше защиты, ну, на тот случай, если магиея подведёт. Для этого есть железный посох. По сути, это просто большая палка из железа с пятой эссенцией внутри. Такой посох крепче обычного, а врезать им можно прям как булавой, да и удары мечом отчасти блокировать.'),
    ('W156', 'exp_toc', 'wt_staff', 'Истинный связывающий посох', 'True Staff of Binding', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'R', '2d6', 2, NULL, 5, 2, '2', 'XL', 1, '2', NULL, ''),
    ('W157', 'core', 'wt_staff', 'Посох', 'Staff', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'C', '1d6+2', 1, 2, 10, 2, '2', 'XL', 1, '3', '335', 'Никому не говори, что я его тебе продал, понял? Спокойно расхаживать с магически посохом можно разве что на Скеллиге, или, может, в Зеррикании или Офире. Для простых смертных это светящаяся палка, а вот маги с помощью посоха способны использовать куда больше магии, чем без него. Учитывая ненависть к магам на Севере и недоверие к ним на Юге, посох делает из владельца ходячую мишень.'),
    ('W158', 'core', 'wt_staff', 'Посох с кристаллом', 'Crystal Staff', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'R', '2d6+2', 2, 2, 5, 2, '2', 'XL', 2, '2,5', '835', 'У лучших магов при себе есть посох с кристаллом. На первый взгляд это обычный посох, в навершие которого вправлен самоцвет. Только вот самоцвет должен быть совершенным: если он хоть чуточку треснутый или изъяном, то может рвануть прямо в лицо. Но посохи эти стоят подобного риска, учитывая то, как хорошо они магию усиливают.'),
    ('W159', 'core', 'wt_staff', 'Посох с крюком', 'Hooked Staff', 'TRUE', NULL, 'TRUE', NULL, 0, 'humans', 'P', '2d6', 2, NULL, 10, 2, '2', 'XL', 1, '3,5', '550', 'Никогда не понимал, зачем нужен такой посох, но один юный маг, с которым я странствовал, рассказал, что таким орудовал маг по имени Альзур. Оказывается, этот Альзур крюком направлял тварей, которых сам создал. Бьюсь об заклад, у него-то крюк был из серебра. Но оружие это в любом случае пригодится тем, кто любит посохом промеж глаз засветить.'),
    ('W160', 'exp_toc', 'wt_staff', 'Связывающий посох', 'Staff of Binding', NULL, NULL, 'TRUE', NULL, 0, 'humans', 'R', '2d6', 2, NULL, 5, 2, '2', 'XL', 1, '2', NULL, ''),
    ('W161', 'core', 'wt_staff', 'Эльфский дорожный посох', 'Elven Walking Staff', NULL, NULL, 'TRUE', NULL, 1, 'non-humans', 'R', '3d6', 3, NULL, 10, 2, '2', 'XL', 2, '1,5', '975', 'Много лет назад с такими ходили эльфьи мудрецы. Дорожные посохи куда меньше обычных, самое большее до груди. Красивые, украшенные шёлком и золотом, но важнее всего в них то, насколько хорошо позволяют фокусировать магическую энергию.'),
    ('W162', 'core', 'wt_staff', 'Посох суккуба', 'Succubus’ Wand', NULL, NULL, 'TRUE', NULL, 0, 'non-humans', 'U', '3d6+2', 3, 2, 5, 2, '2', 'XL', 3, '2', NULL, ''),
    ('W163', 'core', 'wt_axe', 'Боевой топор', 'Battle Axe', NULL, 'TRUE', NULL, NULL, 0, 'humans', 'C', '5d6', 5, NULL, 15, 1, NULL, 'L', 0, '2', '525', 'Надо выломать дверь? Изрубить тело, живое или мёртвое? Тогда, приятель, тебе нужен боевой топор. Форма может быть разной, но так-то боевой топор - смертоносное оружие, поркрепче многих мечей.'),
    ('W164', 'core', 'wt_axe', 'Гномий чёрный топор', 'Gnomish Black Axe', NULL, 'TRUE', NULL, NULL, 2, 'non-humans', 'R', '6d6+2', 6, 2, 15, 2, NULL, 'XL', 2, '2,5', '910', 'Гномий гвихир всем известен. Но немногие знают, что гномы ещё и топоры куют. Сделаны они аналогично гвихирам, только потяжелее. Топор бородовидный, покрытый гномьими рунами. Это оружие по ощущениям настолько лёгкое и тонкое, что пользовать его в бою кажется чем-то несусветным. Но достаточно крепкое, чтобы проломить доспех.'),
    ('W165', 'core', 'wt_axe', 'Краснолюдский топор', 'Dwarven Axe', NULL, 'TRUE', NULL, NULL, 3, 'non-humans', 'R', '5d6+3', 5, 3, 15, 1, NULL, 'L', 1, '4', '740', 'Есть ошибочное мнение, что краснолюды поголовно топоры таскают. На самом деле не все, но многие. Дай краснолюду тяжёлый топор, и он тебе дырку в любой стене прорубит. Особенно если топор этот краснолюдской работы. Двусторонний топор весьма увесист, да и рубить им можно в любую сторону.'),
    ('W166', 'core', 'wt_axe', 'Топор', 'Hand Axe', NULL, 'TRUE', NULL, NULL, 0, 'humans', 'E', '2d6+1', 2, 1, 10, 1, NULL, 'M', 0, '1', '205', 'Полюбил я со временем простой топор. Рубил им сначала дрова. Крепкий такой инструмент. А уж если этим можно дерево рубить, то кости и подавно.'),
    ('W167', 'core', 'wt_axe', 'Топор берсерка', 'Berserker’s Axe', NULL, 'TRUE', NULL, NULL, 0, 'humans', 'P', '6d6', 6, NULL, 15, 2, NULL, 'XL', 1, '3', '960', 'На островах Скеллиге много волколаков и сирен, а ведьмаков мало. Добавь к этому показную храбрость обычного скеллигца, и получится вот эта штука. Двухметровый топор с огромным бородовидным лезвием, украшенным скеллигскими рунам.'),
    ('W168', 'core', 'wt_axe', 'Обезглавливатель', 'Decapitator', NULL, 'TRUE', NULL, NULL, 0, 'humans', 'U', '10d6', 10, NULL, 20, 2, NULL, 'XL', 3, '4', NULL, ''),
    ('W169', 'dlc_sch_snail', 'wt_sword', 'Стальной меч школы Улитки', 'Gastropod Steel Sword', 'TRUE', 'TRUE', NULL, NULL, -6, 'witchers', 'R', '8d6', 8, NULL, 20, 2, NULL, 'XL', 1, '5', NULL, ''),
    ('W170', 'dlc_sch_snail', 'wt_sword', 'Серебряный меч школы Улитки', 'Gastropod Silver Sword', 'TRUE', 'TRUE', NULL, NULL, -6, 'witchers', 'R', '5d6', 5, NULL, 15, 2, NULL, 'XL', 1, '3', NULL, '')
),
ins_i18n AS (
  INSERT INTO i18n_text (id, entity, entity_field, lang, text)
  SELECT * FROM (
    -- Weapon names
    SELECT ck_id('witcher_cc.items.weapon.name.'||rd.w_id),
	       'items',
		   'weapon_names',
	       'ru',
		   rd.name_ru
	  FROM raw_data rd
	 WHERE nullif(rd.name_ru,'') is not null
	UNION ALL
    SELECT ck_id('witcher_cc.items.weapon.name.'||rd.w_id),
	       'items',
		   'weapon_names',
	       'en',
		   rd.name_en
	  FROM raw_data rd
	 WHERE nullif(rd.name_en,'') is not null
	UNION ALL
    -- Weapon descriptions
    SELECT ck_id('witcher_cc.items.weapon.description.'||rd.w_id),
	       'items',
		   'weapon_descriptions',
	       'ru',
		   rd.description_ru
	  FROM raw_data rd
	 WHERE nullif(rd.description_ru,'') is not null ) foo
)
INSERT INTO wcc_item_weapons
  SELECT w_id
       , source_id AS dlc_dlc_id
	   , ck_id('weapons.'||rd.class_id) AS weapon_class_id
	   , ck_id('witcher_cc.items.weapon.name.'||rd.w_id) AS name_id
	   , CASE WHEN rd.is_piercing = 'TRUE' THEN ck_id('damage_type.P') ELSE NULL END is_piercing
	   , CASE WHEN rd.is_slashing = 'TRUE' THEN ck_id('damage_type.S') ELSE NULL END is_slashing
	   , CASE WHEN rd.is_bludgeoning = 'TRUE' THEN ck_id('damage_type.B') ELSE NULL END is_bludgeoning
	   , CASE WHEN rd.is_elemental = 'TRUE' THEN ck_id('damage_type.E') ELSE NULL END is_elemental
	   , accuracy
	   , CASE 
	       WHEN rd.crafted_by_id = 'humans' THEN ck_id('crafted_by.humans')
	       WHEN rd.crafted_by_id = 'non-humans' THEN ck_id('crafted_by.non-humans')
	       WHEN rd.crafted_by_id = 'witchers' THEN ck_id('crafted_by.witchers')
	       ELSE NULL
	     END crafted_by_id
	   , CASE 
	       WHEN rd.availability_id = 'E' THEN ck_id('availability.E')
	       WHEN rd.availability_id = 'C' THEN ck_id('availability.C')
	       WHEN rd.availability_id = 'P' THEN ck_id('availability.P')
	       WHEN rd.availability_id = 'R' THEN ck_id('availability.R')
	       WHEN rd.availability_id = 'U' THEN ck_id('availability.U')
	       ELSE NULL
	     END availability_id
	   , nullif(rd.dmg,'') dmg
	   , damage_dices
	   , damage_modifier
	   , reliability
	   , hands
	   , nullif(rd.range,'') range
	   , CASE 
	       WHEN rd.concealment_id = 'S' THEN ck_id('concealment.S')
	       WHEN rd.concealment_id = 'M' THEN ck_id('concealment.T')
	       WHEN rd.concealment_id = 'L' THEN ck_id('concealment.L')
	       WHEN rd.concealment_id = 'XL' THEN ck_id('concealment.N/A')
	       ELSE NULL
	     END concealment_id
	   , coalesce(enhancements,0) enhancements
	   , CAST(REPLACE(rd.weight, ',', '.') AS numeric) weight
	   , CAST(REPLACE(rd.price, ',', '.') AS numeric) price
	   , ck_id('witcher_cc.items.weapon.description.'||rd.w_id) description_id
    FROM raw_data rd;
-- <<< END sql/items/005_wcc_item_weapons.sql

-- >>> BEGIN sql/items/006_wcc_item_armors.sql

\echo '006_wcc_item_armors.sql'
CREATE TABLE IF NOT EXISTS wcc_item_armors (
    a_id            varchar(10) PRIMARY KEY,          -- e.g. 'A002'
    dlc_dlc_id      varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id), -- source_id (core, hb, dlc_*, exp_*)

    name_id         uuid NOT NULL,                    -- ck_id('witcher_cc.items.armor.name.'||a_id)

    -- Reused dictionary fields (see 000_wcc_items_dict.sql)
    body_part_id    uuid NULL,                        -- ck_id('bodypart.*')
    armor_class_id  uuid NULL,                        -- ck_id('armor_class.*')
    crafted_by_id   uuid NULL,                        -- ck_id('crafted_by.*')
    availability_id uuid NULL,                        -- ck_id('availability.*')

    reliability     integer NULL,
    stopping_power  integer NULL,
    enhancements    integer NOT NULL DEFAULT 0,

    encumbrance     integer NULL,
    weight          numeric(12,1) NULL,
    price           integer NULL,

    description_id  uuid NOT NULL                     -- ck_id('witcher_cc.items.armor.description.'||a_id)
);

COMMENT ON TABLE wcc_item_armors IS
  'Доспехи/щиты. Источник (DLC) через wcc_dlcs, локализуемые поля через i18n_text UUID (ck_id). Часть тела/класс/производитель/доступность — из общего словаря (000_wcc_items_dict.sql).';

COMMENT ON COLUMN wcc_item_armors.dlc_dlc_id IS
  'FK на wcc_dlcs.dlc_id (источник/пакет: core/hb/dlc_*/exp_*).';

COMMENT ON COLUMN wcc_item_armors.name_id IS
  'i18n UUID для названия доспеха. Генерируется детерминированно: ck_id(''witcher_cc.items.armor.name.''||a_id).';

COMMENT ON COLUMN wcc_item_armors.description_id IS
  'i18n UUID для описания доспеха. Генерируется детерминированно: ck_id(''witcher_cc.items.armor.description.''||a_id).';

WITH raw_data (
  a_id, source_id, body_part, armor_class,
  name_ru, name_en,
  is_piercing, is_slashing, is_bludgeoning, is_elemental, is_poison, is_bleeding,
  crafted_by, availability,
  reliability, stopping_power, enhancements, encumbrance, weight, price,
  description_ru, description_en
) AS ( VALUES
  ('A002','core','bodypart.head','armor_class.light',
    $$Капюшон вардэнского лучника$$, $$Verden Archer’s Hood$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,3,1,'0','0,5','100',
    $$Вердэнские лучники - крепкие ребята. Обычно они не слишком усердствуют с бронёй - дриады-то всё равно в щели между доспехами дротик-другой засадят. Зато они носят хорошие плотные капюшоны, расшитые сине-чёрным стрельчатым узором.$$,
    $$Verden archers are tough folk. They usually don’t bother too much with armor—dryads will still stick a dart or two into the gaps. But they do wear good, thick hoods embroidered with a blue-and-black chevron pattern.$$),

  ('A003','core','bodypart.head','armor_class.light',
    $$Каркасный шлем с полумаской$$, $$Spectacled Helm$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,8,0,'0','1','200',
    $$Такие шлемы куда чаще встречаются на Скеллиге и в Нильфгаарде. На севере шлемы обычно либо полностью закрытые, либо просто конусом. Полумаска защищает лицо и глаза. Порой снизу ещё и крепится кольчуга для защиты шеи.$$,
    $$Such helms are far more common in Skellige and Nilfgaard. In the North, helms are usually either fully enclosed or just a simple cone. The half-mask protects the face and eyes. Sometimes a mail curtain is attached below to protect the neck.$$),

  ('A007','core','bodypart.head','armor_class.medium',
    $$Усиленный капюшон$$, $$Armored Hood$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,14,0,'0','2','250',
    $$В дебрях нужен обзор получше, потому народ, в особенности эльфы, носит капюшоны из крепкой кожи и нескольких слоёв льна, и всё это прошито крепкими нитками. Такие капюшоны достаточно плотные, чтобы не пропустить режущий удар или болт, пущеный из небольшого ручного арбалета$$,
    $$In the wilds you need better visibility, so people—especially elves—wear hoods made of sturdy leather and several layers of linen, all stitched with strong thread. These hoods are dense enough to stop a slashing blow or a bolt from a small hand crossbow.$$),

  ('A028','core','bodypart.legs','armor_class.light',
    $$Кавалерийские штаны$$, $$Cavalry Trousers$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,3,0,'0','0,5','75',
    $$Кавалеристы обычно не носят тонну брони, если только это не драгуны какие-нибудь. Вот эти плотные штаны только кожаными полосками укреплены, и всё.$$,
    $$Cavalrymen don’t usually wear a ton of armor—unless they’re dragoons. These thick trousers are reinforced only with leather straps, that’s all.$$),

  ('A029','core','bodypart.legs','armor_class.light',
    $$Стёганые штаны$$, $$Padded Trousers$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,5,1,'0','1','125',
    $$По сути, гамбезон для ног. Не пропустит небольшой клинок, но я бы не стал слишком сильно на такую броню полагаться. А вот над гульфиком можно изрядно поржать.$$,
    $$Basically a gambeson for the legs. It won’t let a small blade through, but I wouldn’t rely on this armor too much. Still, you can have a good laugh at the codpiece.$$),

  ('A053','core','bodypart.shield','armor_class.light',
    $$Стальной баклер$$, $$Steel Buckler$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    '6',NULL,0,'0','1','150',
    $$Баклер - это такой маленький щит. Всего около фута в ширину, но им можно парировать удар клинка.$$,
    $$A buckler is a small shield—about a foot across—but you can use it to parry a blade strike.$$),

  ('A054','core','bodypart.shield','armor_class.light',
    $$Темерский щит$$, $$Temerian Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    '8',NULL,1,'0','1,5','225',
    $$Ммм, старая добрая темерская работа! Каплевидный щит, пожалуй, встречается чаще всего. Темерский щит достаточно долго будет защищать тебя от мечей и стрел.$$,
    $$Mmm, good old Temerian work! The teardrop shield is probably the most common. A Temerian shield will protect you from swords and arrows for quite a while.$$),

  ('A056','core','bodypart.shield','armor_class.medium',
    $$Стальной каплевидный щит$$, $$Steel Kite Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    '16',NULL,4,'0','3','400',
    $$Щит, полностью сделанный из стали, - вещица любопытная. Гудит, что твой колокол, если по нему шибануть, но куда крепче других щитов, да и двинуть в рыло им можно.$$,
    $$A shield made entirely of steel is a curious thing. It rings like a bell when struck, but it’s much sturdier than other shields—and you can smack someone in the face with it.$$),

  ('A017','core','bodypart.torso','armor_class.medium',
    $$Бригантина$$, $$Brigandine$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,12,0,'1','7','300',
    $$Обычно наёмники носят бригантину до тех пор, пока не разживутся бронёй получше. Это простенький кожаный жилет с прикреплёнными к нему пластинами из толстой дублёной кожи. Сам-то я бригантину носил под Бренной и Содденом. И скажу, что в ней плохо: неудобная она, жестковата.$$,
    $$Mercenaries usually wear a brigandine until they can get something better. It’s a simple leather vest with plates of thick boiled leather attached to it. I wore one myself at Brenna and Sodden. And here’s what’s bad about it: it’s uncomfortable and stiff.$$),

  ('A021','hb','bodypart.torso','armor_class.medium',
    $$Каэдвенская кираса$$, $$Kaedweni Cuirass$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.C',
    NULL,13,0,'1','7,5','355',
    $$$$,
    $$$$),

  ('A005','core','bodypart.head','armor_class.medium',
    $$Кольчужный капюшон$$, $$Chain Coif$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.E',
    NULL,12,0,'0','1,5','250',
    $$Ищешь простую и крепкую броньку? В таком случае, приятель, тебе нужен кольчужный капюшон. И удар меча остановит, и от молота спасёт. Некоторые носят его полноценную часть брони, другие же поверх ещё и шлем надевают. Полезная штука, как ни крути.$$,
    $$Looking for simple, sturdy armor? Then, friend, you need a chain coif. It will stop a sword blow and save you from a hammer. Some wear it as a full piece of armor; others put a helmet over it. Useful no matter how you look at it.$$),

  ('A004','hb','bodypart.head','armor_class.medium',
    $$Капеллина$$, $$Capelline$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.E',
    NULL,10,0,'0','1','230',
    $$$$,
    $$$$),

  ('A033','core','bodypart.legs','armor_class.medium',
    $$Усиленные штаны$$, $$Armored Trousers$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.E',
    NULL,12,0,'0','3,5','250',
    $$Честно скажу, ранашивать пару недель точно придётся. Но это не так важно, как тот факт, что дублёная кожа да стальные пластины и защищают, и не слишком сковывают движения.$$,
    $$I’ll be honest: you’ll have to break them in for a couple of weeks. But that’s less important than the fact that boiled leather and steel plates protect you without restricting movement too much.$$),

  ('A052','core','bodypart.shield','armor_class.light',
    $$Кожаный щит$$, $$Leather Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.E',
    '4',NULL,0,'0','0,5','50',
    $$Проще щита, чем обтянутый кожей кусок дерева, не найти. Такие щиты не очень-то поулярны в наши дни - слкшмо хлипкие в сравнении с деревянными или стальными. Но зато дешёвые и лёгкие.$$,
    $$You won’t find a simpler shield than a piece of wood wrapped in leather. These shields aren’t very popular these days—too flimsy compared to wooden or steel ones. But they’re cheap and light.$$),

  ('A012','core','bodypart.torso','armor_class.light',
    $$Гамбезон$$, $$Gambeson$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.E',
    NULL,3,0,'0','1','100',
    $$Ну, по-хорошему, гамбезон - это поддоспешник для более тяжёлых доспехов, но многие бедняки используют его вместо брони. Против меча не поможет, зато спасёт от кинжала и тому подобного.$$,
    $$Properly speaking, a gambeson is padding worn under heavier armor, but many poor folk use it as armor on its own. It won’t help against a sword, but it will save you from a dagger and the like.$$),

  ('A009','core','bodypart.head','armor_class.heavy',
    $$Скеллигский шлем$$, $$Skellige Helm$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,25,1,'0','3,5','700',
    $$Выходцам со Скеллиге нравятся украшения, особенно если, напялив их, они выглядят брутальнее. И их шлемы - тому подтверждение. Скеллигский шлем крепкий, с кольчужной бармицей, на лице полумаска и пластины на щеках... а по бокам часто рога крепятся. По ходу, самые крепкие сотровитяне бодают врагов этими рогами.$$,
    $$Skelligers like ornaments, especially if they look more brutal when wearing them, and their helms prove it. The Skellige helm is sturdy: a mail aventail, a half-mask on the face, plates on the cheeks… and horns are often attached on the sides. Seems the toughest islanders gore their enemies with them.$$),

  ('A001','core','bodypart.head','armor_class.light',
    $$Двуслойный капюшон$$, $$Double Woven Hood$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,5,1,'0','1','175',
    $$Капюшон укрепить легко - просто добавь вставки из кожи, кольчужного полотна и тому подобного. Такие капюшоны куда плотнее обычных, отчего их сложнее повредить оружием. Простенько и защищает.$$,
    $$Reinforcing a hood is easy—just add inserts of leather, mail, and the like. Such hoods are much denser than ordinary ones, making them harder to damage. Simple and protective.$$),

  ('A006','core','bodypart.head','armor_class.medium',
    $$Темерский армет$$, $$Temerian Armet$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,16,1,'0','1,5','475',
    $$Темерские рыцари обычно носят арметы - стандартные рыцарские шлемы. Это полностью закрытый металлический шлем с острым "клювом" на забрале и узкой прорезью для обзора. ОДна проблема: через эту прорезь ни черта не видно.$$,
    $$Temerian knights usually wear armets—standard knightly helms. It’s a fully enclosed metal helm with a sharp “beak” on the visor and a narrow slit for vision. One problem: you can’t see a damn thing through that slit.$$),

  ('A027','core','bodypart.legs','armor_class.light',
    $$Двуслойные штаны$$, $$Double Woven Trousers$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,8,0,'0','1,5','225',
    $$Двойная ткань - лучший выбор. Не столь раздутая, как средней руки стёганка, а зад твой прикрыт.$$,
    $$Double cloth is the best choice. Not as puffed up as a mediocre quilted padding, and it keeps your ass covered.$$),

  ('A030','hb','bodypart.legs','armor_class.light',
    $$Штаны темерского пехотинца$$, $$Temerian Infantry Trousers$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,10,1,'0','2','255',
    $$$$,
    $$$$),

  ('A032','core','bodypart.legs','armor_class.medium',
    $$Реданские поножи$$, $$Redanian Greaves$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,14,1,'0','4','400',
    $$Что гамбезон, что поножи - реданские алебардщики особо не изгаляются. Простые кожаные штаны, поножи и гульфик. Манёвренность ценой прочности.$$,
    $$Whether gambeson or greaves, Redanian halberdiers don’t overthink it. Simple leather trousers, greaves, and a codpiece. Mobility at the cost of durability.$$),

  ('A063','core','bodypart.shield','armor_class.heavy',
    $$Павеза$$, $$Pavise$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    '20',NULL,4,'1','4','500',
    $$Если тебе надо за настоящую стенку запрятаться от врага, то пряься за павезой. Павеза здоровенная - по плечо человеку и ширной с краснолюда. За такой можно присесть и просто переждать, пока тебя поливают дождём из стрел.$$,
    $$If you need to hide behind a real wall from the enemy, hide behind a pavise. It’s huge—up to a man’s shoulder and as wide as a dwarf. You can crouch behind it and simply wait out a rain of arrows.$$),

  ('A055','core','bodypart.shield','armor_class.medium',
    $$Каэдвенский щит$$, $$Kaedweni Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    '14',NULL,1,'0','2,5','400',
    $$Каэдвенский щит несильно отличается от темерского. Они, правда, на внешнюю сторону тратят черное железо. Каэдвенские щиты потяжелее, зато более прочные.$$,
    $$A Kaedweni shield doesn’t differ much from a Temerian one. They do use black iron on the outer face, though. Kaedweni shields are heavier, but tougher.$$),

  ('A058','core','bodypart.shield','armor_class.medium',
    $$Щит налётчика со Скеллиге$$, $$Skellige Raider Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    '10',NULL,4,'0','2','325',
    $$В отличие от остального мира, выходцы со Скеллиге использую большие круглые щиты с умбоном по центру и рукоятью с обратной стороны. Думаю, благодаря такому больше манёвренность, поскольку щит не прикреплён к руке.$$,
    $$Unlike the rest of the world, Skelligers use large round shields with a boss in the center and a grip on the back. I think that gives better maneuverability, since the shield isn’t strapped to the arm.$$),

  ('A011','core','bodypart.torso','armor_class.light',
    $$Аэдирнский гамбезон$$, $$Aedirnian Gambeson$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,5,1,'0','1,5','175',
    $$Когда напал Нильфгаард, аэдирнцам пришлось, пожалуй, тяжелее всех. Они лишились короля, и я даже не знаю, избрали ли они нового до того, как их захлестнуло черно-золотой волной. Аэдирнский гамбезон - наглядное тому свидетельство. Это простой гамбезон с нашитыми кусками кожи и дублёной шкуры.$$,
    $$When Nilfgaard attacked, Aedirn probably had it worst of all. They lost their king, and I don’t even know if they elected a new one before they were swallowed by the black-and-gold wave. The Aedirnian gambeson is proof enough: a simple gambeson with patches of leather and boiled hide sewn on.$$),

  ('A014','core','bodypart.torso','armor_class.light',
    $$Двуслойный гамбезон$$, $$Double Woven Gambeson$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,8,1,'0','2,5','250',
    $$Как и капюшон из того же материала, двуслойный гамбезон - неплохое сочетание цены и качества. Спасёт от удара дешёвого меча или от болта из ручного арбалета, да и весит не так уж много. Обычно я такой и ношу, когда путешествую или хожу по городу. И защищает, и не вызывает лишних вопросов.$$,
    $$Like the hood made from the same material, the double woven gambeson is a good balance of price and quality. It will save you from a cheap sword blow or a bolt from a hand crossbow, and it doesn’t weigh much. It’s what I usually wear when traveling or walking around town—protective, and it doesn’t raise too many questions.$$),

  ('A013','hb','bodypart.torso','armor_class.light',
    $$Гамбезон верденского лучника$$, $$Verden Archer’s Gambeson$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,10,1,'0','2,5','300',
    $$$$,
    $$$$),

  ('A018','core','bodypart.torso','armor_class.medium',
    $$Броня реданского алебардщика$$, $$Redanian Halberdier’s Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,14,1,'1','8,5','400',
    $$Как ни странно, реданский алебардщики много брони на себя не напяливают - берут простенький, длиной до колен гамбезон из кожи и ткани, кольчугу, горжет и наплечники. полагаю, когда между собой и противником алебарда, тажёлая броня особо-то и не нужна. От клинка в случае чего спасёт, да и манёвренность примерно такая же, как в гамбезоне.$$,
    $$Strangely enough, Redanian halberdiers don’t pile on armor—they take a simple knee-length gambeson of leather and cloth, a mail shirt, a gorget, and pauldrons. I suppose when there’s a halberd between you and the enemy, heavy armor isn’t that necessary. It’ll still save you from a blade if it comes to it, and the mobility is about the same as in a gambeson.$$),

  ('A020','hb','bodypart.torso','armor_class.medium',
    $$Доспех охотника за колдуньями$$, $$Witch Hunter Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.P',
    NULL,15,1,'1','6','500',
    $$$$,
    $$$$),

  ('A008','core','bodypart.head','armor_class.heavy',
    $$Нильфгаардский шлем$$, $$Nilfgaardian Helm$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,30,2,'0','3','800',
    $$Шлемаки чёрных созданы весьма интересным образом - они состоят из двух частей. Первая - шлем-салад, у которого спереди либо кусок вырезан, либо прорезь есть для глаз. Вторая часть - бувигер, или нашейник, выступающий вперёд и закрывающий шею, нос и рот. Всё это вместе даёт неплохую защиту.$$,
    $$Nilfgaardian helms are made in an interesting way: they consist of two parts. The first is a sallet with either a cut-out front or an eye-slit. The second is a bevor—a neck guard that juts forward and covers the neck, nose, and mouth. Together, it offers solid protection.$$),

  ('A010','core','bodypart.head','armor_class.heavy',
    $$Топфхельм$$, $$Great Helm$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,20,1,'0','3,5','575',
    $$Топфхельмы носят высший класс рыцарей. Это большие шлемы цилиндрической формы с широкими прорезями для глаз и отверстиями, через которые можно нормально дышать. Они очень крепкие и часто украшены плетёными кисточками, рогами или даже орлами с раскинутыми крыльями. Ужасно вычурно, но небесполезно.$$,
    $$Great helms are worn by the highest class of knights. They’re big cylindrical helms with wide eye slits and holes you can breathe through. Very sturdy, often decorated with braided tassels, horns, or even eagles with outstretched wings. Awfully gaudy, but not useless.$$),

  ('A034','core','bodypart.legs','armor_class.heavy',
    $$Латные поножи$$, $$Plate Greaves$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,20,1,'1','7,5','625',
    $$Поножи, сабатоны, набедренники - всё это защищает твои ноги. Большие пластины из обработанной стали спасут от мечей, булав и стрел, пущеных из длинного лука.$$,
    $$Greaves, sabatons, cuisses—whatever you call them, they protect your legs. Large plates of worked steel will save you from swords, maces, and arrows loosed from a longbow.$$),

  ('A035','core','bodypart.legs','armor_class.heavy',
    $$Нильфгаардские поножи$$, $$Nilfgaardian Greaves$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,30,2,'1','6','850',
    $$Поножи у нильфгаардской брони чуточку легче, чем верхняя часть доспеха. Обычно это сабатоны, собственно поножи и надеваемые под них штаны в клетку из плотной кожи и ткани.$$,
    $$Nilfgaardian greaves are a bit lighter than the upper part of the armor. Usually it’s sabatons, the greaves themselves, and checked trousers of thick leather and cloth worn beneath.$$),

  ('A036','core','bodypart.legs','armor_class.heavy',
    $$Хиндарсфьяльские тяжёлые поножи$$, $$Hindarsfjall Heavy Chausses$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,25,3,'1','5','650',
    $$В состав тяжёлого хиндарсфьяльского доспеха входят шоссы. По сути кольчужные штаны. Крепкие. Большинство даже не заморачиваются напяливать на ноги тяжёлую броню, но в данном случае кольчужная броня неплоха. И при этом она очень гибкая.$$,
    $$The Hindarsfjall heavy armor includes chausses—basically mail trousers. Sturdy. Most don’t bother putting heavy armor on their legs, but in this case mail is a good choice. And it’s very flexible.$$),

  ('A031','core','bodypart.legs','armor_class.medium',
    $$Кожаные штаны из Лирии$$, $$Lyrian Leather Trousers$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,16,1,'0','3,5','525',
    $$Штаны из кожи лирийской работы. Грубоваты, не дышат, но ноги защищают. Правда, внимание к себе ты точно привлечешь.$$,
    $$Lyrian leatherwork. Rough, doesn’t breathe, but it protects the legs. You’ll definitely draw attention, though.$$),

  ('A062','core','bodypart.shield','armor_class.heavy',
    $$Нильфгаардская павеза$$, $$Nilfgaardian Pavise$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    '25',NULL,4,'1','5','600',
    $$Неприятно, конечно, такое говорить, но это лучший щит для арбалетчиков и всех, кто работает с механизмами под вражеским огнём. По размерам нильфгаардская павеза не отличается от обычной, но у неё есть сзади подставка, чтобы щит сам стоял, пока ты оружие перезаряжаешь или работашеь.$$,
    $$Hate to say it, but it’s the best shield for crossbowmen and anyone working mechanisms under enemy fire. It’s the same size as a normal pavise, but it has a stand on the back so it can stand on its own while you reload or work.$$),

  ('A057','dlc_rw2','bodypart.shield','armor_class.medium',
    $$Щит из чешуи виверны$$, $$Wyvern Scale Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    '18',NULL,1,'0','2,5','500',
    $$$$,
    $$$$),

  ('A024','core','bodypart.torso','armor_class.heavy',
    $$Латный доспех$$, $$Plate Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,20,1,'2','14','625',
    $$Такую броню пристало носить рыцарям да королям - крепкие стальные пластины, подогнанные по телу. Тяжеловата, порой в ней едва дышать можно, но много от чего защитит. Иногда выглядит просто и неброско, а иногда пафосно до ужаса.$$,
    $$Armor fit for knights and kings: sturdy steel plates fitted to the body. Heavy—sometimes you can hardly breathe in it—but it protects from a lot. Sometimes it looks simple and plain; sometimes it’s unbearably pompous.$$),

  ('A025','core','bodypart.torso','armor_class.heavy',
    $$Нильфгаардский латный доспех$$, $$Nilfgaardian Plate Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,30,2,'2','12','850',
    $$Это такой чёрно-золотой доспех, крепкий, с высокими наплечниками и кучей деталей. Должен признать, сработан хорошо. От арбалетного болта на нём разве что царапинка останется.$$,
    $$A black-and-gold suit of armor, sturdy, with high pauldrons and lots of details. I have to admit, it’s well made. An arbalest bolt would leave no more than a scratch.$$),

  ('A026','core','bodypart.torso','armor_class.heavy',
    $$Хиндарсфьяльский тяжёлый доспех$$, $$Hindarsfjall Heavy Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,25,3,'2','15','750',
    $$Пару раз всего я на островах Скеллиге бывал. Давным-давно на Хиндарсфьялле посещал храм Фрейи. Снаружи там торчали мечники в совершенно чудовищной броне: тяжёлая кольчуга до колена, кожаная куртка под ней и дублёная кожа сверху, и толстый такой широкий пояс. Думаю, удар алебарды эта дрянь точно выдержит.$$,
    $$I’ve only been to Skellige a couple of times. Long ago, on Hindarsfjall, I visited Freya’s temple. Outside stood swordsmen in truly monstrous armor: heavy mail down to the knees, a leather jacket under it, boiled leather on top, and a thick, wide belt. I think this stuff would definitely take a halberd hit.$$),

  ('A023','hb','bodypart.torso','armor_class.heavy',
    $$Доспех с Ундвика$$, $$Undvik Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,28,3,'2','15','815',
    $$$$,
    $$$$),

  ('A015','hb','bodypart.torso','armor_class.light',
    $$Доспех чародея из Бан Арда$$, $$Ban Ard Mage Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,5,1,'0','3','930',
    $$$$,
    $$$$),

  ('A022','core','bodypart.torso','armor_class.medium',
    $$Кожаная куртка из Лирии$$, $$Lyrian Leather Jacket$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.humans','availability.R',
    NULL,16,1,'1','6,5','525',
    $$Мне однажды довелось примерить кожаную куртку из Лирии. Курва, по ощущениям я на себя напялил чёртовы латы. Лирийцы каким-то особым образом обрабатывают кожу, отчего она становится крепкой, как шкура василиска. Я позволил торговцу в себя из длинного лука выстрелить, так меня даже не поцарапало! Хотя, может, я просто слегка пьян был в тот день.$$,
    $$Once I tried on a Lyrian leather jacket. Damn, it felt like I was putting on plate armor. Lyrians treat leather in a special way, making it as tough as a basilisk hide. I even let a merchant shoot me with a longbow and it didn’t scratch me! Though maybe I was a bit drunk that day.$$),

  ('A019','hb','bodypart.torso','armor_class.medium',
    $$Доспех боевого чародея$$, $$Battlemage Armor$$,
    NULL,NULL,NULL,NULL,'TRUE','TRUE',
    'crafted_by.humans','availability.R',
    NULL,16,1,'1','6','2200',
    $$$$,
    $$$$),

  ('A043','core','bodypart.full','armor_class.heavy',
    $$Доспехи драуга$$, $$Draug Armor$$,
    NULL,NULL,NULL,NULL,'TRUE','TRUE',
    'crafted_by.humans','availability.U',
    NULL,36,3,'3','37',NULL,
    $$$$,
    $$$$),

  ('A041','core','bodypart.full','armor_class.heavy',
    $$Драгунская броня гномьей работы$$, $$Gnomish Dragoon Armor$$,
    'TRUE','TRUE',NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    NULL,25,2,'2','20','2850',
    $$Обычно гномы кавалеристами не становятся, по вполне понятным причинам. Но они выковали броню для людей - командиров кавалерии Нильфгаарда. Лёгкие латы, чёрные с голубым отливом, покрыты гномьей гравировкой. Удар держат как на турнирах, так и на поле боя.$$,
    $$Dwarves don’t become cavalrymen, for obvious reasons. But they forged armor for humans—Nilfgaardian cavalry commanders. Light plate, black with a blue sheen, covered in dwarven engraving. It can take hits both in tournaments and on the battlefield.$$),

  ('A042','core','bodypart.full','armor_class.heavy',
    $$Махакамские латы$$, $$Mahakaman Plate Armor$$,
    'TRUE','TRUE','TRUE',NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    NULL,30,3,'2','30','3525',
    $$Махакаская сталь - прочнее её в мире нет. И потому броня из этой стали всегда будет самой лучшей. Махакамские латы тяжелы, да - тёмная броня, покрытая позолотой и бронзой, угловатыми узорами и краснолюскими рунами. Сам я такую никогда не носил, но разок вёз комплект лат из Махакама в Ангрен. Продал за несколько тысяч.$$,
    $$Mahakaman steel is the strongest in the world, and so armor made from it is always the best. Mahakaman plate is heavy, yes—dark armor covered with gold and bronze, angular patterns and dwarven runes. I’ve never worn it, but once I hauled a set from Mahakam to Angren and sold it for several thousand.$$),

  ('A037','core','bodypart.full','armor_class.light',
    $$Кольчуга гномьей работы$$, $$Gnomish Chain$$,
    NULL,'TRUE',NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    NULL,10,1,'0','5','975',
    $$Созданная гномами кольчужка вся чернёная и полностью тело закрывает - там и капюшо, и хауберг, и шоссы. Просто, красиво и носится без труда. Колечки небольшие, но крепкие, так что кольчужка еще и лёгкая.$$,
    $$The dwarves’ mail is all blackened and covers the whole body—hood, hauberk, and chausses. Simple, beautiful, and comfortable to wear. The rings are small but strong, so the mail is also light.$$),

  ('A038','core','bodypart.full','armor_class.medium',
    $$Броня скоя'таэля$$, $$Scoia’tael Armor$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    NULL,20,2,'1','12','2325',
    $$Не все "белки" носят такую броню - обычно это привилегия командиров спецотрядов, вроде того же Иорвета. Броня хорошая, создана специально, чтобы сливаться с окружением. Вот хоть и ненавижу я скоя'таэлей, но бронька у них отменная.$$,
    $$Not every “squirrel” wears such armor—usually it’s a privilege of special forces commanders, like Iorveth. It’s good armor, made specifically to blend with the surroundings. And though I hate Scoia’tael, their armor is excellent.$$),

  ('A040','core','bodypart.full','armor_class.medium',
    $$Краснолюдский плащ$$, $$Dwarven Cloak$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    NULL,16,1,'0','5','1400',
    $$Такие плащи хороши в дороге. Они и защищают неплохо. Так-то это просто кожа, но настолько хорошо обработанная особым краснолюдским способом, что она не только броню может заменить, но и не промогает.$$,
    $$These cloaks are great on the road. They protect well. It’s just leather, but it’s treated so well in a special dwarven way that it can replace armor—and it doesn’t soak through.$$),

  ('A061','core','bodypart.shield','armor_class.heavy',
    $$Махакамская павеза$$, $$Mahakaman Pavise$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    '35',NULL,4,'1','5,5','1050',
    $$Махакамские бойцы с такими штуковинами защищают свои города. По строению эти павезы аналогичны нильфгаардским, да только сделаны они краснолюдскими ремесленниками, чьё искусство ковки совершенствовалось много веков. Если бы мне пришлось выбирать, за каким щитом спрятаться, я бы выбрал махакамскую павезу.$$,
    $$Mahakam warriors defend their cities with these. Built like Nilfgaardian pavises, but made by dwarven craftsmen whose forging art has been refined over centuries. If I had to choose a shield to hide behind, I’d choose the Mahakaman pavise.$$),

  ('A051','core','bodypart.shield','armor_class.light',
    $$Гномий баклер$$, $$Gnomish Buckler$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    '15',NULL,2,'0','1','450',
    $$То, что для людей баклер, для гнома - полноценный щит. Правда, сомневаюсь, что так эта странная штука на свет появилась. Щит этот сделан по той же технологии, что и прочьи гномьи изделия, да и удар держит получше более крупных щитов.$$,
    $$What is a buckler for humans is a full shield for a dwarf. I doubt that’s how this odd thing first appeared. This shield is made with the same techniques as other dwarven products, and it holds blows better than larger shields.$$),

  ('A060','core','bodypart.shield','armor_class.medium',
    $$Эльфский щит$$, $$Elven Shield$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    '25',NULL,4,'0','3','700',
    $$Теперь таких почти не сыщешь. Партизанская война не особо способствует бою с мечом и щитом. Или же храбрые повстанцы не хотят показаться трусами. Однако эльфский щит прекрасен. По форме каплевидный, с золочением и украшениями в форме листьев.$$,
    $$You can hardly find these anymore. Guerrilla war doesn’t encourage fighting with sword and shield. Or perhaps brave rebels don’t want to look like cowards. Still, the elven shield is splendid: teardrop-shaped, gilded, and decorated with leaf motifs.$$),

  ('A016','core','bodypart.torso','armor_class.light',
    $$Низушечий защитный дублет$$, $$Halfling Protective Doublet$$,
    NULL,NULL,NULL,NULL,NULL,NULL,
    'crafted_by.non-humans','availability.R',
    NULL,8,1,'0','1','375',
    $$Броня - это хорошо. А уж в такие-то времена броню всем носить стоит. Но не каждый может себе позволить кольчугу или латы. Ну и низушки какое-то время назад придумали такой защитный дублет. Снаружи-то он яркий и всячески украшенный, а под тканью скрыт неплохой слой брони.$$,
    $$Armor is good—and in times like these everyone should wear it. But not everyone can afford mail or plate. So halflings came up with a protective doublet some time ago: bright and ornate on the outside, with a decent layer of protection hidden under the fabric.$$),

