\echo '022_wcc_item_vehicles_v.sql'
-- Materialized view for shop UI (vehicles catalog)
-- Provides localized rows per language, plus dlc_id for filtering by allowedDlcs.

DROP MATERIALIZED VIEW IF EXISTS wcc_item_vehicles_v;

CREATE MATERIALIZED VIEW wcc_item_vehicles_v AS
SELECT iv.wt_id
     , iv.dlc_dlc_id AS dlc_id
     , idlcs.text AS dlc
     , iname.text AS vehicle_name
     , isubgrp.text AS subgroup_name
     , iv.base
     , iv.control_modifier
     , iv.speed
     , iv.occupancy
     , iv.upgrade_slots
     , iv.hp
     , coalesce(iv.weight, 0) AS weight
     , coalesce(iv.price, 0) AS price
     , iname.lang
  FROM wcc_item_vehicles iv
  JOIN i18n_text iname ON iname.id = iv.name_id
  LEFT JOIN i18n_text isubgrp
    ON isubgrp.id = iv.subgroup_id
   AND isubgrp.lang = iname.lang
  JOIN wcc_dlcs dlcs ON dlcs.dlc_id = iv.dlc_dlc_id
  JOIN i18n_text idlcs ON idlcs.id = dlcs.name_id AND idlcs.lang = iname.lang
 ORDER BY iname.text;

-- Helpful indexes for shop queries
CREATE UNIQUE INDEX IF NOT EXISTS wcc_item_vehicles_v_wtid_lang_uidx ON wcc_item_vehicles_v (wt_id, lang);
CREATE INDEX IF NOT EXISTS wcc_item_vehicles_v_lang_dlc_idx ON wcc_item_vehicles_v (lang, dlc_id);


-- <<< END sql/items/022_wcc_item_vehicles_v.sql

-- >>> BEGIN sql/items/023_wcc_item_trophies_v.sql

\echo '023_wcc_item_trophies_v.sql'
-- Materialized view for shop UI (trophies catalog)
-- Provides localized rows per language, plus dlc_id for filtering by allowedDlcs.

DROP MATERIALIZED VIEW IF EXISTS wcc_item_trophies_v;

CREATE MATERIALIZED VIEW wcc_item_trophies_v AS
SELECT it.tr_id
     , it.dlc_dlc_id AS dlc_id
     , idlcs.text AS dlc
     , iname.text AS trophy_name
     , imtype.text AS monster_type
     , ieffect.text AS effect
     , coalesce(it.price, 0) AS price
     , iav.text AS availability
     , iname.lang
  FROM wcc_item_trophies it
  JOIN i18n_text iname ON iname.id = it.name_id
  JOIN wcc_dlcs dlcs ON dlcs.dlc_id = it.dlc_dlc_id
  JOIN i18n_text idlcs ON idlcs.id = dlcs.name_id AND idlcs.lang = iname.lang
  LEFT JOIN i18n_text imtype ON imtype.id = it.monster_type_id AND imtype.lang = iname.lang
  LEFT JOIN i18n_text ieffect ON ieffect.id = it.effect_id AND ieffect.lang = iname.lang
  LEFT JOIN i18n_text iav ON iav.id = it.availability_id AND iav.lang = iname.lang
 ORDER BY iname.text;

-- Helpful indexes for shop queries
CREATE UNIQUE INDEX IF NOT EXISTS wcc_item_trophies_v_trid_lang_uidx ON wcc_item_trophies_v (tr_id, lang);
CREATE INDEX IF NOT EXISTS wcc_item_trophies_v_lang_dlc_idx ON wcc_item_trophies_v (lang, dlc_id);
CREATE INDEX IF NOT EXISTS wcc_item_trophies_v_lang_type_idx ON wcc_item_trophies_v (lang, monster_type);


-- <<< END sql/items/023_wcc_item_trophies_v.sql

-- >>> BEGIN sql/items/024_wcc_item_upgrades_v.sql

\echo '024_wcc_item_upgrades_v.sql'
-- Materialized view for shop UI (upgrades catalog)
-- Provides localized rows per language, plus dlc_id for filtering by allowedDlcs.

DROP MATERIALIZED VIEW IF EXISTS wcc_item_upgrades_v;

CREATE MATERIALIZED VIEW wcc_item_upgrades_v AS
SELECT iu.u_id
     , iu.dlc_dlc_id AS dlc_id
     , idlcs.text AS dlc
     , iname.text AS upgrade_name
     , igroup.text AS upgrade_group
     , itarget.text AS target
     , coalesce(iu.slots, 1) AS slots
     , coalesce(iu.price, 0) AS price
     , coalesce(iu.weight, 0) AS weight
     , iav.text AS availability
     , ef.effect_names
     , ef.effect_descriptions
     , iname.lang
  FROM wcc_item_upgrades iu
  JOIN i18n_text iname ON iname.id = iu.name_id
  JOIN wcc_dlcs dlcs ON dlcs.dlc_id = iu.dlc_dlc_id
  JOIN i18n_text idlcs ON idlcs.id = dlcs.name_id AND idlcs.lang = iname.lang
  LEFT JOIN i18n_text igroup ON igroup.id = iu.group_id AND igroup.lang = iname.lang
  LEFT JOIN i18n_text itarget ON itarget.id = iu.target_id AND itarget.lang = iname.lang
  LEFT JOIN i18n_text iav ON iav.id = iu.availability_id AND iav.lang = iname.lang
  LEFT JOIN (
    SELECT ite.item_id
         , ie.lang
         , string_agg(
             replace(coalesce(ie.text, ''), '<mod>', coalesce(ite.modifier::text, ''))
             || coalesce(nullif('[' || coalesce(iec.text, '') || ']', '[]'), ''),
             E'\n'
             ORDER BY ite.e_e_id
           ) AS effect_names
         , string_agg(CASE WHEN e.description_id is not null then
             replace(coalesce(ie.text, ''), '<mod>', coalesce(ite.modifier::text, ''))
             || ' -' || coalesce(nullif(' [' || coalesce(iec.text, '') || ']', ' []'), '')
             || ' ' || replace(coalesce(ide.text, ''), '<mod>', coalesce(ite.modifier::text, ''))
			 end,
             E'\n'
             ORDER BY ite.e_e_id
           ) AS effect_descriptions
      FROM wcc_item_to_effects ite
      LEFT JOIN wcc_item_effects e ON e.e_id = ite.e_e_id
      LEFT JOIN i18n_text ie ON ie.id = e.name_id
      LEFT JOIN i18n_text ide ON ide.id = e.description_id AND ide.lang = ie.lang
      LEFT JOIN wcc_item_effect_conditions ec ON ec.ec_id = ite.ec_ec_id
      LEFT JOIN i18n_text iec ON iec.id = ec.description_id AND iec.lang = ie.lang
     WHERE ite.item_id LIKE 'U%'
     GROUP BY ite.item_id, ie.lang
  ) ef ON iu.u_id = ef.item_id AND ef.lang = iname.lang
 ORDER BY iname.text;

-- Helpful indexes for shop queries
CREATE UNIQUE INDEX IF NOT EXISTS wcc_item_upgrades_v_uid_lang_uidx ON wcc_item_upgrades_v (u_id, lang);
CREATE INDEX IF NOT EXISTS wcc_item_upgrades_v_lang_dlc_idx ON wcc_item_upgrades_v (lang, dlc_id);




-- <<< END sql/items/024_wcc_item_upgrades_v.sql

-- >>> BEGIN sql/items/025_wcc_item_blueprints.sql

\echo '025_wcc_item_blueprints.sql'
-- Узел: Чертежи (blueprints)
-- Источник данных: inline `VALUES (...)` (сформировано из db/sql/items/wcc_items - wcc_item_blueprints.tsv)
--

-- Примечания:
-- - Название чертежа всегда в i18n_text (через name_id). Для item_id без постфикса B — ссылка на название создаваемого объекта (armor/weapon/...). Для item_id с постфиксом B — свои записи в i18n (witcher_cc.items.blueprint.name.<item_id>).
-- - components сохраняем как JSONB массив пар: [{"id": "<uuid>", "qty": <int|null>}, ...]
--   где id — это i18n UUID (ck_id) для *названия* соответствующего предмета (armor/weapon/ingredient/...),
--   qty — число из скобок (если есть), иначе NULL.
-- - Исключение по components: T041, T044, W156 — часть значений отсутствует в i18n, поэтому создаём tech_val ключи и добавляем их в i18n_text.

CREATE TABLE IF NOT EXISTS wcc_item_blueprints (
  b_id              varchar(10) PRIMARY KEY, -- e.g. 'B001'
  item_id           varchar(10) NOT NULL,    -- e.g. 'A001', 'I004', 'W015B', ...
  dlc_dlc_id        varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id),

  name_id           uuid NULL,               -- i18n_text: для не-B — название создаваемого объекта; для ..B — witcher_cc.items.blueprint.name.<item_id>
  availability_id   uuid NULL,               -- ck_id('availability.*') — доступность чертежа (как у брони/оружия)

  group_id          uuid NULL,               -- ck_id(<group_key>) e.g. 'bodypart.head', 'weapons.wt_ammo', ...
  craft_level_id    uuid NULL,               -- ck_id(<craft.level.*>)
  difficulty_check  integer NULL,
  time_value        integer NULL,
  time_unit_id      uuid NULL,               -- ck_id(<time.unit.*>)

  components        jsonb NULL,              

  price_components  integer NULL,
  price_blueprint   integer NULL,
  price_item        integer NULL
);

COMMENT ON TABLE wcc_item_blueprints IS
  'Чертежи для крафта предметов (armor/weapon/ingredients/etc). Названия в i18n_text (name_id). Компоненты — JSONB массив пар (i18n_uuid, qty).';

