\echo '027_wcc_magic_spells.sql'
-- Magic spells (and Witcher Signs) from temp TSV

CREATE TABLE IF NOT EXISTS wcc_magic_spells (
  ms_id              varchar(10) PRIMARY KEY,  -- e.g. 'MS001'
  dlc_dlc_id         varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id),

  level_id           uuid NULL,                -- ck_id('level.*')
  element_id         uuid NULL,                -- ck_id('element.*')
  form_id            uuid NULL,                -- ck_id('magic.form.*')
  effect_time_unit_id uuid NULL,               -- ck_id('time.unit.*')

  name_id            uuid NOT NULL,            -- ck_id('witcher_cc.magic.spell.name.'||ms_id)
  effect_id          uuid NOT NULL,            -- ck_id('witcher_cc.magic.spell.effect.'||ms_id)

  distance           text NULL,
  zone_size          text NULL,
  stamina_cast       text NULL,
  stamina_keeping    text NULL,
  damage             text NULL,
  effect_time_value  text NULL,

  defense_ids        uuid[] NULL,              -- array of ck_id('skill.*') / ck_id('parameter.*') used for defense
  type               text NULL                 -- 'spell' for mage spells, 'sign' for witcher signs
);

-- Add type column if it doesn't exist (migration for existing tables)
DO E'\nBEGIN\n  IF NOT EXISTS (\n    SELECT 1 FROM information_schema.columns\n    WHERE table_name = ''wcc_magic_spells'' AND column_name = ''type''\n  ) THEN\n    ALTER TABLE wcc_magic_spells ADD COLUMN type text NULL;\n  END IF;\nEND ';

WITH raw_data (
  ms_id, dlc_dlc_id,
  level_key, element_key,
  name_ru, name_en,
  effect_ru,
  form_key,
  distance, zone_size,
  stamina_cast, stamina_keeping,
  damage,
  effect_time_value, effect_time_unit_key,
  defense_1, defense_2, defense_3
) AS ( VALUES
  ('MS001', 'core', 'level.novice', 'element.mixed', 'Зеркало Афана', 'Afan''s Mirror', 'Создаёт 1d10 нематериальных и иллюзорных клонов мага никак внешне не отличимых. - Клоны полностью управляются магом без затраты действия - Клоны не могут покидать радиус действия заклинания.', 'magic.form.zone_circle_around', '', '10', '3', '2', '', '', '', '', '', ''),
  ('MS002', 'core', 'level.novice', 'element.mixed', 'Слепящая пыль', 'Blinding Dust', '<align="left">Позволяет направить в глаза цели горсть магической пыли, которая <b><i>ослепит</i></b> её на время действия заклинания.  <b><i>Ослепленная</i></b> цель получает:   * штраф -3 к броскам (Атаки) и (Защиты)   * штраф -5 к проверкам (Внимания), связанным со зрением. - Нужно потратить ход чтобы восстановить зрение.        </align>', 'magic.form.direct', '4', '', '3', '', '', '1d10', 'time.unit.round', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS003', 'core', 'level.novice', 'element.mixed', 'Рассеивание', 'Dispel', 'Позволяет прекратить действие заклинания/ритуала/порчи - Можно сотворить как действие защиты, чтобы блокировать любые магические атаки. - Нужно выиграть встречную проверку <i>(Сотворения заклинаний)</i> для успеха. - Тратит Вын в размере 1/2 стоимости цели', 'magic.form.direct', '10', '', '', '', '', '', '', 'Сотворение заклинаний', '', ''),
  ('MS004', 'core', 'level.novice', 'element.mixed', 'Очарование', 'Glamour', 'Создаёт иллюзию, благодаря которой вы выглядите сногсшибательно! - Мог получает бонус +3 к    * <i>(Соблазнению)</i>    * <i>(Харизме)</i>    * <i>(Лидерству)</i>', 'magic.form.self', '', '', '5', '', '', '1d6', 'time.unit.hour', '', '', ''),
  ('MS005', 'core', 'level.novice', 'element.mixed', 'Магический компас', 'Magic Compass', 'Позволяет мгновенно определить, в каком направлении находится место, где побывал заклинатель, или же просто указывает на север.', 'magic.form.self', '', '', '3', '', '', '1d6', 'time.unit.hour', '', '', ''),
  ('MS006', 'core', 'level.novice', 'element.mixed', 'Управление чувствами', 'Mind Manipulation', 'Позволяет заставить цель испытывать одно из следующих чувств:  - ненависть - любовь - подавленность - эйфория', 'magic.form.direct', '5', '', '3', '', '', '1d10', 'time.unit.round', 'Сопротивление магии', '', ''),
  ('MS007', 'core', 'level.novice', 'element.mixed', 'Призыв посоха', 'Summon Staff', 'Позволяет телепортировать свой посох в место, где заклинатель был за последний день. - Чтобы призвать посох  обратно нужно еще раз выполнить заклинание.', 'magic.form.self', '', '', '2', '', '', '', '', '', '', ''),
  ('MS008', 'core', 'level.novice', 'element.mixed', 'Телепатия', 'Telepathy', 'Позволяет мысленно общаться с одной целью или читать мысли. - Для телепатии не существует языкового барьера. - Если цель - ведьмак, то его медальон завибрирует. - Если цель - маг, то раз в ход он может заметить слежку выиграв бросок <i>(Магических познаний)</i> против <i>(Сотворения заклинаний)</i>.', 'magic.form.direct', '10', '', '2', '1', '', '', '', '', '', ''),
  ('MS009', 'core', 'level.novice', 'element.earth', 'Сенли Грейг', 'Cenlly Graig', 'Метает острые камни в противника. Количество камней равно броску <i>(Сотворение заклинаний)</i> минус бросок <i>(Защиты)</i> и каждый наносит 1d6 урона.', 'magic.form.direct', '5', '', '3', '', '(1..10)*d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS010', 'core', 'level.novice', 'element.earth', 'Коди Бивид', 'Codi Bywyd', 'Позволяет за один ход вырастить из семечка небольшое взрослое растение, т.е. травы и кусты (в т. ч. для алхимии), но не крупные растения вроде деревьев.', 'magic.form.direct', '4', '', '2', '', '', '', '', '', '', ''),
  ('MS011', 'core', 'level.novice', 'element.earth', 'Магическое обследование', 'Diagnostic Spell', '<align="left">Позволяет быстро оценить состояние здоровья цели:  - Количество оставшихся ПЗ - Какие есть критические ранения - Какие на ней эффекты (отравлена/больна ли цель)</align>', 'magic.form.direct', '5', '', '3', '', '', '', '', '', '', ''),
  ('MS012', 'core', 'level.novice', 'element.earth', 'Каменный шип', 'Earthen Spike', 'Выгоняет из земли каменный шип, пронзая цель снизу. Сталагмит остаётся торчать, пока не будет уничтожен, получив 20 пунктов урона.', 'magic.form.direct', '6', '', '5', '', '5d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS013', 'core', 'level.novice', 'element.earth', 'Дыхание Кората', 'Korath''s Breath', 'Метает обжигающую дробь разбитой скалы или земли близ заклинателя, чем <b><i>ослепляет</i></b> цели на 1d6 раундов.', 'magic.form.zone_cone', '', '3', '2', '', '', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS014', 'core', 'level.novice', 'element.earth', 'Перо Лютиэнь', 'Luthien''s Quill', 'Позволяет начертать буквы или рисунок на любой твёрдой поверхности. Нельзя использовать на живых существах.', 'magic.form.direct', '1', '', '2', '', '', '', '', '', '', ''),
  ('MS015', 'core', 'level.novice', 'element.earth', 'Магическое исцеление', 'Magic Healing', 'Эффект на выбор: - Восстанавливает 3 ПЗ за ход. - Лечит крит.ранения, для чего нужно применить спелл [уровень раны]*2+2 раз со <b>Сл:</b>[уровень раны]*2+12, а потом отдых для избавления от штрафов раны (не меньше одного дня): 1) Легкая: 8 - <b>ТЕЛ</b> дней 2) Средняя: 12 - <b>ТЕЛ</b> дней 3) Тяжёлая: 15 - <b>ТЕЛ</b> дней 4) Смертельная: штраф навсегда', 'magic.form.direct', '2', '', '5', '', '', '1d10', 'time.unit.round', '', '', ''),
  ('MS016', 'core', 'level.novice', 'element.earth', 'Тюрьма Тальфрина', 'Talfryn''s Prison', 'Опутывает цель корнями. Их можно уничтожить, у них 15ПЗ. Чтобы выпутаться, можно раз в ход пробросить <i>(Уклонение)</i> больше, чем было в броске <i>(Сотворения заклинаний)</i> при создании тюрьмы.', 'magic.form.direct', '10', '', '3', '', '', '', '', 'Уклонение', '', ''),
  ('MS017', 'core', 'level.novice', 'element.air', 'Адэнидд', 'Adenydd', 'Маг становится легче и планирует вместо падения, не получая урон. Можно двигаться в сторону на то же расстояние, что и вниз.', 'magic.form.self', '', '', '4', '2', '', '', '', '', '', ''),
  ('MS018', 'core', 'level.novice', 'element.air', 'Воздушный пузырь', 'Air Pocket', 'Создаёт пузырь свежего воздуха под водой или в зоне, где обычно чистого воздуха не бывает.', 'magic.form.zone_circle', '12', '1', '3', '', '', '2d10', 'time.unit.round', '', '', ''),
  ('MS019', 'core', 'level.novice', 'element.air', 'Шквал Бронвина', 'Bronwyn''s Gust', 'Наносит собственный урон и отталкивает цель на бросок <i>(Сотворения заклинаний)</i> минус бросок <i>(Защиты)</i> метров.  При столкновении цель получает также урон таранящего удара, то есть [половина дистанции отбрасывания]d6 умноженный на модификатор веса цели.   Модификаторы: 0.5 - Накер, кошка и т.д. 1 - Человек и т.д. 2 - Волколак, Эндриага и т.д. 3 - Главоглаз, Тролль и т.д.', 'magic.form.direct', '2', '', '2', '', '1d6', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS020', 'core', 'level.novice', 'element.air', 'Освежение воздуха', 'Freshen Air', 'Пока дествует, ощичает воздух от дыма, яда или любого другого загрязнения.', 'magic.form.zone_circle_around', '', '4', '2', '2', '', '', '', '', '', ''),
  ('MS021', 'core', 'level.novice', 'element.air', 'Убежище Уриена', 'Urien''s Shelter', 'Отменяет все эффекты плохой погоды: экстремальную жару, экстремальный холод, дождь и снег.', 'magic.form.zone_circle_around', '', '8', '3', '', '', '1d6', 'time.unit.hour', '', '', ''),
  ('MS022', 'core', 'level.novice', 'element.air', 'Статическая буря', 'Static Storm', 'Любой персонаж, кроме самого мага, получает 2 урона статическим электричеством за раунд, если держит или одет в металл.', 'magic.form.zone_circle_around', '', '5', '5', '', '2', '2d6', 'time.unit.round', '', '', ''),
  ('MS023', 'core', 'level.novice', 'element.air', 'Телекинез', 'Telekinesis', 'Позволяет перемещать потоками воздуха предмет весом 5*<i>(Сотворение заклинаний) </i>кг по воздуху. Можно дистанционно применить предмет по назначению, используя вместо нужного навыка <b>ВОЛ</b>+<i>(Сотворение заклинаний)</i> со штрафом -3, а для точных действий даже -5. Бросить предмет можно используя <b>ВОЛ</b> вместо <b>ТЕЛ</b>.', 'magic.form.direct', '5', '', '3', '2', '', '', '', '', '', ''),
  ('MS024', 'core', 'level.novice', 'element.air', 'Зефир', 'Zephyr', 'Наносит собственный урон и отталкивает всех на 6 метров.  При столкновении цель получает также урон таранящего удара, то есть 3d6 умноженный на модификатор веса цели.   Модификаторы: 0.5 - Накер, Кошка и т.д. 1 - Человек и т.д. 2 - Волколак, Эндриага и т.д. 3 - Главоглаз, Тролль и т.д.', 'magic.form.zone_circle', '', '2', '5', '', '1d6', '', '', '', '', ''),
  ('MS025', 'core', 'level.novice', 'element.fire', 'Энье', 'Aenye', 'Метнуть Огненный шар в цель.  - Шанс <b><i>поджечь</i></b> цель - 75%.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '12', '', '5', '', '4d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS026', 'core', 'level.novice', 'element.fire', 'Айна Версеос', 'Aine Verseos', 'Создаёт зону яркого света.  Яркий свет имеет эффекты: - Сложность в применении навыков возрастает на +2. - Штраф -3 к <i>(Вниманию)</i>. - Штраф -3 к <i>(Атаке)</i> и <i>(Защите)</i>, если смотреть на источник света.', 'magic.form.zone_circle_around', '', '4', '1', '2', '', '', '', '', '', ''),
  ('MS027', 'core', 'level.novice', 'element.fire', 'Огненное клеймо', 'Brand of Fire', 'Наносит на обнажённую кожу клеймо с простым символом или словом. - Оставляет большой шрам на всю жизнь - Нечитаемым текст может сделать хирург (Лечащим прикосновением) со <b>Сл:15</b>.', 'magic.form.direct', '8', '', '4', '', '1d6', '', '', '', '', ''),
  ('MS028', 'core', 'level.novice', 'element.fire', 'Хватка Кадфана', 'Cadfan''s Grasp', 'Нагревает металлический предмет.  - Можно заставить кого-то уронить предмет. Если цель отказывается, то получает 2d6 урона по держащей руке. - Можно усилить оружие +2d6 урона и 50%-ным шанс <b><i>поджога</i></b>.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '8', '', '4', '', '', '1d6', 'time.unit.round', '', '', ''),
  ('MS029', 'core', 'level.novice', 'element.fire', 'Магическая вспышка', 'Magic Flare', '<align="left">Вспышка над головой мага <b><i>ослепляет</i></b> всех вокруг на 1d6 раундов. - Вспышку видно на расстоянии 10 километров.  <b><i>Ослепленная</i></b> цель получает:   * штраф -3 к броскам (Атаки) и (Защиты)   * штраф -5 к проверкам (Внимания), связанным со зрением.</align> - Нужно потратить ход чтобы восстановить зрение.', 'magic.form.zone_circle', '', '8', '2', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS030', 'core', 'level.novice', 'element.fire', 'Управление пламенем', 'Raise Flames', 'Управляет уже существующим пламенем. Эффект на выбор: - Усиляет или ослабляет урон на единицу. - Распространяет его на 2 метра за раунд.', 'magic.form.direct', '10', '', '3', '2', '', '', '', '', '', ''),
  ('MS031', 'core', 'level.novice', 'element.fire', 'Танио Ильхар', 'Tanio Ilchar', 'Вполохом пламени <b><i>поджигает</i></b> все цели в зоне поражения с вероятностью 100%.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_square', '8', '2', '3', '', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS032', 'core', 'level.novice', 'element.fire', 'Волна огня', 'Wave of Fire', 'Атака огнём с шансом поджечь 50%.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_cone', '', '3', '4', '', '2d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS033', 'core', 'level.novice', 'element.water', 'Град Кэрис', 'Carys'' Hail', 'Метает от 1 до 5 ледяных осколков в одного противника. Количество осколков - бросок  <i>(Сотворение заклинаний)</i> минус бросок <i>(Защиты)</i>. Вероятность цели заморозки от шипа 25%. Каждый осколок - отдельная атака.', 'magic.form.direct', '5', '', '3', '', '(1..5)*d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS034', 'core', 'level.novice', 'element.water', 'Управление водой', 'Control Water', 'Управляем направлением и скоростью течения. Замедления плавающих целей вдвое, ускорения кораблей в 1.5 раза, или даже замедления или остановка течения. Сложность определяет мастер.', 'magic.form.direct', '10', '', '5', '2', '', '', '', 'СЛ от ведущего', '', ''),
  ('MS035', 'core', 'level.novice', 'element.water', 'Проклятие Седны', 'Curse of Sedna', 'Создаёт водоворот. Цель каждый раунд защищается <i>(Плаванием)</i> против <i>(Сотворения заклинаний)</i> чтобы не оказаться под водой и не начать <b><i>задыхаться</i></b>,  т.е. получать 3 не блокируемого урона за раунд.', 'magic.form.zone_circle', '12', '5', '5', '2', '', '', '', 'Атлетика', '', ''),
  ('MS036', 'core', 'level.novice', 'element.water', 'Туман Дормина', 'Dormyn''s Fog', 'Создаёт зону плотного тумана. Все получают штраф -3 к <i>(Вниманию)</i>, а радиус обзора уменьшается до 4 метров.', 'magic.form.zone_circle_around', '', '10', '3', '2', '', '', '', '', '', ''),
  ('MS037', 'core', 'level.novice', 'element.water', 'Ливень', 'Downpour', 'Вызывает сильный дождь, заливающий любое открытое пламя и отменяет все эффекты <i><b>горения</b></i>.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_circle', '8', '10', '2', '2', '', '', '', '', '', ''),
  ('MS038', 'core', 'level.novice', 'element.water', 'Гололёд', 'Ice Slick', 'Покрывает поверхность льдом. Любой ступивший на него падает подскальзнувшись, провалив проверку <i>(Атлетики) </i>против <i>(Сотворения заклинаний)</i> мага.', 'magic.form.zone_square', '10', '2', '2', '', '', '2d10', 'time.unit.round', 'Атлетика', '', ''),
  ('MS039', 'core', 'level.novice', 'element.water', 'Пиро Дюр', 'Puro Dwr', 'Очищает воду от яда и болезней, оставляя живых существ. Если очищаемой воды меньше куба, то она останется чистой.', 'magic.form.zone_cube', '4', '1', '2', '', '', '1d10', 'time.unit.round', '', '', ''),
  ('MS040', 'core', 'level.novice', 'element.water', 'Рьеви', 'Rhewi', '<b><i>Замораживает</i></b> живую цель, а неживую цель невозможно передвинуть или ею манипулировать.', 'magic.form.direct', '8', '', '2', '', '', '1d10', 'time.unit.round', 'Уклонение', 'Атлетика', ''),
  ('MS041', 'core', 'level.journeyman', 'element.mixed', 'Метод Эйльхарт', 'Eilhart''s Technique', 'Вы извлекаете из памяти цели одну тайну. - При крит.провале защиты цели, её <b>ИНТ</b> навсегда снижается на единицу.', 'magic.form.direct', '3', '', '12', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS042', 'core', 'level.journeyman', 'element.mixed', 'Иллюзия', 'Illusion', 'Создает визуальную иллюзию. - Иллюзия бесшумна, не пахнет и неосязаема. - При крит.провале защиты любой зритель не только видит, но и верит в её реальность.', 'magic.form.zone_circle_around', '', '20', '8', '4', '', '', '', 'Сопротивление магии', '', ''),
  ('MS043', 'core', 'level.journeyman', 'element.mixed', 'Телепортация', 'Teleportation', '<align="left">Переносит мага без пассажира на любую дистанцию. - Вещи можно перенести только те, что в руках или на себе. - Если цель - знакомое место    * <b>Сл:15</b>    * При провале: телепортирует в случайное место в радиусе 1d10 км. - Если цель - незнакомое место    * Нужен предмет из этого места    * <b>Сл:20</b>    * При провале: телепортирует в случайное место в радиусе 3d10 км.</align>', 'magic.form.self', '', '', '10', '', '', '', '', 'СЛ от ведущего', '', ''),
  ('MS044', 'core', 'level.journeyman', 'element.earth', 'Теория Эльгана', 'Elgan''s Theory', 'Делает металлический объект магнитом. Любой металл в зоне действия притягивается и «прилипает» к нему, увеличивая также его вес. Оторвать предмет можно бросив Силу со <b>Сл:18</b>.', 'magic.form.zone_circle', '8', '2', '10', '', '', '2d10', 'time.unit.round', '', '', ''),
  ('MS045', 'core', 'level.journeyman', 'element.earth', 'Ристр Грейг', 'Rhwystr Graig', '- Создает каменную стену размером 2 на 3 метра с 30 ПБ. - Прежде чем урон попадет в скрывающуюся за стеной цель, он будет снижен на текущее значение ПБ стены. Далее урон взаимодействует с нательной бронёй цели по обычным правилам. - При успешном пробитии ПБ стены снижается на 1. - Когда ПБ снизится до нуля, стена будет разрушена.', 'magic.form.direct', '20', '', '15', '', '', '', '', '', '', ''),
  ('MS046', 'core', 'level.journeyman', 'element.earth', 'Землетрясение Стаммельфорда', 'Stammelford''s Earthquake', 'Корёжит землю. - Накладывает на цели штрафы к <b>РЕА</b> -2 и к <b>СКОР</b> -3. - Шанс 10% обрушения мелких строений. - Каждый ход цели через бросок <i>(Атлетики)</i> пытаются не провалиться под землю. Провалившись, начинают <b><i>задыхаться</i></b>, т.е. получать 3 не блокируемого урона за раунд. - Земля остается искорёженной.', 'magic.form.zone_circle', '30', '10', '12', '', '', '1d10', 'time.unit.round', 'Атлетика', '', ''),
  ('MS047', 'core', 'level.journeyman', 'element.air', 'Гром Альзура', 'Alzur''s Thunder', 'Метает молнию с 75%-ным шансом <b><i>горения</i></b> сквозь несколько целей по прямой. Каждой следующей на 1d6 меньше урона.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '25', '', '15', '', '8d6', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS048', 'core', 'level.journeyman', 'element.air', 'Гвинт Троэдли', 'Gwynt Troelli', 'Барьером из ветра блокирует дистанционные атаки, отбрасывая снаряд на 8 метров в случайном направлении, если бросок атаки не превысил <i>(Сотворение заклинаний)</i>.', 'magic.form.zone_circle_around', '', '10', '12', '4', '', '', '', '', '', ''),
  ('MS049', 'core', 'level.journeyman', 'element.air', 'Удушение', 'Suffocate', '- <b><i>Душит</i></b> цель, нанося 1d10 не блокируемого урона каждый раунд. - Цель <b><i>ошеломлена</i></b>. То есть получает штраф -2 к Атаке и Защите, потеряв равновесие. Получив удар или отвлекшись, маг прерывает заклинание.', 'magic.form.direct', '10', '', '14', '4', '1d10', '', '', 'Сопротивление магии', '', ''),
  ('MS050', 'core', 'level.journeyman', 'element.fire', 'Вспышка Деметии Крест', 'Demetia''s Crest Surge', 'Создает огненный щит вокруг мага. - Блокируют 2*<i>(Сотворение заклинаний)</i> заклинаний воды. - Уничтожает снаряды - Не проницаем для живых существ.', 'magic.form.zone_circle_around', '', '10', '12', '4', '', '', '', '', '', ''),
  ('MS051', 'core', 'level.journeyman', 'element.fire', 'Пылающий вихрь', 'Flaming Vortex', 'Создаёт пылающее управляемое торнадо.  - Перемещается на <i>(Сотворение заклинаний)</i> метров за ход. - При контакте у цели 50% шанс <b><i>загореться</i></b>. - Вихрь не уходит дальше дистанции заклинания.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_circle', '10', '1', '15', '4', '5d6', '', '', 'Уклонение', '', ''),
  ('MS052', 'core', 'level.journeyman', 'element.fire', 'Сейриф Хайдь', 'Seirff Haul', 'Несколько огненных змей берут цель в <b><i>захват</i></b> и та <b><i>горит</i></b> - Каждый ход можно предпринимать попытку выбраться броском <i>(Уклонения)</i> против <i>(Сотворения заклинаний)</i> - Каждый ход <b>Сл</b> для броска (Уклонения) растёт на 1. Змеи опоясывают всё туже.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя. <b><i>Захваченная</i></b> цель не может ходить и получает штраф -2 ко фсем физическим действиям.', 'magic.form.direct', '10', '', '10', '', '', '2d10', 'time.unit.round', 'Уклонение', '', ''),
  ('MS053', 'core', 'level.journeyman', 'element.water', 'Аньядьх', 'Anialwch', 'Частично вытягивает жидкость из цели. Наносит одновременно равный смертельный и не смертельный урон.', 'magic.form.direct', '10', '', '8', '', '4d6', '', '', 'Сопротивление магии', '', ''),
  ('MS054', 'core', 'level.journeyman', 'element.water', 'Градобитие Меригольд', 'Merigold''s Hailstorm', 'Создаёт зону мощного града. Цели каждый ход получают урон в случайную часть тела, если проваливают защиту.', 'magic.form.zone_circle', '', '30', '15', '4', '2d6', '', '', 'Уклонение', '', ''),
  ('MS055', 'core', 'level.journeyman', 'element.water', 'Волны Нагльфара', 'Waves of the Naglfar', 'Создаёт волну ледяной магии, <b><i>замораживая</i></b> цели со всех сторон.', 'magic.form.zone_circle', '', '3', '10', '', '4d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS056', 'core', 'level.master', 'element.mixed', 'Мысленный приказ', 'Mental Command', 'Цель выполняет мысленный приказ мага.  - Цель получает +5 к <i>(Сопротивлению магии)</i>, если приказано, что-то, что она никогда бы не сделала. - Цель сопротивляется каждые 1d6 ходов.', 'magic.form.direct', '10', '', '25', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS057', 'core', 'level.master', 'element.mixed', 'Магический портал', 'Standing Portal', '<align="left">Создает портал - Размер: 1x2 метра - Дальность: неограниченная - Можно пронести любые вещи - Отключенный во время прохождения портал наносит крит. рану "потеря конечности" или разрубит вещь надвое. - Если цель - знакомое место, то портал открывается с лёгкостью. - Если цель - незнакомое место    * Нужен предмет из этого места    * Нужна проверка <i>(Сотворения заклинаний)</i> со <b>Сл:20</b>    * При провале: портал ведет в случайное место в радиусе 3d10 км.</align>', 'magic.form.direct', '10', '', '22', '6', '', '', '', 'СЛ от ведущего', '', ''),
  ('MS058', 'core', 'level.master', 'element.earth', 'Полиморфизм', 'Polymorphism', 'Превращает мага в змею, кошку, птицу или собаку с их параметрами, но сохраняя инвентарь. Возврат требует снова сотворить заклинание, но невозможен во время контакта с двимеритом.', 'magic.form.self', '', '', '22', '', '', '', '', '', '', ''),
  ('MS059', 'core', 'level.master', 'element.earth', 'Трансмутация', 'Transmutation', 'Превращает один металл в другой (кроме двимерита), а самоцвет - в совершенный самоцвет.', 'magic.form.direct', '2', '', '25', '', '', '', '', '', '', ''),
  ('MS060', 'core', 'level.master', 'element.air', 'Дервиш', 'Dervish', '- Барьером из ветра блокирует дистанционные атаки, отбрасывая снаряд на 8 метров в случайном направлении, если бросок атаки не превысил бросок <i>(Сотворения заклинаний)</i> - Контактируя с целью наносит  урон 1d6 и отталкивает на 6 метров.  - При столкновении цель получает также урон таранящего удара, то есть 3d6 умноженный на модификатор веса цели.  Маг может только спокойно ходить.', 'magic.form.zone_circle_around', '', '2', '22', '6', '1d6', '', '', 'Атлетика', '', ''),
  ('MS061', 'core', 'level.master', 'element.air', 'Гроза', 'Lightning Storm', 'Каждый ход гроза с шансом 35% бьет молнией по каждой цели (кроме мага). В момент удара цель может попытаться увернуться чтобы не получить урон с 75% шансом <b><i>загореться</i></b>.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_circle', '', '20', '25', '6', '8d6', '', '', 'Уклонение', '', ''),
  ('MS062', 'core', 'level.master', 'element.fire', 'Огонь Мельгара', 'Melgar''s Fire', 'Град из огненных шаров. - Каждый ход с шансом 75% бьет каждую цель (кроме мага) огненным шаром. - Провалив бросок <i>(Защиты)</i>, цель получает урон и с шансом 75% начинает <i><b>гореть</b></i>.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_circle', '', '40', '25', '', '4d6', '2d6', 'time.unit.round', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS063', 'core', 'level.master', 'element.fire', 'Зеркальный эффект', 'Mirror Effect', 'Бьёт не реагирующим на ветер лучом света. - При блокировании луч уничтожает преграду. Но если преградой служит зеркало, то лишь отклоняется в случайном направлении, а зеркало получает урон. - Для каста нужно Солнце, не работает в темноте. - При Луне и пасмурном дне только половина урона.', 'magic.form.direct', '20', '', '25', '', '10d6', '2d6', 'time.unit.round', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS064', 'core', 'level.master', 'element.water', 'Расступление вод', 'Part Water', 'Заставляет воду расступиться (объем до 10x100x10 метров), отгоняя с водой и живых существ (включая мага, если тот в той воде). Стена воды свободно проницаема.', 'magic.form.zone_cube', '10', '10, 100', '25', '6', '', '', '', '', '', ''),
  ('MS065', 'core', 'level.master', 'element.water', 'Трифери Геаф', 'Tryferi Gaeaf', 'Метает 0.5*<i>(Сотворение заклинаний)</i> двухметровых ледяных шипов с 20 прочности. Можно в разные цели. Пробив броню шип замораживает цель, причиняя 2 урона в ход пока не изъят (бросок <i>(Силы)</i> <b>Сл:20</b>), не разрушен, или не кончится заклинание. Каждый шип - отдельная атака.', 'magic.form.direct', '20', '', '22', '', 'x*5d6', '1d10', 'time.unit.round', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS094', 'core', 'level.novice', 'element.mixed', 'Ирден', 'Yrden', 'Создает вокруг заклинателя магический круг, влияющий на цели, пока те в круге. - Вошедшие (кроме заклинателя) получают штраф -[X/2] к <b>СКОР</b> и <b>РЕА</b>, где X - количество вложенной <b>ВЫН</b>. Дробное значение округляется вверх. - Бесплотные существа стано-вятся материальными.', 'magic.form.zone_circle', '', '3', '1-7', '', '', '5', 'time.unit.round', '', '', ''),
  ('MS095', 'core', 'level.novice', 'element.air', 'Аард', 'Aard', 'Аард выпускает волну телекинетической силы. - Все пораженные цели <b><i>ошеломлены</i></b>. То есть получают штраф -2 к <i>(Атаке)</i> и <i>(Защите)</i>, до следующего своего хода. - Шанс <b><i>сбить с ног</i></b> равен X*10%, где X равен количеству вложенных очков <b>ВЫН</b>. Сбитая с ног цель получает еще штраф -2 к (Атаке) и (Защите) пока не потрати перемещение на то чтобы встать.', 'magic.form.zone_cone', '', '2', '1-7', '', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS096', 'core', 'level.novice', 'element.fire', 'Игни', 'Igni', 'Игни испускает волну огня и искр. - Урон равен Xd6, где X - количество очков вложенной <b>ВЫН</b>. - Шанс <b><i>поджечь</i></b> цель 50 %. - Урон по туловищу, но при касте в упор можно выбрать часть тела.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_cone', '', '2', '1-7', '', 'X*d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS097', 'core', 'level.novice', 'element.water', 'Аксий', 'Axii', '<b><i>Дезориентирует</i></b> цель. - Штраф -[X/2] для цели на прохождение испытания <i>(Устойчивости)</i>, где X - количество вложенной <b>ВЫН</b>. Дробное значение округляется вверх. - Можно использовать как <i>(Убеждение)</i>, кидая вместо него <i>(Сотворение заклинаний)</i> и защищаясь <i>(Сопротивлением магии)</i>. Голова и руки мага при этом окутывает заметное свечение.', 'magic.form.direct', '8', '', '1-7', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS098', 'core', 'level.novice', 'element.earth', 'Квен', 'Quen', 'Создает магический щит с [5*X] ПЗ, где X - очки вложенной <b>ВЫН</b>. - Любой урон сперва идет в Квен. - Квен разрушает и смертельный, и не смертельный урон. - Применим против заклинаний с возможностью блокирования. - Не действует на урон статусом (яд, гипоксия, огонь и т.д.). - Нельзя сотворить новый щит Квен, пока действует старый.', 'magic.form.self', '', '', '1-7', '', '', '10', 'time.unit.round', '', '', ''),
  ('MS099', 'core', 'level.journeyman', 'element.mixed', 'Магическая ловушка', 'Magic Trap', '<align="left">Продвинутое владение Ирден создает магическую ловушку. - Каждый раунд ловушка атакует ближайшую цель. - Атаке может подвергнуться только вражеская цель. - На подготовку уходит 1 раунд - Ловушка действует столько раундов, сколько очков <b>ВЫН</b> было вложено в знак.</align>', 'magic.form.zone_circle', '', '3', '1-7', '', '3d6', '1-7', 'time.unit.round', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS100', 'core', 'level.journeyman', 'element.air', 'Сметающий Аард', 'Aard Sweep', 'Продвинутое владение Аардом создает выброс телекине-тической силы в форме сферы. - Все цели в радиусе действия <b><i>ошеломлены</i></b>. - Шанс сбить с ног равен X*10%, где X - количество вложенных очков <b>ВЫН</b>. - Летающие существа получают урон от падения в количестве [H/2]d6, где H - высота падения в метрах.', 'magic.form.zone_circle', '', '4', '1-7', '', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS101', 'core', 'level.journeyman', 'element.fire', 'Огненный поток', 'Fire Stream', 'Продвинутое владение Игни испускает сплошной поток огня. - Урон равен Xd6, где X - очки <b>ВЫН</b>, вложенные в знак.  - Поддержание потока стоит половину вложенных очков <b>ВЫН</b>, округляя вверх. - Шанс <b><i>поджечь</i></b> цель 75%. - В свой ход маг может сменить цель. - Поток можно прицельно направлять в часть тела.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '3', '', '1-7', '1-4', 'X*d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS102', 'core', 'level.journeyman', 'element.water', 'Марионетка', 'Puppet', 'Продвинутое владение Аксием позволяет управлять разумом цели, даля её союзной. - Длится влияние X раундов, где X - количество окчков вложенной <b>ВЫН</b>. - Каждый раунд цель бросает проверку <i>(Сопротивления магии)</i>, пытаясь освободиться.', 'magic.form.direct', '8', '', '1-7', '', '', '1-7', 'time.unit.round', 'Сопротивление магии', '', ''),
  ('MS103', 'core', 'level.journeyman', 'element.earth', 'Активный щит', 'Active Shield', '<align="left">Продвинутое владение Квен создаёт сияющий щит вокруг заклинателя c [10*X] ПЗ, где X - очки вложенной <b>ВЫН</b>.  - Цена поддержки равна цене каста. - Защищает кроме мага и одну  прижавшуюся цель. - Все предметы разрушаются, если проходят через щит. - Бегать нельзя, только ходить. - Если щит сбит или прекращен, то:    * В радиусе 2 метров всё (и союзники) получает урон 1d6 в торс.    * Если предмет легче 226кг и не закреплен, то отбрасывается на 2 метра.</align>', 'magic.form.self', '', '', '1-7', '1-7', '1d6', '', '', '', '', ''),
  ('MS125', 'exp_toc', 'level.novice', 'element.mixed', 'Алхимическое восстановление', 'Alchemical Recovery', 'При провале крафта алхимии восстанавливает одно из веществ. - Нельзя применить к одному проекту дважды. - Можно использовать вместе со стандартным этапом восстановления.', 'magic.form.direct', '2', '', '2', '', '', '', '', '', '', ''),
  ('MS126', 'exp_toc', 'level.novice', 'element.mixed', 'Изъян', 'Blemish', 'Создает небольшую иллюзию на цели, делая её не привлекательой. - Цель получает штраф -3 к проверкам    * <i>(Соблазнения)</i>    * <i>(Харизмы)</i>    * <i>(Лидерства)</i> - Цель не подозревает об изъяне, но может узнать от других или пробросить <i>(Внимательность)</i> со <b>Сл:16</b>, глядя в отражение.', 'magic.form.direct', '4', '', '5', '', '', '1d6', 'time.unit.round', 'Сопротивление магии', '', ''),
  ('MS127', 'exp_toc', 'level.novice', 'element.mixed', 'Обнаружение лей-линий', 'Detect Ley Lines', 'Позволяет найти ближайшую Лей-линию, посылая магический импульс. Рука мага указывает в направлении ближайшей Лей-линии, и он чувствует с каким элементом она связана.', 'magic.form.zone_circle', '', '1609', '2', '', '', '', '', '', '', ''),
  ('MS128', 'exp_toc', 'level.novice', 'element.mixed', 'Погибель Фергуса', 'Fergus'' Demise', 'Позволяет пытать цель, вызывая группу волшебных игл, которые повинуются вашим командам. - Можно использовать для допроса, тогда можно использовать проверку <i>(Сотворения заклинаний)</i> вместо <i>(Запугивания)</i>.', 'magic.form.direct', '2', '', '4', '', '', '1', 'time.unit.hour', '', '', ''),
  ('MS129', 'exp_toc', 'level.novice', 'element.mixed', 'Удержание языка', 'Hold Tongue', 'Губы цели склеены, а язык парализован. - Маг, жрец и друид не могут творить магию, если навык <i>(Сотворения заклинаний)</i> ниже 7.  - Цель сопротивляется против нового броска <i>(Сотворения Заклинаний)</i> каждый ход.', 'magic.form.direct', '10', '', '5', '', '', '10', 'time.unit.minute', 'Сопротивление магии', '', ''),
  ('MS130', 'exp_toc', 'level.novice', 'element.mixed', 'Магический заслон', 'Magic Screen', 'Создает иллюзию, скрывая или изменяя объекты. - Изменение только визуальное - Заклинание может быть рассеяно или прерваться, если какой-либо объект покинул зону действия. - Цель может распознать иллюзию и посмотреть сквозь неё, подойдя на 4 метра и успешно бросив проверку <i>(Сопротивления магии)</i>.', 'magic.form.zone_cube', '4', '2', '3', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS131', 'exp_toc', 'level.novice', 'element.mixed', 'Переоткрытие портала', 'Reopen Portal', 'Вновь открывает не активные порталы.    * Стационарный постоянный портал. Сложность проверки <i>(Сотворения заклинаний)</i> <b>Сл:16</b>    * Устанавливаемый портал другого пользователя магии, если тот закрылся не более 30 секунд назад.  Сложность проверки <i>(Сотворения заклинаний)</i> <b>Сл:20</b>.', 'magic.form.direct', '2', '', '6', '', '', '1', 'time.unit.round', 'СЛ от ведущего', '', ''),
  ('MS132', 'exp_toc', 'level.novice', 'element.mixed', 'Метод Саволлы', 'Savolla''s Method', 'Разрушает ткани трупа, отслаивая при этом мутагенные соединения и те слегка светятся в теле цели. - Позволяет извлечь мутаген с  проверкой <i>(Алхимии)</i> или <i>(Подготовкой ведьмака)</i> со <b>Сл:14</b>.', 'magic.form.direct', '2', '', '5', '', '', '', '', '', '', ''),
  ('MS133', 'exp_toc', 'level.novice', 'element.earth', 'Крифхау', 'Cryfhau', 'Уплотняет материал, повышая текущее и максимальное значение ПБ укрытия на 5. Уплотнить один участок можно лишь раз.', 'magic.form.zone_cube', '2', '2', '4', '', '', '', '', '', '', ''),
  ('MS134', 'exp_toc', 'level.novice', 'element.earth', 'Земляной столб', 'Earthen Pillar', '- Поднимает куб земли из земляной поверхности, являющейся укрытием с 10 ПБ. - Прежде чем урон попадет в скрывающуюся за стеной цель, он будет снижен на текущее значение ПБ столба. Далее урон взаимодействует с нательной бронёй цели по обычным правилам. - При успешном пробитии ПБ столба снижается на 1. - Когда ПБ снизится до нуля, столб будет разрушен.', 'magic.form.zone_cube', '10', '2', '4', '', '', '', '', '', '', ''),
  ('MS135', 'exp_toc', 'level.novice', 'element.earth', 'Обострение чувств', 'Sharpen Senses', 'Вы немедленно получаете преимущества: - Ночное зрение: нет штрафа -2 к <i>(Вниманию)</i> и +2 к <b>Сл</b> при слабом освещении.  - Способность отслеживания запахов. - Хороший слух: бонус +2 к броскам на <i>(Внимание)</i>.  Однако яркий свет или громкий шум вызовут эффект <b><i>ошеломления</i></b>.', 'magic.form.self', '', '', '2', '', '', '30', 'time.unit.minute', '', '', ''),
  ('MS136', 'exp_toc', 'level.novice', 'element.earth', 'Размягчение Земли', 'Soften Earth', 'Превращает землю в трясину или зыбучие пески. Штраф -2 к <i>(Уклонению)</i> и <i>(Атлетике)</i> из-за того, что становится трудно передвигаться.', 'magic.form.zone_cube', '10', '6', '2', '', '', '2d10', 'time.unit.round', '', '', ''),
  ('MS137', 'exp_toc', 'level.novice', 'element.air', 'Бронвинский лук', 'Bronwyn''s Bow', 'Призывает поток воздуха для метания метательного оружия, стрелы/болта или бомбы с использованием <i>(Сотворения заклинаний)</i>. Стрела/болт дают дополнительно 4d6.урона.', 'magic.form.direct', '50', '', '5', '', '', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS138', 'exp_toc', 'level.novice', 'element.air', 'Пылевое покрытие', 'Dust Coating', 'Создает облако пыли, выявляющее невидимых существ на один раунд, плюс одной цели может отменить невидимость, облепив пылью, если та не смогла защититься.', 'magic.form.zone_cube', '20', '10', '3', '2', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS139', 'exp_toc', 'level.novice', 'element.air', 'Легкие ноги', 'Light Feet', 'Увеличивает скорость мага на 5, бег на 15, прыжок на 3.', 'magic.form.self', '', '', '2', '2', '', '', '', '', '', ''),
  ('MS140', 'exp_toc', 'level.novice', 'element.air', 'Усиление запахов', 'Magnify Odor', 'Усиливает запах в области. При провале броска (<i>Стойкости)</i> против вашего броска <b><i></b>(Сотворение заклинаний)<b></i></b> цель <b><i>тошнит</i></b> 1 минуту и воняет неделю, давая +2 к <i>(Отслеживанию)</i> через нюх, но можно смыть вонь полным погружением. У самой цели <i>(Отслеживание)</i> запаха при этом отшибает.', 'magic.form.zone_cube', '10', '6', '5', '', '', '7', 'time.unit.day', '', '', ''),
  ('MS141', 'exp_toc', 'level.novice', 'element.fire', 'Дыхание огня', 'Breath of Fire', 'Выдыхает струю магического огня. Цель получает урон и <b><i>загорается</i></b> с шансом 100%.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '4', '', '4', '', '3d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS142', 'exp_toc', 'level.novice', 'element.fire', 'Пламенное покрытие', 'Coating of Fire', 'Шанс <b><i>загореться</i></b> становится 100% при контакте с любым открытм огнём или чем-то с любым шансом поджога.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '2', '', '3', '', '', '1', 'time.unit.hour', 'Уклонение', 'Атлетика', ''),
  ('MS143', 'exp_toc', 'level.novice', 'element.fire', 'Безобидное пламя', 'Harmless Fire', 'Делает тепло и огнь в области безопасным. - Он не распространяется и не причиняет вреда. - От огненных атак цели всё еще получают урон.', 'magic.form.zone_cube', '8', '2', '3', '', '', '10', 'time.unit.minute', '', '', ''),
  ('MS144', 'exp_toc', 'level.novice', 'element.fire', 'Дым Вахилы', 'Vahila''s Smoke', 'Окутывает голову цели дымом. - Цель <b><i>слепнет</i></b> и <b><i>задыхается</i></b>, т.е. получает 3 не блокируемого урона за раунд. - Каждый ход, с тратой действия, можно пытаться развеять новым броском <i>(Защиты)</i> против новой проверки <i>(Сотворения заклинаний)</i>.  <b><i>Ослепленная</i></b> цель получает:   * штраф -3 к броскам (Атаки) и (Защиты)   * штраф -5 к проверкам (Внимания), связанным со зрением.</align> - Нужно потратить ход чтобы восстановить зрение.', 'magic.form.direct', '10', '', '3', '2', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS145', 'exp_toc', 'level.novice', 'element.water', 'Дыхание Авроры', 'Aurora''s Breath', 'Позволяет дышать водой.', 'magic.form.self', '', '', '5', '', '', '30', 'time.unit.minute', '', '', ''),
  ('MS146', 'exp_toc', 'level.novice', 'element.water', 'Скользящий поток', 'Slip Stream', '<align="left">Увеличивает скорость плавания на 12, отменяет штрафы за атаку и защиту под водой.  Обычные штрафы под водой: - Скорость атаки ближним боем равна одному удару за раунд. - К атаке, блокированию и парированию штраф -2. - К <i>(Вниманию)</i> штраф -3. - Вместо <i>(Уклонения)</i> только <i>(Атлетика)</i> для защиты. И при движении. - Дальность стрельбы из лука и арбалета 25</align>% от нормы, а урон 50%.', 'magic.form.self', '', '', '5', '', '', '10', 'time.unit.minute', '', '', ''),
  ('MS147', 'exp_toc', 'level.novice', 'element.water', 'Струя воды', 'Water Jet', 'Создает управляемый гейзер из источника воды. Наносит урон с типом урона на ваш выбор и <b><i>сбивает с ног</i></b>. - Сбитая с ног цель получает штраф -2 к (Атаке) и (Защите) пока не потратит перемещение на то чтобы встать.', 'magic.form.direct', '8', '', '5', '', '4d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS148', 'exp_toc', 'level.novice', 'element.water', 'Паутина льда', 'Web of Ice', 'Создаёт на поверхности тонкую ледяную структуру, которую можно обнаружить пробросив <i>(Внимание)</i> со <b>Сл:16</b>. При наличии двух связанных структур, потревожив одну, разрушатся обе.', 'magic.form.direct', '2', '', '2', '', '', '1', 'time.unit.day', '', '', ''),
  ('MS149', 'exp_toc', 'level.journeyman', 'element.mixed', 'Покров', 'Cloak', '<align="left">Дает невидимость магу и всему, что он носит. - Бонус +10 к <i>(Скрытности)</i> - Бонус +5 к <i>(Атаке)</i> - Бонус +5 к <i>(Защите)</i> - бонусы для <i>(Атаки)</i> и <i>(Защиты)</i> становится +3, если:     * Цель бросает проверку <i>(Внимания)</i>      * Цель кастует Ирден     * Цель бросает бомбу "Лунная пыль" - Бонус для <i>(Скрытности)</i> становится +5, если:     * Цель кастует Ирден     * Цель бросает бомбу "Лунная пыль" - При попадании атаки по вам заклинание спадает.</align>', 'magic.form.self', '', '', '16', '2', '', '', '', '', '', ''),
  ('MS150', 'exp_toc', 'level.journeyman', 'element.mixed', 'Разрыв фокусировки', 'Disrupt Focus', 'Временно отключает эффект Фокусировки в предмете с таким эффектом.  Эффект "Фокусирующее (n)" :При сотворении магии с помощью этого оружия вычтите n из стоимости заклинания в Выносливости. Эффект "Фокусирующее (+)": Бонус +2 к <b>Сл</b> проверок против заклинания владельца предмета.', 'magic.form.direct', '10', '', '15', '', '', '10', 'time.unit.minute', '', '', ''),
  ('MS151', 'exp_toc', 'level.journeyman', 'element.mixed', 'Камера Дормина', 'Dormyn''s Chamber', 'Запечатывает цель в полупрозрачном магическом пузыре. - Пузырь имеет 40 ПЗ. - Сквозь пузырь нельзя выбрать цель в обе стороны. - Звук не проходит.', 'magic.form.direct', '10', '', '18', '8', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS152', 'exp_toc', 'level.journeyman', 'element.mixed', 'Усиление', 'Empower', '<align="left">Следующее заклинание мага после усиления имеет эффект выбор: - Шанс наступления эффекта 100%. - Бонус +2 к <i>(Сотворению заклинаний)</i>  - Дополнительный урон 2d6.  - При крит.провале (1 на дайсе) маг получает:   * Любой фокусирующий предмет у мага взрывается на 1d10 урона в радиусе 2 метров.    * Безусловные 20 урона    * Случайный эффект из следующих:       1. Маг <b><i>загорается</i></b>        2. Маг <b><i>заморожен</i></b>         3. Мага отбрасывает на 2 метра.        4. Маг <b><i>дизориентирован</i></b></align>', 'magic.form.self', '', '', '12', '', '', '1', 'time.unit.minute', '', '', ''),
  ('MS153', 'exp_toc', 'level.journeyman', 'element.mixed', 'Спектральная связь', 'Spectral Tether', 'Не позволяет цели:    * Становиться бестелесной    * Становиться невидимой    * Телепортироваться    * Удаляться более чем на 10 м от мага - Можно на каждому ходу пытаться сбросить эффекты связи новой проверкой <i>(Сопротивления магии)</i> против нового броска <i>(Атаки)</i> ценой траты действия.', 'magic.form.direct', '10', '', '8', '4', '', '', '', 'Сопротивление магии', '', ''),
  ('MS154', 'exp_toc', 'level.journeyman', 'element.mixed', 'Портал-ловушка', 'Trap Portal', 'Размещает ловушку в существующем портале, перенаправляя его конечную точку в пределах 1.6км от настоящей. - Можно заметить, если успешно пробросить <i>(Магическое познание)</i> со <b>Сл:16</b> или <i>(Образование)</i> со <b>Сл:20</b>. - Работает только на одном существе, проходящем через портал. - Следы ловушки в портале можно обнаружить даже через 30 дней после наложения.', 'magic.form.direct', '4', '', '12', '', '', '30', 'time.unit.day', '', '', ''),
  ('MS155', 'exp_toc', 'level.journeyman', 'element.earth', 'Обвал Беккера', 'Bekker''s Rockslide', '- Бросает из-под земли большой камень в цель, нанося урон 6d6 по торсу и <b><i>сбивая с ног</i></b>, если та провалит защиту.  - Осколки наносят 4d6 урона по торсу любому в радиусе 6м при провале <i>(Атлетики)</i> со <b>Сл:16</b>, также <b><i>сбивая с ног</i></b>. - Сбитая с ног цель получает штраф -2 к (Атаке) и (Защите) пока не потратит перемещение на то чтобы встать.', 'magic.form.zone_circle', '10', '6', '13', '', '6d6', '', '', 'Атлетика', '', ''),
  ('MS156', 'exp_toc', 'level.journeyman', 'element.earth', 'Бастион Элгана', 'Elgan''s Bastion', 'Магнетизмом создает круговое каменное укрытие из камней вокруг мага. - Защищающает от физических атак. - Укрытие имеет 30 ПБ - Снижает скорость до 2 и маг может лишь двигаться и только один раз в раунд.', 'magic.form.self', '', '', '14', '4', '', '', '', '', '', ''),
  ('MS157', 'exp_toc', 'level.journeyman', 'element.earth', 'Рой Яведа', 'Javed''s Swarm', '<align="left">Приманивает подконтрольный рой насекомых, атакующий облеплением. Характеристики роя:    * ПЗ - 15    * <b>СКОР</b> - 7    * <i>(Уклонение) </i>основа - 14.    * Урон - 1d6 по торсу, который не блокируется бронёй.    * Шанс 100% <i><b>отравить</b></i> в атаке. То есть цель получает 3 не блокируемого урона за раунд. Для прекращения отравления нужно пробросить <i>(Стойкость)</i> со <b>Сл:15,</b> потратив действие.', 'magic.form.direct', '6', '', '10', '', '', '10', 'time.unit.minute', '', '', ''),
  ('MS158', 'exp_toc', 'level.journeyman', 'element.air', 'Шаровая молния', 'Ball Lightning', 'Создает подконтрольную одноразовую магическую молнию, наносящую урон по торсу и крит.эффект <b>Контузию</b> на 10 минут. При успешном уклонении цели на следующем ходу можно опять действием направить её в цель.', 'magic.form.direct', '20', '', '14', '', '3d6', '5', 'time.unit.round', 'Уклонение', 'Атлетика', ''),
  ('MS159', 'exp_toc', 'level.journeyman', 'element.air', 'Невидимая лента', 'Invisible Ribbon', 'Создает невидимое лезвие ветра, наносящее 3d6 урона. Бросок Внимания СЛ20 чтобы понять источник атаки. Кастуется шёпотом.', 'magic.form.direct', '10', '', '15', '', '3d6', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS160', 'exp_toc', 'level.journeyman', 'element.air', 'Прикосновение молнии', 'Touch of Lightning', 'Заряжает неподвижный металлический предмет электричеством, наносящим 1d6 урона. Можно усилить, поддерживая каст, по 1d6 за ход до 8d6 урона. При движении и через сутки предмет теряет заряд. Обнаруживается броском <i>(Внимания) <b></i>Сл:20</b>.', 'magic.form.direct', '2', '', '8', '5', '(1..8)*d6', '', '', '', '', ''),
  ('MS161', 'exp_toc', 'level.journeyman', 'element.fire', 'Укольная дверь', 'Cinder Door', 'Жгёт горючие структуры. Наносит 4d6 разрушающего урона горючему материалу какждый раунд пока активно, не повреждая ничего другого.', 'magic.form.zone_cube', '2', '2', '12', '3', '4d6', '', '', '', '', ''),
  ('MS162', 'exp_toc', 'level.journeyman', 'element.fire', 'Магическая кузница', 'Mage''s Forge', 'Создает волшебный огонь. - Можно использовать как походную кузницу. - Можно использовать для очистки металла. При провале крафта металл автоматически будет восстанавливаться. - Невозможно исползовать на двимерите.', 'magic.form.direct', '2', '', '12', '', '', '1', 'time.unit.day', '', '', ''),
  ('MS163', 'exp_toc', 'level.journeyman', 'element.fire', 'Прикосновение кузнеца', 'Smith''s Touch', 'Позволяет манипулировать металлом как глиной голыми руками. - В бою, в качестве атаки наносит 3d6 разрушающего урона доспехам или оружию. - Не применимо к двимериту.', 'magic.form.direct', '2', '', '10', '10', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS164', 'exp_toc', 'level.journeyman', 'element.water', 'Эссенция зелья', 'Essence of Potion', 'Один раз копирует свойства одного зелья или эликсира, перенося их в единицу Эссенции Воды.', 'magic.form.direct', '2', '', '12', '', '', '', '', '', '', ''),
  ('MS165', 'exp_toc', 'level.journeyman', 'element.water', 'Инверн', 'Invaerne', 'Создает воющуий снежный ветер, создавая снежные и ледяные условия. На холоде может работать до недели.', 'magic.form.zone_circle', '50', '50', '14', '', '', '1', 'time.unit.hour', '', '', ''),
  ('MS166', 'exp_toc', 'level.journeyman', 'element.water', 'Коррозия', 'Rusting', 'Наносит 2d6 разрушающего урона на выбор всем доспехам или оружию. При блоке щитом урон получает только щит. - Каждый поврежденный предмет доспеха дает -2 штраф к <b>РЕА</b>, <b>ЛВК</b>, <b>СКОР</b>. - Поврежденное оружие дает штраф -2 на атаки. Устраняется проверкой Ремесла СЛ14 за час с десяти предметов.', 'magic.form.direct', '4', '', '14', '', '', '', '', 'Уклонение', 'Атлетика', 'Блокирование'),
  ('MS167', 'exp_toc', 'level.master', 'element.mixed', 'Тёмное зеркало Беккера', 'Bekker''s Dark Mirror', 'Околдовывает отражающую поверхность с отражением цели, поймав её отражение. - Снижает две характеристики цели на 1d6, уменьшая и связанные доп. характеристики. - Во время действия цель не дает других отражений. - Снимается уничтожением отражения. - Цель должна быть способна отражаться.', 'magic.form.direct', '10', '', '25', '', '', '30', 'time.unit.day', 'Сопротивление магии', '', ''),
  ('MS168', 'exp_toc', 'level.master', 'element.mixed', 'Кража заклинаний', 'Steal Spell', 'Переназначает цель заклинания другого мага не уровня мастера. - Цель должна быть в зоне досягаемости другого мага. - Требуется встречная проверка  <i>(Сотворения заклинания)</i>. - Если заклинание требует проверки <i>(Атаки)</i>, используйте проверку <i>(Сотворения заклинаний)</i> из встречной проверки. - Активное заклинание теперь поддерживается вашей выносливостью.', 'magic.form.direct', '10', '', '20', '', '', '', '', 'Сотворение заклинаний', '', ''),
  ('MS169', 'exp_toc', 'level.master', 'element.earth', 'Кристаллический Стазис', 'Crystal Stasis', 'Окружает цель кристаллами. Требуется активная поддержка еще 2 хода для полного наложения. Прерванное заклинание теряет все эффекты. Наложенное снимается рассеиванием магии. - На первом ходу дает цели штраф -3 к Атаке, Защите и <b>СКОР</b>. - На втором ходу цель не может двигаться. - На третьем - цель <b><i>теряет сознание</i></b> на годы, не старея.', 'magic.form.direct', '6', '', '25', '6', '', '', '', 'Сопротивление магии', 'Уклонение', 'Атлетика'),
  ('MS170', 'exp_toc', 'level.master', 'element.earth', 'Формование Земли', 'Shape Earth', 'Создает структуру за 10 минут из доступных материалов, включая дерево, в пределах зоны влияния любой не сложной формы.   ПБ (5-30) такого укрытия определяется Мастером в зависимости от материала и формы.', 'magic.form.zone_cube', '6', '20', '25', '', '', '', '', '', '', ''),
  ('MS171', 'exp_toc', 'level.master', 'element.air', 'Гвинтог', 'Gwyntog', 'Создает бурю. - Летающие существа получают урон от падения в количество [X/2]d6, где X - высота падения в метрах. - Летающие существа  <b><i>сбиваются с ног</i></b>. Сбитая с ног цель получает штраф -2 к (Атаке) и (Защите) пока не потратит перемещение на то чтобы встать. - Дальнобойные атаки вместо цели попадают туда, куда решит мастер. Перемещение или бег возможны после броска <i>(Атлетики)</i> <b>Сл:20</b>.', 'magic.form.zone_circle', '100', '40', '24', '6', '', '', '', '', '', ''),
  ('MS172', 'exp_toc', 'level.master', 'element.air', 'Рука бури', 'Hand of the Tempest', 'Эффект на выбор: - Подбросить до 1000кг на 14 метров. Живая цель может бросить проверку <i>(Уклонения)</i>. Падать начнет к концу следующего хода. При падении объект и то, что под ним получает 7d6 дробящего урона по корпусу, а объект <b><i>сбивается с ног</i></b>. Сбитая с ног цель получает штраф -2 к (Атаке) и (Защите) пока не потратит перемещение на то чтобы встать. - Толкнуть проваливших защиту цели в конусе на 14 метров назад. Врезаясь цели получают таранящий урон. - Управление объектом до 1000кг будто рукой (телекинез).', 'magic.form.direct', '20', '', '25', '', '', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS173', 'exp_toc', 'level.master', 'element.fire', 'Пламя Кората', 'Blaze of the Korath', '<align="left">Создает ауру, истощающую <b>ВЫН</b> всех существ на 2d6   * в момент каста   * в начале своего хода цели   * при входе на своём ходу. - Цели не могут отдохнуть. - При снижении <b>ВЫН</b> до 0, существо <i><b>теряет сознание</b></i> пока не восстановит 20 <b>ВЫН</b> и не пробросит испытание <i>(Устойчивости)</i>.</align>', 'magic.form.zone_circle', '100', '40', '24', '4', '', '', '', '', '', ''),
  ('MS174', 'exp_toc', 'level.master', 'element.fire', 'Живой огонь', 'Living Fire', '<align="left">Призывает бесплотный управляемый Живой Огонь. Характеристики огня:    * <b>СКОР</b> 5.    * <b>ВЫН</b> - бесконечная    * <i>(Сотворение Заклинаний)</i> основа - 16    * Знает спеллы:       - Энье       - Волна огня       - Пылающий вихрь   * Нет дополнительных действий   * Может быть потушен как любой огонь.   * Из-за бесплотности имеет иммунитет к физическим атакам, кровотечению и яду.</align>', 'magic.form.direct', '10', '', '25', '', '', '10', 'time.unit.minute', '', '', ''),
  ('MS175', 'exp_toc', 'level.master', 'element.water', 'Извлечение Айфры', 'Ainfra''s Extraction', 'Высасывает влагу цели, снижая её <b>ВЫН</b> на 8d6. Влагу можно немедленно направить в Рьеви, Гололед или Струю воды без затрат <b>ВЫН</b>.', 'magic.form.direct', '', '', '22', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS176', 'exp_toc', 'level.master', 'element.water', 'Потоп Ис', 'Deluge of Ys', 'Призывает куб воды, который разливается в течение этого же хода на открытой местности, а в замкнутом пространстве заполняет его и разрушает неукрепленные барьеры.  - Волна также наносит урон по торсу и <b><i>сбивает всех с ног</i></b> при провале броска на <i>(Силу)</i> <b>Сл:24.</b> Сбитая с ног цель получает штраф -2 к (Атаке) и (Защите) пока не потратит перемещение на то чтобы встать.', 'magic.form.zone_cube', '40', '20', '24', '', '5d6', '', '', '', '', ''),
  ('MS210', 'exp_toc', 'level.journeyman', 'element.water', 'Сомна', 'Somne', '<align="left">Усыпляет цель на 8 часов, <b><i>дезориентируя</i></b> её. - Если X - количество очков вложенной <b>ВЫН</b>, то цель может проснуться от:    * Громкого шума - при X = 2..3    * Попытки разбудить действием - при X = 2..5    * Попытки разбудить полного раунда - при X = 2..6    * Урона - при X = 2..7 - Цель не узнает о влиянии магии при пробуждении, если нет причин подозревать о нем.</align>', 'magic.form.direct', '8', '', '2-7', '', '', '', '', 'Сопротивление магии', '', ''),
  ('MS211', 'exp_toc', 'level.journeyman', 'element.mixed', 'Супирре', 'Supirre', 'Нанеся знак на поверхность, можно слышать происходящее рядом с любого расстояния без проверки <i>(Внимания)</i>, "подключившись" к нему сознанием. - Радиус зоны слышимости от нанесенного знака [2*X] метров, где X - очки вложенной <b>ВЫН</b>. - Можно сосредоточиться на одном звуке или разговоре, "отключив" все остальные шумы. - Нанося новый знак, маг теряет связь со старым.', 'magic.form.zone_circle', '2', '2..14', '1-7', '', '', '', '', '', '', ''),
  ('MS228', 'exp_bot', 'level.journeyman', 'element.mixed', 'Процедура Прис', 'Preece’s Procedure', 'Временно блокирует одну эмоцию (Ненависть, Любовь, Депрессия, Счастье) у цели. - Цель не подозревает о магическом воздействии ни во время, ни после завершения влияния. - При повторном наложении на цель, уже находящуюся под его воздействием, <b>ВЫН</b> для применения увеличивается на 2.', 'magic.form.direct', '3', '', '10', '', '', '8', 'time.unit.hour', 'Сопротивление магии', '', ''),
  ('MS229', 'exp_bot', 'level.journeyman', 'element.air', 'Акхан Дааль', 'Akhan Daal', E'Создаёт взрыв сотрясающей энергии. - Цели получают урон по туловищу - Цели сбиваются с ног - Цели отбрасываются на 4 метра - При столкновении с чем-либо цели получают таранящий урон, т.е. 2d6 умноженный на модификатор веса цели. \n \n Модификаторы тарана:\n 0.5 - Накер, кошка и т.д.\n 1 - Человек и т.д.\n 2 - Волколак, Эндриага и т.д.\n 3 - Главоглаз, Тролль и т.д.', 'magic.form.zone_circle', '4', '2', '12', '', '4d6', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS230', 'exp_bot', 'level.journeyman', 'element.mixed', 'Замещение де Клодин', 'De Claudine’s Substitution', 'Позволяет навсегда изменить одну единицу алхимического ингредиента. - Мутированный ингредиент меняет содержащийся в нем алхимический ингредиент на любой другой. - В алхимической формуле можно использовать только одну единицу трансмутированного вещества без разрушения смеси.', 'magic.form.direct', '2', '', '8', '', '', '', '', '', '', ''),
  ('MS231', 'exp_bot', 'level.journeyman', 'element.air', 'Шторм ван Аделаиды', 'Van Adelaide''s Gale', E'Переносит вас на расстояние до 30м мощным ветром с мягкой посадкой без получения урона. - Порыв ветра в момент прыжка:   * отбрасывает любого на 6м   * цели получают урон в корпус   * цели получают дополнительно та-ранящий урон при столкновении. Т.е. 3d6 умноженный на модификатор веса цели. \n \n Модификаторы тарана:\n 0.5 - Накер, кошка и т.д.\n 1 - Человек и т.д.\n 2 - Волколак, Эндриага и т.д.\n 3 - Главоглаз, Тролль и т.д.', 'magic.form.zone_circle', '', '2', '12', '', '1d6', '', '', 'Уклонение', 'Атлетика', ''),
  ('MS232', 'exp_toc', 'level.journeyman', 'element.necromancy', 'Восстановление трупа', 'Corpse Restoration', 'Восстанавливает мышцы, плоть, кожу и волосы целевого трупа в призрачной форме. Восстановленный труп выглядит как полупрозрачная версия человека в момент смерти со всеми ранами. Форму можно трогать и исследовать как настоящую. Можно призвать части тела, которые у вас есть, даже если они не соединены, в пределах 4м. - При провале происходит вторжение Беспокойных Духов.', 'magic.form.direct', '4', '', '7', '', '', '1', 'time.unit.hour', '', '', ''),
  ('MS233', 'exp_toc', 'level.master', 'element.necromancy', 'Буря душ', 'Storm of Souls', 'Втягивает беспокойные души в мир, чтобы сеять хаос. Сразу после сотворения призывается 1d6+4 призрака, ослепленных яростью. Они атакуют любую цель, включая заклинателя и союзников. - При провале происходит вторжение Беспокойных Духов.', 'magic.form.direct', '10', '', '22', '', '', '2d6', 'time.unit.round', '', '', '')
),
spell_effects_en (ms_id, text_en) AS (
  VALUES
    ('MS001', E'Creates 1d10 intangible, illusory clones of the mage that are indistinguishable from the original.\n- The clones are fully controlled by the mage without spending an action.\n- The clones cannot leave the spell''s radius.'),
    ('MS002', E'You fling a handful of magical dust into the target''s eyes, Blinding them for the spell''s duration.\nA Blinded target suffers:\n* -3 to Attack and Defense rolls\n* -5 to sight-based Awareness checks\n- The target must spend a turn to clear their vision.'),
    ('MS003', E'Ends an active spell/ritual/hex.\n- May be cast as a defensive action to block magical attacks.\n- You must win an opposed (Spell Casting) check.\n- Costs STA equal to 1/2 of the target effect''s STA cost.'),
    ('MS004', E'Creates an illusion that makes you look stunning.\n- You gain +3 to (Seduction), (Charisma), and (Leadership).'),
    ('MS005', 'Instantly determines the direction to a place the caster has visited, or simply points north.'),
    ('MS006', E'Forces the target to feel one of the following:\n- hatred\n- love\n- depression\n- euphoria'),
    ('MS007', E'Teleports your staff to a location the caster has been within the last day.\n- To return the staff, cast this spell again.'),
    ('MS008', E'Allows you to communicate telepathically with one target, or read thoughts.\n- There is no language barrier.\n- If the target is a witcher, their medallion vibrates.\n- If the target is a mage, once per turn they may notice the intrusion by winning a (Magical Knowledge) check vs your (Spell Casting) check.'),
    ('MS009', E'Hurls sharp stones at the enemy.\nThe number of stones equals your (Spell Casting) roll minus the target''s Defense roll; each stone deals 1d6 damage.'),
    ('MS010', 'In one turn, grows a small mature plant from a seed (herbs and bushes, including alchemy plants), but not large plants like trees.'),
    ('MS011', E'Quickly assesses the target''s health:\n- remaining HP\n- critical wounds\n- any active effects (poisoned/sick, etc.'),
    ('MS012', E'Forces a stone spike up from the ground, impaling the target from below.\nThe stalagmite remains until destroyed after taking 20 damage.'),
    ('MS013', 'Throws scorching shards of shattered rock/earth near the caster, Blinding targets for 1d6 rounds.'),
    ('MS014', E'Writes letters or draws on any hard surface.\nCannot be used on living creatures.'),
    ('MS015', E'Choose one effect:\n- Restores 3 HP per turn.\n- Heals critical wounds: you must cast the spell [wound level]*2+2 times at DC [wound level]*2+12, then rest to remove wound penalties (at least one day):\n1) Light: DC 8 — BODY days\n2) Moderate: DC 12 — BODY days\n3) Severe: DC 15 — BODY days\n4) Mortal: penalty is permanent'),
    ('MS016', E'Entangles the target with roots (15 HP).\nTo break free, once per turn the target may roll (Dodge/Escape) higher than your original (Spell Casting) roll used to create the prison.'),
    ('MS017', E'The mage becomes lighter and glides instead of falling, taking no fall damage.\nYou may drift sideways as far as you fall downward.'),
    ('MS018', 'Creates a pocket of fresh air underwater or in an area where clean air normally doesn''t exist.'),
    ('MS019', E'Deals its listed damage and pushes the target back by (Spell Casting) minus the target''s Defense, in meters.\nOn collision, the target also takes ramming damage: [half the push distance]d6 multiplied by the target''s weight modifier.\nWeight modifiers:\n0.5 — nekker, cat, etc.\n1 — human, etc.\n2 — werewolf, endriaga, etc.\n3 — fiend, troll, etc.'),
    ('MS020', 'While active, cleans the air of smoke, poison, or any other contamination.'),
    ('MS021', 'Cancels all effects of bad weather: extreme heat, extreme cold, rain, and snow.'),
    ('MS022', 'Any character except the mage takes 2 damage from static electricity each round if holding or wearing metal.'),
    ('MS023', E'Moves an object weighing up to 5*(Spell Casting) kg through the air.\nYou may use the object remotely for its intended purpose, rolling WILL+(Spell Casting) instead of the required skill at -3 (or -5 for delicate actions).\nYou may also throw objects using WILL instead of BODY.'),
    ('MS024', E'Deals its listed damage and pushes everyone back 6 meters.\nOn collision, ramming damage is 3d6 multiplied by the target''s weight modifier (see Bronwyn''s Gust).'),
    ('MS025', E'Throws a fireball at the target.\n- 75% chance to set the target on fire.\nA Burning target takes 5 damage to each body part each round. Armor absorbs damage but loses 1 SP (as do weapons). It takes a turn to put out the flames.'),
    ('MS026', E'Creates an area of bright light. Bright light effects:\n- +2 to the DC of skill checks\n- -3 to (Awareness)\n- -3 to (Attack) and (Defense) if looking at the light source'),
    ('MS027', E'Brands bare skin with a simple symbol or word.\n- Leaves a large scar for life.\n- A surgeon can make the text unreadable with Healing Touch at DC 15.'),
    ('MS028', E'Heats a metal object.\n- You can force someone to drop it; if they refuse, they take 2d6 damage to the holding hand.\n- You can empower a weapon: +2d6 damage and a 50% chance to set the target on fire.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS029', E'A flare above the mage blinds everyone around for 1d6 rounds.\n- Visible from 10 km.\nA Blinded target suffers:\n* -3 to Attack and Defense rolls\n* -5 to sight-based Awareness checks\n- The target must spend a turn to clear their vision.'),
    ('MS030', E'Controls an existing flame. Choose one:\n- Increase or decrease its damage by 1.\n- Spread it by 2 meters per round.'),
    ('MS031', E'A burst of flame sets all targets in the area on fire with a 100% chance.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS032', E'Fire attack with a 50% chance to set the target on fire.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS033', E'Throws 1 to 5 ice shards at one enemy.\nThe number of shards equals your (Spell Casting) roll minus the target''s Defense roll.\nEach shard is a separate attack. Each shard has a 25% chance to freeze the target.'),
    ('MS034', E'Controls the direction and speed of a current: halve the speed of swimmers, increase ships by 1.5×, or even slow/stop the current.\nThe GM sets the DC.'),
    ('MS035', E'Creates a whirlpool.\nEach round the target defends with (Swimming) vs your (Spell Casting) to avoid being pulled under and starting to Suffocate, taking 3 unblockable damage per round.'),
    ('MS036', E'Creates an area of thick fog.\nEveryone suffers -3 to (Awareness), and visibility radius is reduced to 4 meters.'),
    ('MS037', 'Summons heavy rain that extinguishes any open flame and removes all Burning effects.'),
    ('MS038', E'Covers the ground with ice.\nAnyone who steps on it falls prone after failing an (Athletics) check vs the caster''s (Spell Casting) check.'),
    ('MS039', E'Purifies water of poison and disease while leaving living creatures intact.\nIf the amount of purified water is smaller than a cube, it remains clean.'),
    ('MS040', E'Freezes a living target.\nAn inanimate target cannot be moved or manipulated.'),
    ('MS041', E'Extracts one secret from the target''s memory.\nOn a critical failure of the target''s defense, their INT is permanently reduced by 1.'),
    ('MS042', E'Creates a visual illusion.\n- Silent, odorless, intangible.\n- On a critical failure of the defense, any observer not only sees it but believes it is real.'),
    ('MS043', E'Teleports the mage (no passenger) any distance.\n- You can only bring items held or worn.\n- Familiar destination:\n* DC 15\n* On failure: you arrive at a random location within 1d10 km.\n- Unfamiliar destination:\n* Requires an item from that place\n* DC 20\n* On failure: you arrive at a random location within 3d10 km.'),
    ('MS044', E'Turns a metal object into a magnet.\nAny metal in the area is pulled to it and sticks, increasing its weight.\nTo pull an item away, roll Strength at DC 18.'),
    ('MS045', E'Creates a stone wall 2×3 meters with 30 SP.\n- Before damage reaches a target behind the wall, reduce it by the wall''s current SP; then apply remaining damage to the target''s armor normally.\n- Each successful penetration reduces the wall''s SP by 1.\n- When SP reaches 0, the wall is destroyed.'),
    ('MS046', E'Warps the ground.\n- Targets suffer -2 REF and -3 SPD.\n- 10% chance to collapse small structures.\n- Each turn, targets must make an (Athletics) check or fall into the ground; on failure they begin to Suffocate, taking 3 unblockable damage per round.\n- The ground remains warped.'),
    ('MS047', E'Fires a lightning bolt through multiple targets in a line with a 75% chance to inflict Burning.\nEach subsequent target takes 1d6 less damage.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS048', 'A wind barrier blocks ranged attacks, deflecting a projectile 8 meters in a random direction if the attack roll does not exceed your (Spell Casting) check.'),
    ('MS049', E'Suffocates the target, dealing 1d10 unblockable damage each round.\n- The target is Stunned (–2 to Attack and Defense).\n- If you take a hit or are distracted, you break the spell.'),
    ('MS050', E'Creates a fiery shield around the mage.\n- Blocks 2*(Spell Casting) water spells.\n- Destroys projectiles.\n- Impassable for living beings.'),
    ('MS051', E'Creates a controllable flaming tornado.\n- Moves up to (Spell Casting) meters per turn.\n- On contact, 50% chance to set the target on fire.\n- Cannot move beyond the spell''s range.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS052', E'Several fire snakes Grapple the target and set them on fire.\n- Each turn, the target may try to escape with a (Dodge/Escape) check vs your (Spell Casting) check.\n- Each turn, the DC of the escape check increases by 1 as the snakes tighten.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.)\nA Grappled target cannot move and suffers -2 to all physical actions.'),
    ('MS053', 'Partially draws liquid from the target, dealing equal lethal and nonlethal damage simultaneously.'),
    ('MS054', E'Creates an area of powerful hail.\nEach turn, targets take damage to a random body part if they fail their defense.'),
    ('MS055', 'Creates a wave of icy magic, freezing targets from all sides.'),
    ('MS056', E'The target follows the mage''s mental command.\n- The target gains +5 to (Resist Magic) if commanded to do something they would never do.\n- The target resists every 1d6 turns.'),
    ('MS057', E'Creates a portal.\n- Size: 1×2 meters\n- Range: unlimited\n- Any items can be carried through\n- If the portal shuts while something is passing through, it inflicts the critical wound "lost limb" or cuts an item in half\n- Familiar destination: opens easily\n- Unfamiliar destination:\n* Requires an item from that place\n* Requires a (Spell Casting) check at DC 20\n* On failure: the portal leads to a random location within 3d10 km'),
    ('MS058', E'Transforms the mage into a snake, cat, bird, or dog, using their stats while keeping inventory.\nTo revert, cast again; cannot revert while in contact with dimeritium.'),
    ('MS059', 'Transmutes one metal into another (except dimeritium), and a gemstone into a perfect gemstone.'),
    ('MS060', E'A wind barrier blocks ranged attacks, deflecting projectiles 8 meters in a random direction if the attack roll does not exceed your (Spell Casting) check.\n- On contact, deals 1d6 damage and pushes the target 6 meters.\n- On collision, the target takes ramming damage: 3d6 multiplied by the target''s weight modifier.\nThe mage can only walk calmly (no running).'),
    ('MS061', E'Each turn, the storm has a 35% chance to strike every target (except the mage) with lightning.\nAt the moment of impact, the target may attempt to dodge to avoid damage; on a hit there is a 75% chance to set the target on fire.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS062', E'A hail of fireballs.\n- Each turn, 75% chance to hit each target (except the mage) with a fireball.\n- If the target fails their Defense, they take damage and have a 75% chance to start Burning.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS063', E'Fires a beam of light unaffected by wind.\n- If blocked, the beam destroys the obstacle; but if the obstacle is a mirror, the beam ricochets in a random direction and the mirror takes damage.\n- Requires sunlight to cast; does not work in darkness.\n- Under moonlight or on a cloudy day, damage is halved.'),
    ('MS064', E'Parts water (up to 10×100×10 meters), pushing water and living creatures aside (including the mage if they are in that water).\nThe wall of water is freely permeable.'),
    ('MS065', E'Throws 0.5*(Spell Casting) two-meter ice spikes with 20 durability. You may target different creatures.\nIf a spike penetrates armor, it freezes the target, dealing 2 damage per turn until removed (Strength check DC 20), destroyed, or the spell ends.\nEach spike is a separate attack.'),
    ('MS094', E'Creates a magic circle around the caster that affects targets while they remain inside.\n- Anyone entering (except the caster) suffers -ceil(X/2) to SPD and REF, where X is the amount of STA invested (round fractions up).\n- Ethereal creatures become corporeal.'),
    ('MS095', E'Aard releases a wave of telekinetic force.\n- All affected targets are Stunned (–2 to Attack and Defense) until their next turn.\n- Chance to knock prone is X*10%, where X is the STA invested.\nA prone target suffers an additional –2 to Attack and Defense until they spend movement to stand up.'),
    ('MS096', E'Igni releases a wave of fire and sparks.\n- Damage is Xd6, where X is the STA invested.\n- 50% chance to set the target on fire.\n- Damage is to the torso; at point-blank you may choose a body part.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS097', E'Axii Dazes the target.\n- Penalty to the target''s Stability test is -ceil(X/2), where X is the STA invested (round fractions up).\n- Can be used like (Persuasion), rolling (Spell Casting) instead, opposed by (Resist Magic).\nThe mage''s head and hands glow visibly.'),
    ('MS098', E'Quen creates a magic shield with [5*X] HP, where X is the STA invested.\n- All damage is applied to Quen first.\n- Quen absorbs both lethal and nonlethal damage.\n- Works against spells that can be blocked.\n- Does not protect against status damage (poison, hypoxia, fire, etc.).\n- You cannot create a new Quen shield while the old one persists.'),
    ('MS099', E'Advanced Yrden creates a magic trap.\n- Each round the trap attacks the nearest target.\n- It can only attack an enemy target.\n- Takes 1 round to set up.\n- Lasts a number of rounds equal to the STA invested in the Sign.'),
    ('MS100', E'Advanced Aard releases a spherical telekinetic burst.\n- All targets within range are Stunned.\n- Chance to knock prone is X*10%, where X is the STA invested.\n- Flying creatures take falling damage equal to [H/2]d6, where H is fall height in meters.'),
    ('MS101', E'Advanced Igni produces a continuous stream of fire.\n- Damage is Xd6, where X is the STA invested.\n- Sustaining costs half the invested STA, rounded up.\n- 75% chance to set the target on fire.\n- On your turn, you may switch targets.\n- You can aim at a specific body part.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS102', E'Advanced Axii allows you to control the target''s mind, making them your ally.\n- Influence lasts X rounds, where X is the STA invested.\n- Each round the target makes a (Resist Magic) check to break free.'),
    ('MS103', E'Advanced Quen creates a glowing shield around the caster with [10*X] HP, where X is the STA invested.\n- Sustain cost equals cast cost.\n- Protects the caster and one adjacent ally pressed close.\n- Any objects passing through the shield are destroyed.\n- You cannot run; only walk.\n- If the shield is broken or ended:\n* Within 2 meters, everything (including allies) takes 1d6 damage to the torso.\n* If an object is lighter than 226 kg and not fixed in place, it is pushed 2 meters away.'),
    ('MS125', E'On an alchemy crafting failure, restores one of the substances.\n- Cannot be used twice for the same project.\n- Can be used together with the standard recovery step.'),
    ('MS126', E'Creates a small illusion on the target, making them unattractive.\n- The target suffers -3 to checks:\n* (Seduction)\n* (Charisma)\n* (Leadership)\n- The target does not suspect the blemish, but may learn from others or notice it with an (Awareness) check at DC 16 while looking at a reflection.'),
    ('MS127', E'Finds the nearest Ley Line by sending out a magical pulse.\nThe mage''s hand points toward the nearest Ley Line, and the mage senses which element it is tied to.'),
    ('MS128', E'Allows you to torture a target by conjuring a group of magical needles that obey your commands.\n- Can be used for interrogation; in that case you may use (Spell Casting) instead of (Intimidation).'),
    ('MS129', E'The target''s lips are sealed and their tongue is paralyzed.\n- A mage, priest, or druid cannot cast magic if their (Spell Casting) skill is below 7.\n- Each turn the target resists against a new (Spell Casting) roll.'),
    ('MS130', E'Creates an illusion that hides or changes objects.\n- The change is visual only.\n- The spell can be dispelled or may end if any object leaves the area.\n- A target can recognize the illusion and see through it by approaching within 4 meters and succeeding on a (Resist Magic) check.'),
    ('MS131', E'Reopens inactive portals:\n* A stationary permanent portal: (Spell Casting) check DC 16\n* Another caster''s portal that closed no more than 30 seconds ago: (Spell Casting) check DC 20'),
    ('MS132', E'Breaks down a corpse''s tissues while separating mutagenic compounds, which glow faintly in the body.\n- Allows you to extract a mutagen with an (Alchemy) or (Witcher Training) check at DC 14.'),
    ('MS133', E'Densifies a material, increasing the current and maximum SP of a piece of cover by 5.\nYou can densify a given section only once.'),
    ('MS134', E'Raises a cube of earth from an earthen surface, creating cover with 10 SP.\n- Before damage reaches a target behind it, reduce damage by the pillar''s current SP; then apply remaining damage to the target''s armor normally.\n- Each successful penetration reduces the pillar''s SP by 1.\n- When SP reaches 0, the pillar is destroyed.'),
    ('MS135', E'You immediately gain the following benefits:\n- Night vision: no -2 penalty to (Awareness) in dim light, and +2 to DCs in dim light.\n- Ability to track by smell.\n- Good hearing: +2 to (Awareness) rolls.\nHowever, bright light or loud noise will cause the Stunned condition.'),
    ('MS136', E'Turns ground into mud or quicksand.\n- -2 to (Dodge/Escape) and (Athletics) because movement becomes difficult.'),
    ('MS137', E'Conjures a stream of air that lets you throw a thrown weapon, arrow/bolt, or a bomb using (Spell Casting) instead of the usual skill.\nAn arrow/bolt deals an additional 4d6 damage.'),
    ('MS138', E'Creates a cloud of dust that reveals invisible creatures for 1 round.\nAdditionally, you may remove one target''s invisibility by coating them with dust if they fail their defense.'),
    ('MS139', 'Increases the mage''s Speed by 5, Run by 15, and Jump by 3.'),
    ('MS140', E'Amplifies smells in the area.\nIf a target fails an (Endurance) check vs your (Spell Casting) check:\n- They vomit for 1 minute.\n- They stink for a week, giving +2 to tracking them by smell (but the stench can be washed off by full immersion).\n- The target''s own sense of smell tracking is dulled.'),
    ('MS141', E'You breathe a jet of magical flame. The target takes damage and ignites with 100% chance.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS142', E'The chance to ignite becomes 100% when the target comes into contact with any open fire or anything that has any chance to ignite.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS143', E'Makes heat and fire in the area harmless.\n- The fire does not spread and does not cause damage.\n- Fire attacks still deal damage normally.'),
    ('MS144', E'Envelops the target''s head in smoke.\n- The target is Blinded and Suffocating, taking 3 unblockable damage per round.\n- Each turn (spending an action), the target may try to disperse it with a new Defense roll vs a new (Spell Casting) check.\nBlinded penalties:\n* -3 to Attack and Defense rolls\n* -5 to sight-based Awareness checks\n- The target must spend a turn to clear their vision.'),
    ('MS145', 'Allows you to breathe underwater.'),
    ('MS146', E'Increases swimming speed by 12 and removes penalties for attacking and defending underwater.\nStandard underwater penalties:\n- Melee attack speed is one strike per round.\n- -2 to Attack, Block, and Parry.\n- -3 to (Awareness).\n- Only (Athletics) can be used for defense and movement (instead of (Dodge/Escape)).\n- Bow and crossbow range is 25% of normal and damage is 50%.'),
    ('MS147', E'Creates a controllable geyser from a water source.\nDeals damage of a type you choose and knocks the target prone.\n- A prone target suffers -2 to Attack and Defense until they spend movement to stand.'),
    ('MS148', E'Creates a thin ice structure on a surface. It can be detected with an (Awareness) check at DC 16.\nIf two linked structures exist, disturbing one destroys both.'),
    ('MS149', E'Grants invisibility to the mage and everything they wear.\n- +10 to (Stealth)\n- +5 to (Attack)\n- +5 to (Defense)\n- The Attack and Defense bonuses become +3 if:\n* A target makes an (Awareness) check\n* A target casts Yrden\n* A target throws a "Moon Dust" bomb\n- The Stealth bonus becomes +5 if:\n* A target casts Yrden\n* A target throws a "Moon Dust" bomb\n- If you are hit by an attack, the spell ends.'),
    ('MS150', E'Temporarily disables a Focus effect in an item.\nFocus effects:\n- "Focusing (n)": when casting magic through this weapon, subtract n from the spell''s STA cost.\n- "Focusing (+)": +2 to the DC of checks against the owner''s spells.'),
    ('MS151', E'Seals the target inside a semi-transparent magical bubble.\n- The bubble has 40 HP.\n- You cannot target through the bubble in either direction.\n- Sound does not pass through.'),
    ('MS152', E'Your next spell after Empower gains one chosen benefit:\n- 100% chance for its effect to occur\n- +2 to (Spell Casting)\n- +2d6 additional damage\nOn a critical failure (rolling a 1 on the die), the mage suffers:\n* Any focusing item they carry explodes for 1d10 damage in a 2 m radius\n* An automatic 20 damage\n* One random effect:\n1) The mage ignites\n2) The mage is frozen\n3) The mage is pushed back 2 meters\n4) The mage is Dazed'),
    ('MS153', E'Prevents the target from:\n* becoming incorporeal\n* becoming invisible\n* teleporting\n* moving more than 10 meters away from the mage\n- Each turn, the target may attempt to break the tether by making a new (Resist Magic) check vs the caster''s new Attack roll, spending an action.'),
    ('MS154', E'Places a trap on an existing portal, redirecting its destination within 1.6 km of the true endpoint.\n- Can be noticed with (Magical Knowledge) at DC 16 or (Education) at DC 20.\n- Affects only one creature passing through the portal.\n- Traces of the trap can be detected even 30 days later.'),
    ('MS155', E'Hurls a large rock from the ground at a target, dealing 6d6 torso damage and knocking them prone if they fail their defense.\n- Shrapnel deals 4d6 torso damage to anyone within 6 m who fails an (Athletics) check at DC 16, also knocking them prone.\n- A prone target suffers -2 to Attack and Defense until they spend movement to stand.'),
    ('MS156', E'Uses magnetism to create a circular stone cover around the mage.\n- Protects against physical attacks.\n- The cover has 30 SP.\n- Reduces Speed to 2; the mage can only move, and only once per round.'),
    ('MS157', E'Summons a controlled insect swarm that attacks by swarming. Swarm stats:\n* HP 15\n* SPD 7\n* (Dodge/Escape) base 14\n* Damage: 1d6 torso, not blocked by armor\n* 100% chance to Poison on attack: the target takes 3 unblockable damage per round\nTo end the poison, the target must roll (Endurance) at DC 15, spending an action.'),
    ('MS158', E'Creates a controllable one-time lightning that deals torso damage and inflicts the critical effect Concussion for 10 minutes.\nIf the target successfully dodges, on your next turn you may spend an action to direct it at the target again.'),
    ('MS159', E'Creates an invisible blade of wind that deals 3d6 damage.\nAn (Awareness) check at DC 20 is required to understand the source of the attack.\nCast as a whisper.'),
    ('MS160', E'Charges a stationary metal object with electricity, dealing 1d6 damage.\nYou may empower it by sustaining the spell: +1d6 per turn up to 8d6.\nIf the object is moved, or after a day passes, the charge dissipates.\nDetected with an (Awareness) check at DC 20.'),
    ('MS161', E'Burns flammable structures.\nDeals 4d6 destructive damage to flammable material each round while active, without damaging anything else.'),
    ('MS162', E'Creates magical fire.\n- Can be used as a travel forge.\n- Can be used to purify metal.\n- If a crafting attempt fails, the metal is automatically recovered.\n- Cannot be used on dimeritium.'),
    ('MS163', E'Allows you to shape metal like clay with bare hands.\n- In combat, as an attack, deals 3d6 destructive damage to armor or weapons.\n- Not applicable to dimeritium.'),
    ('MS164', 'Once, copies the properties of one potion or elixir into one unit of Water Essence.'),
    ('MS165', E'Creates a howling snowy wind, creating snow and ice conditions.\nIn cold weather, it can last up to a week.'),
    ('MS166', E'Deals 2d6 destructive damage (choose) to either all armor pieces or all weapons.\nIf blocked with a shield, only the shield takes damage.\n- Each damaged armor piece gives -2 to REF, DEX, and SPD.\n- A damaged weapon gives -2 to attacks.\nRepaired with a (Crafting) check at DC 14, taking 1 hour per ten items.'),
    ('MS167', E'Enchants a reflective surface with the target''s reflection, trapping it.\n- Reduces two of the target''s attributes by 1d6 (and reduces linked derived stats).\n- While active, the target produces no other reflections.\n- Ends when the reflection is destroyed.\n- The target must be able to be reflected.'),
    ('MS168', E'Retargets another mage''s spell (not Master level).\n- The original target must be within that mage''s range.\n- Requires an opposed (Spell Casting) check.\n- If the spell uses an (Attack) check, use the (Spell Casting) value from the opposed check.\n- The spell is now sustained with your STA.'),
    ('MS169', E'Surrounds the target with crystals. Requires active sustaining for 2 additional turns to fully apply.\nIf the spell is interrupted, all effects are lost. Once applied, it is removed by Dispel Magic.\n- Turn 1: the target suffers -3 to Attack, Defense, and SPD.\n- Turn 2: the target cannot move.\n- Turn 3: the target falls unconscious for years without aging.'),
    ('MS170', E'Creates a structure over 10 minutes from available materials (including wood) within the area, of any simple shape.\nThe SP (5–30) of the resulting cover is set by the GM based on material and shape.'),
    ('MS171', E'Creates a storm.\n- Flying creatures take falling damage equal to [H/2]d6, where H is fall height in meters.\n- Flying creatures are knocked prone. A prone target suffers -2 to Attack and Defense until they stand.\n- Ranged attacks miss their intended target and hit wherever the GM decides.\n- Moving or running requires an (Athletics) check at DC 20.'),
    ('MS172', E'Choose one effect:\n- Toss up to 1000 kg up to 14 meters. A living target may make a (Dodge/Escape) check. The fall begins at the end of the target''s next turn. On impact, the object and whatever is beneath it take 7d6 bludgeoning damage to the torso, and the target is knocked prone.\n- Push targets in a cone who fail their defense back 14 meters. On collision they take ramming damage.\n- Manipulate an object up to 1000 kg as if with a hand (telekinesis).'),
    ('MS173', E'Creates an aura that drains 2d6 STA from all creatures:\n* at the moment of casting\n* at the start of a creature''s turn\n* when a creature enters on their turn\n- Targets cannot rest.\n- If a creature''s STA drops to 0, it falls unconscious until it recovers 20 STA and passes a Stability test.'),
    ('MS174', E'Summons an incorporeal, controllable Living Fire. Stats:\n* SPD 5\n* STA infinite\n* (Spell Casting) base 16\n* Knows spells: Aenye, Wave of Fire, Flaming Vortex\n* No extra actions\n* Can be extinguished like any normal fire\n* Due to incorporeality: immune to physical attacks, bleeding, and poison'),
    ('MS175', E'Drains moisture from the target, reducing their STA by 8d6.\nThe moisture can immediately be redirected into Rhewi, Ice Slick, or Water Jet with no STA cost.'),
    ('MS176', E'Summons a cube of water that spills across open ground in the same turn, and in enclosed spaces fills them and breaks unreinforced barriers.\n- The wave also deals torso damage and knocks everyone prone if they fail a Strength check at DC 24.'),
    ('MS210', E'Puts the target to sleep for 8 hours, leaving them Dazed.\n- If X is the STA invested, the target can be awakened by:\n* loud noise (if X = 2..3)\n* an attempt to wake them using an action (if X = 2..5)\n* an attempt to wake them using a full-round action (if X = 2..6)\n* damage (if X = 2..7)\n- The target does not realize they were affected by magic upon waking unless they have reason to suspect it.'),
    ('MS211', E'By drawing the Sign on a surface, you can hear what happens nearby from any distance without an (Awareness) check by "connecting" your mind to it.\n- Hearing radius is [2*X] meters, where X is the STA invested.\n- You can focus on one sound or conversation, filtering out all other noise.\n- When you draw a new Sign, you lose the connection to the old one.'),
    ('MS228', E'Temporarily blocks one emotion in the target (Hatred, Love, Depression, Happiness).\n- The target does not suspect magical influence during or after the effect.\n- If cast again on a target already affected, the STA cost increases by 2.'),
    ('MS229', E'Creates an explosion of concussive energy.\n- Targets take torso damage.\n- Targets are knocked prone.\n- Targets are pushed back 4 meters.\n- On collision, targets take ramming damage: 2d6 multiplied by the target''s weight modifier.\nWeight modifiers:\n0.5 — nekker, cat, etc.\n1 — human, etc.\n2 — werewolf, endriaga, etc.\n3 — fiend, troll, etc.'),
    ('MS230', E'Permanently alters one unit of an alchemy ingredient.\n- The mutated ingredient changes the alchemical substance contained within it to any other substance.\n- In a single alchemy formula, you can use only one unit of transmuted substance without ruining the mixture.'),
    ('MS231', E'Moves you up to 30 m on a powerful wind with a soft landing, taking no damage.\n- The gust at the moment of the jump:\n* pushes anyone 6 m\n* deals torso damage\n* deals additional ramming damage on collision: 3d6 multiplied by the target''s weight modifier\nWeight modifiers:\n0.5 — nekker, cat, etc.\n1 — human, etc.\n2 — werewolf, endriaga, etc.\n3 — fiend, troll, etc.'),
    ('MS232', 'Restores the muscle, flesh, skin, and hair of a targeted corpse in ghostly form. The restored corpse appears as a translucent version of the person at the moment of death with all wounds present. The form can be touched and examined as if real. You can summon body parts you have, even if disconnected, within 4m. - On failure, Restless Spirits invade.'),
    ('MS233', E'Drags restless souls into the world to sow chaos. Immediately upon casting, 1d6+4 wraiths are summoned, blinded by rage. They attack any target, including the caster and allies. - On failure, Restless Spirits invade.')
),
ins_i18n AS (
INSERT INTO i18n_text (id, entity, entity_field, lang, text)
SELECT * FROM (
-- names
SELECT ck_id('witcher_cc.magic.spell.name.'||rd.ms_id),
'magic',
           'spell_names',
           'ru',
           rd.name_ru
      FROM raw_data rd
     WHERE nullif(rd.name_ru,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.spell.name.'||rd.ms_id),
           'magic',
           'spell_names',
           'en',
           rd.name_en
      FROM raw_data rd
     WHERE nullif(rd.name_en,'') IS NOT NULL
    UNION ALL
    -- effects (HTML stripped at insert time)
    SELECT ck_id('witcher_cc.magic.spell.effect.'||rd.ms_id),
           'magic',
           'spell_effects',
           'ru',
           regexp_replace(replace(replace(rd.effect_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.effect_ru,'') IS NOT NULL
    UNION ALL
    -- effects EN (from manual translations)
    SELECT ck_id('witcher_cc.magic.spell.effect.'||see.ms_id),
           'magic',
           'spell_effects',
           'en',
           see.text_en
      FROM spell_effects_en see
  ) foo
  ON CONFLICT (id, lang) DO UPDATE
    SET text = EXCLUDED.text
)
INSERT INTO wcc_magic_spells (
  ms_id, dlc_dlc_id,
  level_id, element_id, form_id,
  name_id, effect_id,
  distance, zone_size,
  stamina_cast, stamina_keeping,
  damage,
  effect_time_value, effect_time_unit_id,
  defense_ids,
  type
)
SELECT rd.ms_id
     , rd.dlc_dlc_id
     , CASE WHEN nullif(rd.level_key,'') IS NOT NULL THEN ck_id(rd.level_key) ELSE NULL END AS level_id
     , CASE WHEN nullif(rd.element_key,'') IS NOT NULL THEN ck_id(rd.element_key) ELSE NULL END AS element_id
     , CASE WHEN nullif(rd.form_key,'') IS NOT NULL THEN ck_id(rd.form_key) ELSE NULL END AS form_id
     , ck_id('witcher_cc.magic.spell.name.'||rd.ms_id) AS name_id
     , ck_id('witcher_cc.magic.spell.effect.'||rd.ms_id) AS effect_id
     , nullif(rd.distance,'')
     , nullif(rd.zone_size,'')
     , nullif(rd.stamina_cast,'')
     , nullif(rd.stamina_keeping,'')
     , nullif(rd.damage,'')
     , CASE
         WHEN nullif(rd.effect_time_value,'') IS NULL THEN NULL
         WHEN rd.effect_time_unit_key LIKE 'time.unit.%' THEN nullif(rd.effect_time_value,'')
         WHEN nullif(rd.effect_time_unit_key,'') IS NOT NULL THEN (nullif(rd.effect_time_value,'') || ' ' || rd.effect_time_unit_key)
         ELSE nullif(rd.effect_time_value,'')
       END AS effect_time_value
     , CASE
         WHEN rd.effect_time_unit_key LIKE 'time.unit.%' THEN ck_id(rd.effect_time_unit_key)
         ELSE NULL
       END AS effect_time_unit_id
     , ARRAY_REMOVE(ARRAY[
         CASE btrim(rd.defense_1)
           WHEN 'Уклонение' THEN ck_id('skill.dodge')
           WHEN 'Уклонение/Изворотливость' THEN ck_id('skill.dodge_escape')
           WHEN 'Атлетика' THEN ck_id('skill.athletics')
           WHEN 'Блокирование' THEN ck_id('skill.blocking')
           WHEN 'Сопротивление магии' THEN ck_id('skill.resist_magic')
           WHEN 'Сопротивление убеждению' THEN ck_id('skill.resist_coercion')
           WHEN 'Сотворение заклинаний' THEN ck_id('skill.spell_casting')
           WHEN 'СЛ от ведущего' THEN ck_id('skill.gm_dc')
           ELSE NULL
         END,
         CASE btrim(rd.defense_2)
           WHEN 'Уклонение' THEN ck_id('skill.dodge')
           WHEN 'Уклонение/Изворотливость' THEN ck_id('skill.dodge_escape')
           WHEN 'Атлетика' THEN ck_id('skill.athletics')
           WHEN 'Блокирование' THEN ck_id('skill.blocking')
           WHEN 'Сопротивление магии' THEN ck_id('skill.resist_magic')
           WHEN 'Сопротивление убеждению' THEN ck_id('skill.resist_coercion')
           WHEN 'Сотворение заклинаний' THEN ck_id('skill.spell_casting')
           WHEN 'СЛ от ведущего' THEN ck_id('skill.gm_dc')
           ELSE NULL
         END,
         CASE btrim(rd.defense_3)
           WHEN 'Уклонение' THEN ck_id('skill.dodge')
           WHEN 'Уклонение/Изворотливость' THEN ck_id('skill.dodge_escape')
           WHEN 'Атлетика' THEN ck_id('skill.athletics')
           WHEN 'Блокирование' THEN ck_id('skill.blocking')
           WHEN 'Сопротивление магии' THEN ck_id('skill.resist_magic')
           WHEN 'Сопротивление убеждению' THEN ck_id('skill.resist_coercion')
           WHEN 'Сотворение заклинаний' THEN ck_id('skill.spell_casting')
           WHEN 'СЛ от ведущего' THEN ck_id('skill.gm_dc')
           ELSE NULL
         END
       ], NULL)::uuid[] AS defense_ids
     , CASE
         WHEN rd.ms_id IN ('MS094', 'MS095', 'MS096', 'MS097', 'MS098', 'MS099', 'MS100', 'MS101', 'MS102', 'MS103', 'MS210', 'MS211') THEN 'sign'
         ELSE 'spell'
       END AS type
  FROM raw_data rd
ON CONFLICT (ms_id) DO UPDATE
SET
  dlc_dlc_id = EXCLUDED.dlc_dlc_id,
  level_id = EXCLUDED.level_id,
  element_id = EXCLUDED.element_id,
  form_id = EXCLUDED.form_id,
  effect_time_unit_id = EXCLUDED.effect_time_unit_id,
  name_id = EXCLUDED.name_id,
  effect_id = EXCLUDED.effect_id,
  distance = EXCLUDED.distance,
  zone_size = EXCLUDED.zone_size,
  stamina_cast = EXCLUDED.stamina_cast,
  stamina_keeping = EXCLUDED.stamina_keeping,
  damage = EXCLUDED.damage,
  effect_time_value = EXCLUDED.effect_time_value,
  defense_ids = EXCLUDED.defense_ids,
  type = EXCLUDED.type;

-- <<< END sql/items/027_wcc_magic_spells.sql

-- >>> BEGIN sql/items/028_wcc_magic_hexes.sql

\echo '028_wcc_magic_hexes.sql'
-- Magic hexes from temp TSV

CREATE TABLE IF NOT EXISTS wcc_magic_hexes (
  ms_id              varchar(10) PRIMARY KEY,  -- e.g. 'MS119'
  dlc_dlc_id         varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id),

  level_id           uuid NULL,                -- ck_id('level.*')

  name_id            uuid NOT NULL,            -- ck_id('witcher_cc.magic.hex.name.'||ms_id)
  effect_id          uuid NOT NULL,            -- ck_id('witcher_cc.magic.hex.effect.'||ms_id)
  remove_instructions_id uuid NOT NULL,        -- ck_id('witcher_cc.magic.hex.remove_instructions.'||ms_id)

  remove_components  jsonb NULL,               
  stamina_cast       text NULL
);

WITH raw_data (
  ms_id, dlc_dlc_id,
  level_key,
  name_ru, name_en,
  effect_ru,
  remove_components_raw,
  remove_instructions_ru,
  stamina_cast
) AS ( VALUES
  ('MS119', 'core', 'level.novice', 'Теневая порча', 'The Hex of Shadows', 'Жертва слышит шёпот в тенях и видит призрачные силуэты. Она должна совершать случайные проверки <i>(Внимания)</i> с неопределённой <b>Сл</b>, замечая кого-то или что-то краем глаза. Эти проверки не несут угрозы, это лишь видения', 'I253 (1), I254 (1), I255 (1)', 'Жертва должна прийти на поляну, когда в небе полумесяц. Когда месяц в зените, нужно вылить чернила в воду, смокнуть раствором ветвь и, задержав дыхание, разбрызгать раствор вокруг.', '4'),
  ('MS120', 'core', 'level.novice', 'Вечный зуд', 'The Eternal Itch', 'На гениталиях жертвы высыпают воспалённые зудящие прыщи, чем причиняет жертве постоянный дискомфорт. Штраф -1 к любым броскам. Также штраф -5 к <i>(Соблазнению)</i> при раздевании.', 'I079 (1), I082 (1), I109 (1)', 'Связать травы в пучок, развести костёр, поджечь пучок и пеплом посыпать между ног, произнося магические слова.', '4'),
  ('MS121', 'core', 'level.journeyman', 'Дьявольская удача', 'The Devil''s Luck', 'В особо стрессовых ситуациях крит. провалом считаются броски d10 не только 1, но и 2. Примеры ситуаций: - В бою. - При необходимости выполнить что-то за установленный срок. - При проверке со <b>Сл</b> выше 15.', 'I256 (1), I100 (2), I257 (1)', 'Жертва должна вбить гвоздь в раму у себя дома, повесить на него пучок аконита, перевязанный волосами. Встать под этот аконит, пожечь его и поглубже вдохнуть дым.', '8'),
  ('MS122', 'core', 'level.journeyman', 'Кошмар', 'The Nightmare', 'Жертва видит повторяющийся кошмар. Каждую ночь она бросает <i>(Сопротивление убеждению)</i> со <b>Сл</b> равной начальному броску <i>(Наведения порчи)</i>. При успехе беспокойно спит, при провале не спит и не восстанавливает <b>Вын</b> или ПЗ. При трёх провалах подряд <b>Вын</b> теряет 50%, штраф -2 ко всем броскам до полного ночного сна', 'I274 (5), I014 (5), I035 (1)', 'Расставить свечи вокруг жертвы, соединив костями, а руду положить на голову. Так нужно успешно проспать одну ночь.', '8'),
  ('MS123', 'core', 'level.master', 'Поцелуй Песты', 'The Pesta''s Kiss', 'Жертва ослабевает, становясь уязвимой к болезням и тошноте. Заболевает при контакте с заражённым с вероятностью 75%. При малейшем тошнотворном запахе проходит проверку Стойкости <b>Сл:16</b>, при провале мучается тошнотой.', 'I041 (3), I002 (1), I009 (3), I089 (1)', 'Вылепить тотем из глины и пыли, покрыть смолой, использовать угли как глаза, бросив <i>(Искусство)</i> со <b>Сл:14</b>. Произнести магические слова, разбить тотем, измельчить угли и съесть.', '12'),
  ('MS124', 'core', 'level.master', 'Звериная порча', 'The Hex of the Beast', 'Жертва становится ненавистна животным. В радиусе 10м от животных:   * Штраф -3 к <i>(Выживанию в дикой при-роде)</i>   * Животные нападают с вероятностью 50%.', 'I258 (1), I090 (2), I099 (1), I059 (2), I098 (3)', 'Под полной луной жертва вспарывает глотку животному и пьёт его кровь. Тело обкладывают растениями, затем сжигают. Когда шкура начнёт гореть, бросить фосфор. После угасания огня, жертва носит кости животного целый день.', '12'),
  ('MS222', 'exp_toc', 'level.novice', 'Проклятие трезвости', 'Curse of Temperance', 'Проклятие сдержанности насыщает желудок алкоголем, усугубляя влияние спиртного. При потреблении любого алкоголя жертва немедленно страдает от: <b><i>Опьянения</i></b>: Штраф -2 к <b>Реа</b>, <b>Лвк</b> и <b>Инт.</b> и -3 в <i>(Словесной дуэли)</i>. Шанс 25% плохо помнить события. <b><i>Тошноты</i></b>: Каждые три хода при броске d10 не ниже <b>Тел</b> блюет и пропускает ход.', 'I259 (1), I271 (1)', 'Наполнить ведро алкоголем и окунуть голову жертвы, пока та не начнет <b><i>задыхаться</i></b>.', '4'),
  ('MS223', 'exp_toc', 'level.novice', 'Отвратительная порча', 'The Odious Hex', 'Делает жертву отталкивающей для представителей той же расы. То есть понижает социальный статус на один уровень, если она не была ненавидима.', 'I067 (1), I057 (1), I082 (1)', 'Жертва должна сделать свою фигурку из растений. Оскорблять чучело будто себя, пока не закончатся оскорбления. А потом жертва должна сжечь фигурку.', '4'),
  ('MS224', 'exp_toc', 'level.journeyman', 'Дурной сглаз', 'The Evil Eye', 'Плетёт паутину несчастий вокруг цели. - При каждом крит.провале d10 нужно бросить дважды и выбрать худший результат. - Кроме того, ГМу рекомендовано выбирать жертву как цель угрозы (атаки, ловушки, и т.д.), когда она должны была бы быть выбрана случайно.', 'I260 (1)', 'Нужно сделать из коралла подвеску, пробросил (Искусство) со Сл:14. Нужно носить её всё полнолуние. На рассвете подвеска расколется, сняв порчу.', '8'),
  ('MS225', 'exp_toc', 'level.journeyman', 'Бесконечная потребность', 'Unending Need', E'Заставляет жертву быть ленивой и обжорливой.\n - Нужны 10 часов сна каждую ночь, иначе штраф -3 ко всем броскам.\n - Требуется 5 приёмов пищи в день, иначе <b>Вын</b> уменьшается вдвое на следующий день.', 'T033 (1)', 'Жертва должна голодать 3 дня и ночи, пить только воду и спать со сладостями под подушкой. Если жертва справится и не притронется к сладостям, порча исчезнет утром четвёртого дня.', '8'),
  ('MS226', 'exp_toc', 'level.master', 'Стеклянные кости', 'Bones of Glass', 'Стеклянные кости делают кости жертвы полыми и склонными к расщеплению. Критические ранения заменяются на более серьёзные: треснутые ребра — на сломанные, перелом руки/ноги — на открытый перелом, небольшая травма головы — на проломленный череп. Штраф -3 на стабилизацию и лечение этих ран.', 'I283 (1), I092 (1), I261 (1), I080 (3), I272 (1)', 'Обескровить коня, собрать кровь в котел, добавить печень, мясо и листья, готовить 3 часа. Съесть всю похлёбку за 1 час и выпить бутылку спиртного.', '12'),
  ('MS227', 'exp_toc', 'level.master', 'Порча забвения', 'Hex of Forgetfulness', 'Порча забвения затрудняет сохранение знаний и воспоминаний. Субъект не может получать О.У. за обучение или изучать новую магию, как и сам обучать. Раз в день ГМ может заставить цель пробросить <i>(Сопротивления магии)</i> со <b>Сл:20</b>, а при провале забыть выбранное воспоминание, рецепт или магию до снятия порчи.', 'I088 (2), I041 (2), I085 (1)', 'Нужно обрить голову, нанести на неё замешанную пасту в виде знаков, а в рот взять Optima Mater. Молча ждать день и ночь высыхание глины. Удалить глину и вынуть Optima Mater, которая станет серой и теперь дает Фокусировку (2) для тёмных искусств.', '12')
),
hex_effects_en (ms_id, text_en) AS (
  VALUES
    ('MS119', E'The victim hears whispers in the shadows and sees ghostly silhouettes.\nThey must make random (Awareness) checks at an unspecified DC, noticing someone or something out of the corner of their eye. These checks are not dangerous—just visions.'),
    ('MS120', E'Inflamed, itchy pimples appear on the victim''s genitals, causing constant discomfort.\n-1 to all rolls. Additionally, -5 to (Seduction) when undressing.'),
    ('MS121', E'In highly stressful situations, a critical failure is considered to be a d10 roll of 1 or 2 (instead of only 1).\nExamples:\n- in combat\n- when you must do something under a time limit\n- when making a check with DC higher than 15'),
    ('MS122', E'The victim suffers a recurring nightmare.\nEach night they roll (Resist Coercion) vs a DC equal to the original (Hex Weaving) roll.\nOn success they sleep restlessly; on failure they do not sleep and recover no STA or HP.\nAfter three failures in a row, the victim loses 50% STA and takes -2 to all rolls until they get a full night''s sleep.'),
    ('MS123', E'The victim weakens, becoming vulnerable to disease and nausea.\nThey become ill on contact with infection with a 75% chance.\nAt any nauseating smell they must make an Endurance check at DC 16; on failure they are overcome with nausea.'),
    ('MS124', E'Animals come to hate the victim.\nWithin 10 meters of animals:\n* -3 to (Wilderness Survival)\n* Animals attack with a 50% chance.'),
    ('MS222', E'Fills the victim''s stomach with alcohol, worsening the effects of drinking.\nWhenever the victim consumes any alcohol, they immediately suffer:\nDrunk: -2 to REF, DEX, and INT, and -3 to (Verbal Combat). 25% chance to remember events poorly.\nNausea: every three turns, if a d10 roll is not lower than BODY, the victim vomits and loses their turn.'),
    ('MS223', E'Makes the victim repulsive to members of their own race.\nEffectively lowers their social status by one level (if they were not already hated).'),
    ('MS224', E'Weaves a web of misfortune around the victim.\n- On every critical failure, roll d10 twice and take the worse result.\n- Additionally, the GM is encouraged to choose the victim as the target of threats (attacks, traps, etc.) whenever the target would otherwise be chosen randomly.'),
    ('MS225', E'Makes the victim lazy and gluttonous.\n- They need 10 hours of sleep each night; otherwise they take -3 to all rolls.\n- They must eat 5 meals per day; otherwise their STA is halved the next day.'),
    ('MS226', E'Makes the victim''s bones hollow and prone to splintering.\nCritical wounds are replaced with more severe ones: cracked ribs become broken ribs, a broken arm/leg becomes an open fracture, a minor head injury becomes a crushed skull.\n-3 to stabilizing and treating these wounds.'),
    ('MS227', 'Makes it difficult to retain knowledge and memories.
The subject cannot gain IP from training or learn new magic, and cannot teach either.
Once per day the GM may force the target to roll (Resist Magic) at DC 20; on a failure they forget a chosen memory, recipe, or spell until the hex is removed.')
),
hex_remove_en (ms_id, text_en) AS (
  VALUES
    ('MS119', E'The victim must come to a clearing when the moon is a half-moon.\nWhen the moon is at its zenith, pour ink into water, soak a branch in the mixture, then—holding your breath—spray the mixture around you.'),
    ('MS120', 'Tie the herbs into a bundle, build a fire, burn the bundle, and sprinkle the ash between the legs while speaking magical words.'),
    ('MS121', 'The victim must hammer a nail into the window frame at home, hang a bundle of aconite tied with a virgin''s hair from it, stand beneath it, burn it, and inhale the smoke deeply.'),
    ('MS122', 'Place candles around the victim, connecting them with animal bones, and place the glowing ore on their head. The victim must successfully sleep through one night like this.'),
    ('MS123', E'Sculpt a totem from clay and powder, coat it with resin, use charcoal as eyes, and make an (Art) check at DC 14.\nSpeak magical words, smash the totem, grind the charcoal, and eat it.'),
    ('MS124', E'Under a full moon the victim slits a living animal''s throat and drinks its blood.\nCover the body with the plants, then burn it. When the hide starts to burn, throw in the phosphorus.\nAfter the fire dies, the victim must wear the animal''s bones for a whole day.'),
    ('MS222', 'Fill a bucket with alcohol and dunk the victim''s head until they begin to Suffocate.'),
    ('MS223', E'The victim must make a small figure of themselves from plants.\nThey must insult the effigy as if insulting themselves until they run out of insults, then burn the figure.'),
    ('MS224', E'Make a pendant from coral with an (Art) check at DC 14.\nThe victim must wear it for the entire full moon. At dawn the pendant cracks, removing the hex.'),
    ('MS225', E'The victim must fast for 3 days and nights, drink only water, and sleep with sweets under their pillow.\nIf they endure and do not touch the sweets, the hex ends on the morning of the fourth day.'),
    ('MS226', E'Bleed a warhorse dry, collect the blood in a cauldron, add the liver, meat, and leaves, and cook for 3 hours.\nEat all the stew within 1 hour and drink a bottle of alcohol.'),
    ('MS227', E'Shave the victim''s head, apply a mixed paste in the shape of signs, and place Optima Mater in their mouth.\nSilently wait day and night for the clay to dry.\nRemove the clay and take out the Optima Mater; it turns grey and now provides Focusing (2) for dark arts.')
),
ins_i18n AS (
INSERT INTO i18n_text (id, entity, entity_field, lang, text)
SELECT * FROM (
SELECT ck_id('witcher_cc.magic.hex.name.'||rd.ms_id),
'magic',
           'hex_names',
           'ru',
           rd.name_ru
      FROM raw_data rd
     WHERE nullif(rd.name_ru,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.hex.name.'||rd.ms_id),
           'magic',
           'hex_names',
           'en',
           rd.name_en
      FROM raw_data rd
     WHERE nullif(rd.name_en,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.hex.effect.'||rd.ms_id),
           'magic',
           'hex_effects',
           'ru',
           regexp_replace(replace(replace(rd.effect_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.effect_ru,'') IS NOT NULL
    UNION ALL
    -- effects EN (from manual translations)
    SELECT ck_id('witcher_cc.magic.hex.effect.'||hee.ms_id),
           'magic',
           'hex_effects',
           'en',
           hee.text_en
      FROM hex_effects_en hee
    UNION ALL
    SELECT ck_id('witcher_cc.magic.hex.remove_instructions.'||rd.ms_id),
           'magic',
           'hex_remove_instructions',
           'ru',
           regexp_replace(replace(replace(rd.remove_instructions_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.remove_instructions_ru,'') IS NOT NULL
    UNION ALL
    -- remove instructions EN (from manual translations)
    SELECT ck_id('witcher_cc.magic.hex.remove_instructions.'||hre.ms_id),
           'magic',
           'hex_remove_instructions',
           'en',
           hre.text_en
      FROM hex_remove_en hre
  ) foo
  ON CONFLICT (id, lang) DO UPDATE
    SET text = EXCLUDED.text
)
INSERT INTO wcc_magic_hexes (
  ms_id, dlc_dlc_id,
  level_id,
  name_id, effect_id, remove_instructions_id,
  remove_components,
  stamina_cast
)
SELECT rd.ms_id
     , rd.dlc_dlc_id
     , CASE WHEN nullif(rd.level_key,'') IS NOT NULL THEN ck_id(rd.level_key) ELSE NULL END AS level_id
     , ck_id('witcher_cc.magic.hex.name.'||rd.ms_id) AS name_id
     , ck_id('witcher_cc.magic.hex.effect.'||rd.ms_id) AS effect_id
     , ck_id('witcher_cc.magic.hex.remove_instructions.'||rd.ms_id) AS remove_instructions_id
     , CASE
         WHEN rd.remove_components_raw IS NULL OR trim(rd.remove_components_raw) = '' THEN NULL
         ELSE (
           SELECT
             CASE
               WHEN jsonb_agg(comp.obj ORDER BY comp.pos) IS NULL THEN NULL
               ELSE jsonb_agg(comp.obj ORDER BY comp.pos)
             END
           FROM (
             SELECT
               pieces.pos,
               jsonb_build_object(
                 'id',
                 (
                   CASE
                     WHEN pieces.code ~ '^I[0-9]{3}$' THEN ck_id('witcher_cc.items.ingredient.name.'||pieces.code)
                     WHEN pieces.code ~ '^T[0-9]{3}$' THEN ck_id('witcher_cc.items.general_gear.name.'||pieces.code)
                     ELSE NULL
                   END
                 )::text,
                 'qty',
                 pieces.qty
               ) AS obj
             FROM (
               SELECT
                 part.ord * 10 AS pos,
                 CASE
                   WHEN (regexp_match(trim(part.part_raw), '\((\d+)\)\s*$')) IS NOT NULL 
                   THEN (regexp_match(trim(part.part_raw), '\((\d+)\)\s*$'))[1]::int
                   ELSE NULL
                 END AS qty,
                 trim(regexp_replace(trim(part.part_raw), '\s*\([^)]*\)\s*$', '')) AS code
               FROM (
                 SELECT token AS part_raw, ord
                 FROM regexp_split_to_table(rd.remove_components_raw, '\s*,\s*') WITH ORDINALITY AS s(token, ord)
               ) part
             ) pieces
             WHERE pieces.code IS NOT NULL AND pieces.code <> '' AND pieces.code ~ '^[IT][0-9]{3}$'
           ) comp
           WHERE (comp.obj->>'id') IS NOT NULL
         )
       END AS remove_components
     , nullif(rd.stamina_cast,'')
  FROM raw_data rd
ON CONFLICT (ms_id) DO UPDATE
SET
  dlc_dlc_id = EXCLUDED.dlc_dlc_id,
  level_id = EXCLUDED.level_id,
  name_id = EXCLUDED.name_id,
  effect_id = EXCLUDED.effect_id,
  remove_instructions_id = EXCLUDED.remove_instructions_id,
  remove_components = EXCLUDED.remove_components,
  stamina_cast = EXCLUDED.stamina_cast;

-- <<< END sql/items/028_wcc_magic_hexes.sql

-- >>> BEGIN sql/items/029_wcc_magic_invocations.sql

\echo '029_wcc_magic_invocations.sql'
-- Magic invocations (druid & priest) from temp TSV

CREATE TABLE IF NOT EXISTS wcc_magic_invocations (
  ms_id               varchar(10) PRIMARY KEY,  -- e.g. 'MS066'
  dlc_dlc_id          varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id),

  magic_type_id       uuid NOT NULL,            -- ck_id('magic.gruid_invocations' | 'magic.priest_invocations')
  level_id            uuid NULL,                -- ck_id('level.*')
  form_id             uuid NULL,                -- ck_id('magic.form.*')
  effect_time_unit_id uuid NULL,                -- ck_id('time.unit.*')

  cult_or_circle_id   uuid NULL,                -- ck_id('witcher_cc.magic.invocation.cult_or_circle.'||ms_id)
  name_id             uuid NOT NULL,            -- ck_id('witcher_cc.magic.invocation.name.'||ms_id)
  effect_id           uuid NOT NULL,            -- ck_id('witcher_cc.magic.invocation.effect.'||ms_id)

  distance            text NULL,
  zone_size           text NULL,
  stamina_cast        text NULL,
  stamina_keeping     text NULL,
  damage              text NULL,
  effect_time_value   text NULL,

  defense_ids         uuid[] NULL
);

WITH raw_data (
  ms_id, dlc_dlc_id,
  magic_type_key, level_key,
  cult_ru, cult_en,
  name_ru, name_en,
  effect_ru,
  form_key,
  distance, zone_size,
  stamina_cast, stamina_keeping,
  damage,
  effect_time_value, effect_time_unit_key,
  defense_1, defense_2
) AS ( VALUES
  ('MS066', 'core', 'magic.gruid_invocations', 'level.novice', '', '', 'Кипящая кровь', 'Boiling Blood', 'Накладывается на животное или неразумное чудовище, вызывая в нем злобу по отношению к назначенной цели, на которую тот будет пытаться напасть.', 'magic.form.direct', '8', '', '3', '', '', '1d10', 'time.unit.round', 'Воля*3', ''),
  ('MS067', 'core', 'magic.gruid_invocations', 'level.novice', '', '', 'Проклятая болезнь', 'Cursed Illness', 'Вызывает у цели болезнь. В зависимости от вложенной <b>ВЫН</b>, цель получает: * 2: цель кашляет, получая <b><i>ошеломле-ние</i></b>, т.е. штраф -2 к <i>(Атаке)</i> и <i>(Защите)</i>, до следующего своего хода.  * 4: цель <b><i>дезориентирована</i></b> из-за сильной тошноты. Т.е. она не может совершать действий, а попасть по ней можно со <b>Сл:10</b>. Эффект спадет, если по цели попадут.  * 6: цель как бы <b><i>отравлена</i></b> (получает по 3 урона) из-за серьезной болезни.  - Снять эффекты болезни можно пробросив <i>(Стойкость)</i> против <i>(Сотворения инвокации)</i>.', 'magic.form.direct', '8', '', '2-6', '', '', '', '', 'Сопротивление магии', ''),
  ('MS068', 'core', 'magic.gruid_invocations', 'level.novice', '', '', 'Друг животных', 'Friend to Wild Kind', 'Успокаивает одно животное. - Можно наложить на себя, тогда друид получает бонус +3 к <i>(Выживанию в дикой природе)</i> при общении с животными.', 'magic.form.direct', '5', '', '1', '', '', '1d6', 'time.unit.hour', 'Воля*3', ''),
  ('MS069', 'core', 'magic.gruid_invocations', 'level.novice', '', '', 'Дар природы', 'Nature''s Gift', 'Выращивает съедобные растения растений на любой почве. - Растений достаточно, чтобы насытить на 1 день количество персон, равное числу затраченных очков <b>ВЫН</b>.', 'magic.form.direct', '2', '', 'x', '', '', '', '', '', ''),
  ('MS070', 'core', 'magic.gruid_invocations', 'level.novice', '', '', 'Взор природы', 'Nature''s Sight', 'Позволяет видеть существ, противоестественных для мира Неверленда. - Заклинатель может разглядеть чудовищ даже сквозь препятствия.  - Увиденные таким образом чудовища кажутся светящимися.', 'magic.form.zone_centered', '', '50', '2', '1', '', '', '', '', ''),
  ('MS071', 'core', 'magic.gruid_invocations', 'level.novice', '', '', 'Символ скрытого', 'Sigil of the Hidden', 'Укрывает растительностью и природным декором указанную область, скрывая содержимое невидимостью. - Даёт бонус +5 к <i>(Скрытности)</i>, но не позволяет никому двинуться. - Снять маскировку можно:  * Повторив инвокацию   * Нанести веткам 10 ПЗ урона', 'magic.form.zone_circle', '', '3', '2', '', '', '', '', '', ''),
  ('MS072', 'core', 'magic.gruid_invocations', 'level.journeyman', '', '', 'Благословение исцеления', 'Blessing of Healing', 'Эффект на выбор: - Восстанавливает 3 ПЗ за ход. - Лечит крит.ранения, для чего нужно применить спелл [уровень раны]*2+2 раз со <b>Сл:</b>[уровень раны]*2+12, а потом отдых для избавления от штрафов раны (не меньше одного дня): 1) Легкая: 8 - <b>ТЕЛ</b> дней 2) Средняя: 12 - <b>ТЕЛ</b> дней 3) Тяжёлая: 15 - <b>ТЕЛ</b> дней 4) Смертельная: штраф навсегда', 'magic.form.direct', '2', '', '5', '3', '', '', '', '', ''),
  ('MS073', 'core', 'magic.gruid_invocations', 'level.journeyman', '', '', 'Животная сила', 'Primal Reservoir', 'Пробуждает внутренние резервы цели - Даёт бонус +2 к Урону в ближ-нем бою - Дает штраф -2 к <b>ИНТ</b> на время действия заклинания.', 'magic.form.direct', '5', '', '6', '', '', '2d6', 'time.unit.round', 'Сопротивление магии', ''),
  ('MS074', 'core', 'magic.gruid_invocations', 'level.journeyman', '', '', 'Нити жизни', 'Threads of Life', 'Позволяет увидеть нити жизни, связующие всё живое. - Можно видеть ПЗ, оставшиеся у видимых целей. - Можно видеть и крит. ранения.', 'magic.form.zone_centered', '', '10', '4', '2', '', '', '', '', ''),
  ('MS075', 'core', 'magic.gruid_invocations', 'level.master', '', '', 'Управление природой', 'Shape Nature', 'Позволяет превратить небольшое дерево в голема. - Голем служит друиду во время действия заклинания, а потом превращается обратно в дерево. - С убитого голема можно полу-чить только 2dl0 древесины. - По остальным параметрам деревянный голем аналогичен нормальному.', 'magic.form.direct', '10', '', '12', '', '', '1d10', 'time.unit.round', '', ''),
  ('MS076', 'core', 'magic.gruid_invocations', 'level.master', '', '', 'Песнь небес', 'Song of the Sky', 'Песнь небес меняет погоду вокруг заклинателя. Варианты погоды:   * Ясная: нет модификаторов  * Облачная: мало солнечного света, т.е.    - <b>Сл</b> для навыков возрастает на +2    - Штраф -3 к <i>(Вниманию)</i>.  * Ливень: гасит огонь  * Штормовой ветер: штраф -2 к <b>ЛВК</b> для дистанционных атак.  * Гроза: Каждый ход гроза с шансом 35% бьет молнией по каждой цели (кроме мага). Цель может спастись уворотом и не получить урон 8d6 с 75% шансом <b><i>загореться</i></b>, т.е. получать по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.zone_centered', '', '50', '10', '5', '', '', '', '', ''),
  ('MS077', 'core', 'magic.priest_invocations', 'level.novice', '', '', 'Благословение удачи', 'Blessing of Good Fortune', 'Даёт цели очки <b>Удачи</b>. - Количество очков равно половине очков, которые вы набрали свыше <b>Сл:12</b> при броске <i>(Сотворения инвокаций)</i>. - Максимум можно дать 5 очков <b>Удачи</b>.', 'magic.form.direct', '10', '', '1', '', '', '', '', 'СЛ от ведущего', ''),
  ('MS078', 'core', 'magic.priest_invocations', 'level.novice', '', '', 'Благословение любви', 'Blessing of Love', 'Даёт цели бонус +3 к <i>Харизме</i> и <i>Соблазнению</i>.', 'magic.form.direct', '5', '', '2', '', '', '1d10', 'time.unit.round', '', ''),
  ('MS079', 'core', 'magic.priest_invocations', 'level.novice', '', '', 'Священный свет', 'Holy Light', 'От рук жреца исходит свет, поднимая освещенность вокруг на 1 уровень. Эффекты освещенности: - Штраф к <b>Сл</b> применения навыков:   * Темнота: +5   * Слабый свет: +2   * Дневной свет: нет   * Яркий свет: +2 - Штраф к <i>(Вниманию)</i>:   * Темнота: -4   * Слабый свет: -2   * Дневной свет: нет   * Яркий свет: -3 - Штраф к <i>(Атаке)</i> и <i>(Защите)</i>:   * Темнота: -2   * Яркий свет: -2, если смотреть против источника света', 'magic.form.zone_centered', '', '5', '1', '', '', '3d10', 'time.unit.round', '', ''),
  ('MS080', 'core', 'magic.priest_invocations', 'level.novice', '', '', 'Хранилище знаний', 'Vaults of Knowledge', 'Хранилище знаний позволяет заклинателю погрузиться в чертоги собственного разума, чтобы заново пережить любое своё воспоминание или вспомнить знание, когда-либо полученное.', 'magic.form.self', '', '', '3', '', '', '', '', '', ''),
  ('MS081', 'core', 'magic.priest_invocations', 'level.novice', '', '', 'Воды очищения', 'Waters of Clearance', 'Снимает эффект <b><i>опьянения</i></b>.  <b><i>Пьяная</i></b> цель имеет * штраф -2 к <b>РЕА</b>, <b>ЛВК</b>, <b>ИНТ</b> * штраф -3 к <i>(Словесной дуэли)</i> * шанс 25% забыть что делал, пока был пьяным.', 'magic.form.direct', '5', '', '1', '', '', '', '', 'Сопротивление магии', ''),
  ('MS082', 'core', 'magic.priest_invocations', 'level.novice', '', '', 'Паутина лжи', 'Web of Lies', 'Наводит беспорядок в голове цели, заставляя её сомневаться в любой информации и даже в собственных воспоминаниях. - Цель <b><i>дезориентирована</i></b>. То есть она не может совершать действий, а попасть по ней можно со <b>Сл:10</b>. Эффект спадет, если по цели попадут. - Чтобы снять эффект нужно в свой ход бросить 1d10 ниже <b>ИНТ</b> цели.', 'magic.form.direct', '8', '', '3', '', '', '', '', 'Сопротивление магии', ''),
  ('MS083', 'core', 'magic.priest_invocations', 'level.journeyman', '', '', 'Очищающее пламя', 'Cleansing Fire', 'Воспламеняет цель - Наносит разовый урон - Шанс 100% <b><i>поджечь</i></b> цель', 'magic.form.direct', '10', '', '6', '', '3d6', '', '', 'Сопротивление магии', ''),
  ('MS084', 'core', 'magic.priest_invocations', 'level.journeyman', '', '', 'Святая защита', 'Holy Fortification', 'Укрепляет волю цели, позволяя ей совершить новую проверку против эффектов любого действующего на неё заклинания.', 'magic.form.direct', '10', '', '5', '', '', '', '', '', ''),
  ('MS085', 'core', 'magic.priest_invocations', 'level.journeyman', '', '', 'Свет истины', 'Light of Truth', 'Создаёт яркий белый огонёк, заставляющий одну цель говорить правду. - Каждый раунд цель проходит новую проверку <i>(Защиты)</i>. - При провале цель должна отвечать правду на любой заданный вопрос.', 'magic.form.direct', '5', '', '4', '2', '', '', '', 'Сопротивление магии', ''),
  ('MS086', 'core', 'magic.priest_invocations', 'level.master', '', '', 'Божественный портал', 'Divine Portal', '<align="left">Создает портал на 1 раунд - Размер: 1x2 метра - Дальность: неограниченная - Можно пронести любые вещи - Отключенный во время прохождения портал наносит крит. рану "потеря конечности" или разрубит вещь надвое. - Цель - только знакомое место.</align>', 'magic.form.direct', '-1', '', '12', '', '', '1', 'time.unit.round', '', ''),
  ('MS087', 'core', 'magic.priest_invocations', 'level.master', '', '', 'Божественная мудрость', 'Divine Wisdom', 'Позволяет получить ответ на один вопрос. Это не может быть предсказание будущего. - <b>Сл</b> проверки определяет ведущий в зависимости от секретности информации.', 'magic.form.direct', '50', '', '10', '5', '', '', '', 'СЛ от ведущего', ''),
  ('MS088', 'core', 'magic.priest_invocations', 'level.arch_priest', 'Корам Агх Тэра', 'Coram Agh Tera', 'Благословение смерти', 'Blessing of Death', E'Разрезает связывающие цель с этим миром узы жизни. - Цель оказывается в состоянии <b><i>при смерти</i></b>, будто получила урон.\n - Цель могут спасти союзники проверкой <i>(Первой помощи)</i> или <i>(Лечащим прикосновением)</i> со Сл:16, вернув ПЗ в изначальное состояние.  <b><i>При смерти</i></b> все параметры снижаются до 1/3 от нормы. Каждый раунд цель должна бросать 1d10 не выше её базовой <b>УСТ</b>. При провале цель безвозвратно умирает.', 'magic.form.direct', '10', '', '16', '', '', '', '', 'Сопротивление магии', ''),
  ('MS089', 'core', 'magic.priest_invocations', 'level.arch_priest', 'Вечный Огонь', 'The Eternal Fire', 'Вечный суд', 'Eternal Judgement', 'Заставляет цель <b><i>загореться</i></b> яр-ким белым пламенем с красными проблесками. - Наносит двойной урон от <b><i>горения</i></b>. - Может быть потушено лишь магическим образом либо полным погружением под воду на 3 раунда. - Всё, что коснётся этого пламени, получает обычное <b><i>горение</i></b>.  <b><i>Горящая</i></b> цель получает по 5 урона в каждую часть тела. Броня поглощает урон, но теряет 1 ПБ, как и оружие. Нужно потратить ход чтобы сбить пламя.', 'magic.form.direct', '10', '', '16', '', '', '', '', 'Сопротивление магии', ''),
  ('MS090', 'core', 'magic.priest_invocations', 'level.arch_priest', 'Фрейя', 'Freya', 'Храбрость Фрейи', 'Freya''s Bravery', 'Призывает дух Фреи в тело жреца, создавая вокруг него свечение. - Цели становятся невосприим-чивы к <b><i>ужасу</i></b>. - Цели получают доп. 25 ПЗ. - Покинув зону инвокации, эффект длится ещё ld6 раундов пока цель не вернется в зону. - Не обязательно верить во Фрейю. - Эффект снимается с целей по воле жреца.', 'magic.form.zone_centered', '', '20', '16', '', '', '20', 'time.unit.round', '', ''),
  ('MS091', 'core', 'magic.priest_invocations', 'level.arch_priest', 'Мелитэле', 'Melitele', 'Целительный покой', 'Healing Rest', 'Погружает цели в глубокую кому, во время которой раны целей заживают. - Количество целей равно значениею навыка <i>(Сотворение заклинаний). </i> - Цели не реагирую ни на что. - После комы цели очнутся с пол-ным запасом ПЗ. - Снимаются все остаточные временные штрафы от вылеченных еще до инвокации критических ранений.', 'magic.form.zone_circle', '', '5', '16', '', '', '24', 'time.unit.hour', '', ''),
  ('MS092', 'core', 'magic.priest_invocations', 'level.arch_priest', 'Крева', 'Kreve', 'Божественная удача', 'Luck of the Father', 'Позволяет потратить очки <b>Удачи</b> на благословение Кревы.  - На время инвокации потраченные в начале очки <b>Удачи</b> действуют на любой бросок жреца. - По желанию жреца эффект действует как штраф или бонус на любой бросок в области доступа. - Максимум вложенной удачи ограничен тройным значением <i>(Сотворения заклинаний)</i> жреца', 'magic.form.zone_centered', '', '10', '16', '', '', '1', 'time.unit.hour', '', ''),
  ('MS093', 'core', 'magic.priest_invocations', 'level.arch_priest', 'Великое Солнце', 'The Great Sun', 'Белое пламя', 'White Flame', 'Вокруг жреца появляется аура Белого пламени. - Освещенность становится "Яркий свет", т.е. все получают:  * Штраф +2 к <b>Сл</b> при проверке навыков  * Штраф -3 к <i>(Вниманию)</i>  * Штраф -2 к <i>(Атаке)</i> и <i>(Защите)</i>, если смотреть в сторону жреца. - Растапливается любой лёд - Рассеиваются любые спеллы воды - Новые заклинания воды можно соз-дать только при успешной встречной проверке <i>(Сотворения заклинаний)</i>. - Уязвимые к Солнцу существа полу-чают двойные эффекты уязвимости.', 'magic.form.zone_centered', '', '10', '16', '', '', '1', 'time.unit.hour', 'Сопротивление магии', ''),
  ('MS177', 'exp_toc', 'magic.priest_invocations', 'level.novice', '', '', 'Благословенное оружие', 'Blessed Weapon', 'Создает светящуюся руну на оружии ближнего боя, облегчая и уравновешивая его. - Оружие получает эффект <b>Сбалансированного</b> на время действия.', 'magic.form.direct', '2', '', '2', '', '', '30', 'time.unit.minute', '', ''),
  ('MS178', 'exp_toc', 'magic.priest_invocations', 'level.novice', '', '', 'Божественное вдохновение', 'Divine Inspiration', 'Благословляет цель проницательностью. - Давая бонус +2 к одному навыку. - Цель должна иметь хотя бы 1 уровень в этом навыке. - Можно использовать раз в день.', 'magic.form.direct', '8', '', '2', '', '', '10', 'time.unit.minute', '', ''),
  ('MS179', 'exp_toc', 'magic.priest_invocations', 'level.novice', '', '', 'Двойственная тьма', 'Duplicitous Darkness', 'Окутывает разум цели ложными мыслями, скрывающими истину. - Цель получает +2 к проверкам <i>(Обмана)</i> - Цель нельзя заставить сказать правду магией. - Нельзя шпионить за целью телепатией. - Попытка исследовать цель магией не обнаруживает заклинание. Только при успешной проверке <i>(Внимания)</i> со <b>Сл:20</b>.', 'magic.form.direct', '2', '', '2', '', '', '1', 'time.unit.hour', '', ''),
  ('MS180', 'exp_toc', 'magic.priest_invocations', 'level.novice', '', '', 'Свет покаяния', 'Light of Penance', 'Призывает силу божества, истощая волю цели к сопротивлению. - Цель теряет 2d6 <b>ВЫН</b>. - Если порог энергии цели 1 или выше, она теряет еще 2d6 <b>ВЫН</b>.', 'magic.form.direct', '6', '', '3', '', '2d6', '', '', 'Сопротивление магии', ''),
  ('MS181', 'exp_toc', 'magic.priest_invocations', 'level.novice', '', '', 'Божественное присутствие', 'Presence of the Divine', 'Призывает аспект божества, делая осанку жреца внушительной. - Ваш голос слышен издалека - Бонус +4 к <i>(Запугиванию)</i>. - В качестве альтернативы мож-но сделать до 6 целей в пределах 10м невосприим-чивыми к страху.', 'magic.form.self', '', '', '3', '', '', '10', 'time.unit.minute', '', ''),
  ('MS182', 'exp_toc', 'magic.priest_invocations', 'level.journeyman', '', '', 'Благословение богатства', 'Blessing of Abundance', 'Наделяет божественным провидением. - При первом лутании чего бы то ни было, вы или ваш игровой мастер бросаете дважды и берёте большее значение. - Это касается каждого найден-ного предмета в том же источнике. Например, при лутании монстра бросаешь дважды на каждый возможный вид лута с него.', 'magic.form.self', '', '', '6', '', '', '1', 'time.unit.day', '', ''),
  ('MS183', 'exp_toc', 'magic.priest_invocations', 'level.journeyman', '', '', 'Клеймо увядания', 'Brand of Withering', 'Помечает цель символом разложения, лишая её способности к исцелению. - Цель не может восстан-авливать ПЗ от любых эффектов, включая естест-венное исцеление.', 'magic.form.direct', '8', '', '6', '', '', '7', 'time.unit.day', 'Сопротивление магии', ''),
  ('MS184', 'exp_toc', 'magic.priest_invocations', 'level.journeyman', '', '', 'Поиск ищущих', 'Seek the Seekers', 'Поиск ищущих реагирует на попытки гадать о вас или ком-либо в пределах 10м от вас. - Срабатывает на Гидромантию, Пиромантию и т.д. - Вы не только поймете, что стали целью гадания, но и увидете лицо прорицателя. - Чтобы понять, что пойман прорицатель должен пробросить <i>(Образование)</i> или <i>(Магические познания)</i> со <b>Сл:20</b>. - Вам сообщат, если прорицатель понял, что был пойман.', 'magic.form.self', '', '', '6', '', '', '1', 'time.unit.day', '', ''),
  ('MS185', 'exp_toc', 'magic.priest_invocations', 'level.master', '', '', 'Божественное перо', 'Quill of the Divine', 'Проникает в разум цели, изменяя её воспоминания. Эффект зависит от вложенной ВЫН:  *14: вызывает ретроградную амнезию у цели, блокируя воспоминания  *16: можно внедрить созданные воспоминания. Цель получает бонус +5 к <i>(Защите)</i>, если прежде не подвергалась блокировке воспоминаний.', 'magic.form.direct', '2', '', '14-16', '', '', '', '', 'Сопротивление магии', ''),
  ('MS186', 'exp_toc', 'magic.priest_invocations', 'level.master', '', '', 'Сагитта Аурея', 'Sagitta Aurea', 'Метает волшебное копье из золотого света. - Копье движется по прямой, сквозь несколько целей. Каждая из них получает одинаковый урон при провале <i>(Защиты)</i>. - Демоны также получают урон и вытесняются из тела. - Демоны, поврежденные этой инвокацией, не могут использовать способности в следующем раунде.', 'magic.form.direct', '20', '', '14', '', '7d6', '', '', 'Уклонение', 'Атлетика'),
  ('MS187', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Эпона', 'Epona', 'Благословенный табун', 'Blessed Herd', 'Призывает до 10 диких лошадей и наделяет их магией. - Лошади пребывают в следующий час. - Возможны 2 варианта для каждой лошади на выбор: "Лошадь" и "Боевой конь". - Сбруя боевого коня не улучшает ПБ - Выбранные существа получат +5 для <i>(Верховой езды)</i> при использовании этих коней.', 'magic.form.self', '', '', '16', '', '', '7', 'time.unit.day', '', ''),
  ('MS188', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Свальблод', 'Svalblod', 'Кровь берсерка', 'Blood of the Berserker', 'Превращает вас в Гигантского Медведя. - Все предметы сливаются с формой. - Получаете способности Гигантского Медведя, но теряете профессиональные способности и магию. - Ваши Параметры и Навыки заменяются на значения Гигантского Медведя, если они выше ваших. - Урон и критические раны переносятся в обе стороны при смене облика. ПЗ при этом не падает ниже 1.', 'magic.form.self', '', '', '16', '', '', '1', 'time.unit.day', '', ''),
  ('MS189', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Вейопатис', 'Veyopatis', 'Чемпион реки', 'Champion of the River', 'Помечает цель речной водой, делая её вашим чемпионом.  - Чемпион получает сопроти-вление всем источникам урона. То есть урон, прошедший за броню уменьшается вдвое. - Чемпион получает бонус +5 ко всем броскам.', 'magic.form.direct', '10', '', '16', '5', '', '', '', '', ''),
  ('MS190', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Дана Меадбх', 'Dana Meadbh', 'Праздник изобилия', 'Feast of Plenty', '<align="left">Благословляет пиршество живительными эффектами. Есть два условия: 1) Пир должен быть размахом как минимум на 20 человек, но не ограничен сверху. 2) Пир должен быть приготовлен из местных продуктов - Поевшие на пиру получают:   * Восстанавление 6d6 ПЗ   * Немедленная обработка всех критических ран (но штрафы после обработки всё-таки сохраняются до заживления).   * Снятие <b><i>отравления</i></b>   * Излечение от <b><i>болезней</i></b></align>', 'magic.form.direct', '2', '', '16', '', '', '', '', '', ''),
  ('MS191', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Пророк Лебеда', 'The Prophet Lebioda', 'Чудо Лебеды', 'Miracle of Lebioda', 'Приказывает телу цели исцелить себя. - Цель полностью исцеляет одну критическую рану, включая штраф после обработки, или снимает штраф от уже обработанной раны. - Рана обрабатывается так, как если бы она не была нанесена (включая отрастание конеч-ностей, глаз и т.д.).', 'magic.form.direct', '2', '', '16', '', '', '', '', '', ''),
  ('MS192', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Нехалени', 'Nehaleni', 'Предзнаменование несчастья', 'Omen of Misfortune', 'Заполнить ваш разум проблесками возможного будущего. - Бросайте 1d10, пока не получите 3 результата, не равных 1 и 10, и запишите эти числа. - В течение дня, если цель рядом бросит на d10 одно из этих значений, то вы можете заменить результат на крит провал без использования действия.', 'magic.form.zone_centered', '', '20', '16', '', '', '1', 'time.unit.day', '', ''),
  ('MS193', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Морриган', 'Morrigan', 'Возмездие ворона', 'Retribution of the Raven', 'Вы блокируете связь со стихийными планами, сводя на нет всю магию. - Только выбранные вами цели или те, кто успешно защитился от этой инвокации, могут использовать магию любой формы. - Эту инвокацию нельзя рассеять.', 'magic.form.zone_centered', '', '20', '16', '5', '', '', '', 'Сопротивление магии', ''),
  ('MS194', 'exp_toc', 'magic.priest_invocations', 'level.arch_priest', 'Лилвани', 'Lilvani', 'Серебряный свет', 'Silverlight', 'Вы помечаете до 5 человек благословением лунного света. - Затронутые персонажи не получают штрафов за ПЗ ниже  Порога Ранения (т.е. их <b>РЕА</b>, <b>ЛВК</b>, <b>ИНТ</b>, <b>ВОЛЯ</b> не падают вдвое) или состояния При Смерти (т.е. все параметры не падают втрое). - При первом падении ПЗ ниже единицы, их количество остается равным 1. - Эффект длится до следующего рассвета.', 'magic.form.direct', '2', '', '16', '', '', '0-24', 'time.unit.hour', '', ''),
  ('MS195', 'exp_toc', 'magic.gruid_invocations', 'level.novice', '', '', 'Травничество', 'Herbalism', 'Позволяет создать эликсир из растительных ингредиентов. - Если все ингредиенты для эликсира являются растениями, вы можете бросать проверки <i>(Сотворения заклинаний)</i> вместо <i>(Алхимии)</i> при создании и  восстановлени.', 'magic.form.direct', '2', '', '2', '', '', '', '', '', ''),
  ('MS196', 'exp_toc', 'magic.gruid_invocations', 'level.novice', '', '', 'Печать щедрости', 'Touch of Bounty', 'Эффект зависит от того, на что друид наложил печать:-  Испорченную еду или питье можно снова сделать свежими и вкусными. - Кормовое растение становится в два раза более сытным. - Почву можно сделать в два раза более урожайной одним из двух способов:  * Растения станут в два раза больше.  * Урожай зреет в два раза быстрее.', 'magic.form.direct', '2', '', '1', '', '', '365', 'time.unit.day', '', ''),
  ('MS197', 'exp_toc', 'magic.gruid_invocations', 'level.novice', '', '', 'Голос советника', 'Voice of the Counselor', 'Делает слова вдохновенными. - Вы получаете бонус +4 к <i>(Лидерству)</i>. - Эффект на выбор:   * Можно шепнуть на ухо одной цели в пределах 10 метров.   * Сделать голос громким, слы-шимым издалека.', 'magic.form.self', '', '', '3', '', '', '10', 'time.unit.minute', '', ''),
  ('MS198', 'exp_toc', 'magic.gruid_invocations', 'level.novice', '', '', 'Паутина корней', 'Web of Roots', '<align="left">Позволяет управлять корнями дерева. - Корни имеют 15 ПЗ. - Можно менять цель атаки корней. - Варианты движений корней:    * <b><i>Схватить</i></b> цель, т.е. цель не может ходить и получает ко всем физическим действиям -2 штраф. Сбежать можно, бросая раз в ход проверку <i>(Защиты)</i> против новой проверки <i>(Сотворения заклинаний)</i>, или разрубив корни.    * Сделать подсечку, <i><b>сбив с ног</b></i> цель. Такая цель получает штраф -2 к <i>(Атаке)</i> и <i>(Защите)</i>, пока не потратит переме-щение на то чтобы встать.    * Разоружить цель, выбив оружие на (1d6)/2 метров, либо со штрафом -3 к <i>(Сотворению заклинаний)</i> схватить его корнем (но не использовать).</align>', 'magic.form.direct_bounce', '10', '', '2', '1', '', '', '', '', ''),
  ('MS199', 'exp_toc', 'magic.gruid_invocations', 'level.novice', '', '', 'Слово призыва', 'Word of Summoning', 'Призывает ближайшее дикое животное. - Зверь прибежит за 1d6 раундов. - Зверь дружелюбно и помогает, если друид не предает и не злоупотребляет животным. - По истечению инвокации зверь  становится нейтральным. - Можно использовать 1 раз в день в одной и той же области. - Зверь зависит от вложенной <b>ВЫН</b>:  * 2: маленький (птица, змей, кот...)  * 5: средний (волка, пантера, кабан..)  * 10: большой (медведь, бык, конь..)', 'magic.form.direct', '{inf}', '', '2-10', '', '', '10', 'time.unit.minute', '', ''),
  ('MS200', 'exp_toc', 'magic.gruid_invocations', 'level.journeyman', '', '', 'Осквернение Бигелоу', 'Bigelow''s Befoulment', 'Заражает еду и напитки бактериями.  * 5: съевшему дает <b><i>болезнь</i></b> на 1 час.  * 10: съевшему дает <b><i>отравление</i></b>.  <b><i>Болезнь</i></b>: Штраф -2 ко всем действиям, штраф -25% <b>ВЫН</b>, по требованию ГМ нужны проверки <i>(Стойкости) </i>Сл:14 (при провале получаем <b><i>Тошноту</i></b>). Лечится <i>(Лечащим прикосновением)</i>, со Сл:15 и ночным отдыхом. <b><i>Тошнота</i></b>: раз в 3 раунда при броске 1d10 не ниже <b>ТЕЛ</b> пропускаем ход из-за рвоты. <b><i>Отравление</i></b>: цель получает 3 урона/ход. Для снятия эффекта нужно пробросить <i>(Стойкость)</i> со <b>Сл:15,</b> потратив действие.', 'magic.form.zone_cube', '4', '2', '5-10', '', '', '', '', '', ''),
  ('MS201', 'exp_toc', 'magic.gruid_invocations', 'level.journeyman', '', '', 'Кровь горы', 'Blood of the Mountain', 'Наделяет цель огромной силой. - Атаки ближнего боя нельзя па-рировать - Атаки ближнего боя наносят двойной разрушающий урон оружию, щитам и доспехам. - Цель невосприимчива к эффек-там, сбивающим с ног.', 'magic.form.direct', '6', '', '6', '', '', '10', 'time.unit.minute', '', ''),
  ('MS202', 'exp_toc', 'magic.gruid_invocations', 'level.journeyman', '', '', 'Печать охоты', 'Sigil of the Hunt', 'Метит до 6 целей как «безопасные» или «добыча».   * «Безопасные» вызывают у зверей дружелюбние, а монстры становятся нейтральны.   * «Добыча» воспринимается хищниками и монстрами как цель для атаки. - Метки кажутся идентичными, но различимы при проверке Образования (Сл 16)', 'magic.form.direct', '2', '', '5', '', '', '1', 'time.unit.day', 'Сопротивление магии', ''),
  ('MS203', 'exp_toc', 'magic.gruid_invocations', 'level.master', '', '', 'Друидский тотем', 'Druidic Totem', E'Пожертвовав посохом из Дуба и омелы, создаете двухметровый тотем с 20ПЗ, который связывает вас с природой.  - Дает бонус фокусировке +4, т.е. заклинания становятся дешевле на 4 очка <b>ВЫН</b>. - При этом снимает бонус фокусиров-ке от ритуала Дуба и Омелы. - Все животные дружественные. - Дополнительный бонус зависит от местности. - Можно иметь только один активный тотем. Создание нового превращает старый в обычное растение.\n<b>Поля</b>: <b>Скор</b> друида равна 12. <b>Горы</b>: Сопротивление дробящему, рубящему и колющему урону. <b>Под землей</b>: Улучшенное Ночное Видение и бонус +4 к проверкам <i>(Скрытности)</i>. <b>Лес</b>: Регенерация 3 ПЗ/ход на 1 час при потреблении фрукта из области тотема. <b>Болото</b>: Невосприимчивость к <b><i>отравлениям</i></b> и <b><i>болезням</i></b>. <b>Берег</b>: Возможность дышать под водой и отсутствие штрафов за бой/маневры в воде. <b>Пустыня</b>: Невосприимчивость к жаре и возможность всегда найти источник воды. Один раз в день восстановление всей <b>ВЫН</b> при потреблении воды из области тотема. <b>Тундра</b>: Невосприимчивость к условиям снега и льда, иммунитет к <b><i>поджогу</i></b> и <b><i>заморозке</i></b>, сопротивление урону от огня и льда.', 'magic.form.zone_circle', '2', '1600', '14', '', '', '', '', '', ''),
  ('MS204', 'exp_toc', 'magic.gruid_invocations', 'level.master', '', '', 'Гнев природы', 'Wrath of Nature', E'Природа бушует вокруг друида. - Требует действие полного хода в каждом раунде. - Цель всегда бросает проверку <i>(Защиты)</i> против проверки навыка именно <i>(Сотворения заклинаний)</i> друида. - Эффект инвокации зависит от типа местности, где она создана.\n*<b>Поля</b>: либо спавн 1 торнадо в пределах 10м, либо существующий направить в пределах зоны шторма. Торнадо (куб 4 метра) двигается на 10м/ход, наносит 4d6 урона по торсу с отбросом на 10м куда укажет ГМ при контакте и провале защиты через  <i>(Атлетику)</i>.   *<b>Горы</b>: удар молнией по цели в зоне шторма. При провале  с уроном 6d6 по торсу и шансом <b><i>поджечь</i></b> 50%. Защита через <i>(Уклонение)</i> или <i>(Атлетику)</i>.   *<b>Под землей</b>: удар спавном сталактита или сталаг-мита с 5d6 урона. Вырост остается как укрытие с 20ПБ. Защита через <i>(Уклонение)</i>, <i>(Атлетику)</i>, <i>(Блок)</i>.   *<b>Лес</b>: либо спавн клубка корней с основой <i>(Борьбы)</i> равной 16 или базе <i>(Сотворения заклинаний)</i>, который не ходит, но бьет на 2м. Либо управление одним клубком чтобы захватить, обездвижить, удушить, обезаружить или сбить с ног цель.   *<b>Болото</b>: спавн облака болотного газа радиусом 6м. Цели получают <b><i>болезнь</i></b> при контакте (защита через <i>(Стойкость)</i>). Облако висит до конца инвокации. При контакте с огнем облако взрывается с 5d6 урона в торс и шансом 75% <b><i>загореться</i></b>.   *<b>Берег</b>: спавн смерча на воде, из которого вырываются 2 струи, бьющие на 20м с уроном 3d6 и отбрасыванием на 6м. Защита через <i>(Уклонение)</i> или <i>(Атлетику)</i>.   *<b>Пустыня</b>: спавн облака горящих песков радиусом 6м на 1 раунд. Цели при контакте получают <b><i>ослепление</i></b> на 5 раундов и <b><i>горение</i></b>. Защита через <i>(Уклонение)</i> или <i>(Атлетику)</i>.   *<b>Тундра</b>: заковать одну цель в лёд (защита через <i>(Уклонение)</i>, <i>(Атлетику)</i>, <i>(Сопротивление магии)</i>). Лёд блокирует любые действия цели. Снять эффект можно через проверку (Силы) со Сл:16 или если союзник нанесёт льду 10ПЗ урона (или 5ПЗ урона огнем), но лишний урон пойдет в закованную цель.', 'magic.form.zone_centered', '', '60', '14', '6', '', '', '', 'СЛ от ведущего', ''),
  ('MS205', 'exp_toc', 'magic.gruid_invocations', 'level.arch_druid', 'Блеобхерис', 'Bleobheris', 'Тень Блеобхериса', 'Shade of Bleobheris', 'Призывает великий дуб, успокаи-вающий сердца. - Звери становятся послушными. - Бойцы теряют инициативу и не могут совершать враждебные действия. - Подавляет предубеждения, отменяя штрафы от Социального положения или чудовищного наследия. - Цель может на каждом ходу пройти проверку <i>(Защиты)</i>. - Инвокация перестает действо-вать на цель после атаки.', 'magic.form.zone_circle', '', '50', '16', '', '', '1', 'time.unit.day', 'Сопротивление магии', ''),
  ('MS206', 'exp_toc', 'magic.gruid_invocations', 'level.arch_druid', 'Гвин Гарн', 'Gwyn Gern', 'Ветры тайги', 'Winds of the Taiga', 'Создает метель, ослепляющую всех в области и создающую условия Снега и Льда. - Выбранные вами союзники не ослеплены, невосприимчивы к снегу и льду, а их атаки имеют 50% шанс <b><i>заморозить</i></b>.  <b><i>Заморозка</i></b>: тело цели плохо слушается, а одежда покрывается наледью. Цель получает штраф -3 к <b>Скор</b> и -1 к <b>РЕА</b>. Лёд можно сломать, пройдя проверку <i>(Силы)</i> со <b>Сл:16</b> и потратив действие​​.', 'magic.form.zone_circle', '', '1600', '16', '', '', '1', 'time.unit.hour', '', ''),
  ('MS207', 'exp_toc', 'magic.gruid_invocations', 'level.arch_druid', 'Каэд Мырквид', 'Caed Myrkvyd', 'Святилище Чёрной рощи', 'Sanctuary of the Black Grove', 'Настраивает вас и (опционально) союзников на деревья в зоне действия. - Прикоснувшись к дереву, вы видите сквозь все деревья в этой области и можете сосредоточиться на конкретном месте. - Вы и ваши союзники можете проходить через любое дерево в этой области и выходить из другого дерева. - Союзники не могут видеть сквозь деревья, но могут указывать, куда хотят идти.', 'magic.form.zone_circle', '', '1600', '16', '', '', '1', 'time.unit.hour', '', ''),
  ('MS208', 'exp_toc', 'magic.gruid_invocations', 'level.arch_druid', 'Клан Ворона', 'Raven Clan', 'Заговор Матери', 'Conspiracy of the Mother', '<align="left">Призывает до 10 воронов, если они есть на расстоянии до полумили. - Пока вороны не дальше 20м:   * У вас есть телепатическая связь с воронами.    * Вороны разумны и верны приказам.    * Некоторые параметры и навыки получают усиление.    * Касаясь воронов, можно смотреть их воспоминания.    * Вороны всегда знают где вы</align>', 'magic.form.zone_centered', '', '20', '16', '', '', '', '', '', ''),
  ('MS209', 'exp_toc', 'magic.gruid_invocations', 'level.arch_druid', 'Гединейт', 'Gedynneith', 'Колодец знаний', 'Well of Knowledge', 'На тронутом дереве отрастает миска со светящейся волшебной водой. - 20 человек, которые пьют из миски, получают на один день:   * бонус +4 к <i>(Инициативе)</i> и <i>(Вниманию)</i>   * невосприимчивость к <b><i>Ошеломлению</i></b>, <b><i>Дезориентации</i></b> и <b><i>Галлюцинациям</i></b>   * видят сквозь иллюзии.   * если Порог Энергии был выше нуля, он получат бонус +4, но <i>(Сопротивление Магии)</i> получает штраф -4. - После окончания заклинания дерево возвращается в нормальное состояние, оставляя выгравированный символ друида. - Эффект можно получить не чаще раза в неделю.', 'magic.form.direct', '2', '', '16', '', '', '1', 'time.unit.day', '', '')
),
invocation_effects_en (ms_id, text_en) AS (
  VALUES
    ('MS066', 'Cast on an animal or mindless monster, causing it to become enraged toward a designated target and attempt to attack that target.'),
    ('MS067', E'Afflicts the target with a sickness. Depending on the STA invested, the target suffers:\n* 2: the target coughs and becomes Stunned (–2 to Attack and Defense) until their next turn.\n* 4: the target is Dazed from severe nausea. They cannot take actions, and attacks against them have DC 10. The effect ends if the target is hit.\n* 6: the target is effectively Poisoned (takes 3 damage per turn).\n- To remove the sickness effects, the target may roll (Endurance) vs your (Invocation Casting) check.'),
    ('MS068', E'Calms one animal.\n- You may cast it on yourself; then the druid gains +3 to (Wilderness Survival) when interacting with animals.'),
    ('MS069', E'Grows edible plants in any soil.\n- The plants are enough to feed, for 1 day, a number of people equal to the STA spent.'),
    ('MS070', E'Allows you to see creatures unnatural to the world of Neverland.\n- You can see monsters even through obstacles.\n- Monsters seen this way appear to glow.'),
    ('MS071', E'Covers a chosen area with vegetation and natural decor, hiding its contents with invisibility.\n- Grants +5 to (Stealth) but prevents anyone from moving.\n- The camouflage can be removed by:\n* repeating the invocation, or\n* dealing 10 damage to the branches.'),
    ('MS072', E'Choose one effect:\n- Restores 3 HP per turn.\n- Heals critical wounds: you must cast the blessing [wound level]*2+2 times at DC [wound level]*2+12, then rest to remove wound penalties (at least one day):\n1) Light: DC 8 — BODY days\n2) Moderate: DC 12 — BODY days\n3) Severe: DC 15 — BODY days\n4) Mortal: penalty is permanent'),
    ('MS073', E'Awakens the target''s primal reserves.\n- +2 to melee damage\n- -2 to INT for the duration.'),
    ('MS074', E'Reveals the threads of life that connect all living things.\n- You can see the remaining HP of visible targets.\n- You can also see critical wounds.'),
    ('MS075', E'Allows you to turn a small tree into a golem.\n- The golem serves the druid for the duration, then turns back into a tree.\n- A destroyed golem yields only 2d10 units of wood.\n- Otherwise, the wooden golem is the same as a normal golem.'),
    ('MS076', E'Changes the weather around the caster. Possible weather:\n* Clear: no modifiers\n* Cloudy: little sunlight:\n- +2 to DCs of skill checks\n- -3 to (Awareness)\n* Downpour: extinguishes fire\n* Storm winds: -2 DEX for ranged attacks\n* Thunderstorm: each turn, with a 35% chance, lightning strikes each target (except the caster). A target may dodge; on a hit it deals 8d6 damage with a 75% chance to set the target on fire.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS077', E'Grants the target Luck points.\n- The number of points equals half the points you rolled above DC 12 on your (Invocation Casting) check.\n- Maximum: 5 Luck points.'),
    ('MS078', 'Grants the target +3 to (Charisma) and (Seduction).'),
    ('MS079', E'Light emanates from the priest''s hands, increasing the light level in the area by 1.\nLighting effects:\n- DC modifier to skill checks:\n* Darkness: +5\n* Dim light: +2\n* Daylight: none\n* Bright light: +2\n- Awareness modifier:\n* Darkness: -4\n* Dim light: -2\n* Daylight: none\n* Bright light: -3\n- Attack and Defense modifier:\n* Darkness: -2\n* Bright light: -2 if looking toward the light source'),
    ('MS080', 'Allows the caster to enter the vaults of their own mind, reliving any memory or recalling any knowledge they have ever learned.'),
    ('MS081', E'Removes the Drunk condition.\nA Drunk target suffers:\n* -2 to REF, DEX, and INT\n* -3 to (Verbal Combat)\n* 25% chance to forget what they did while drunk'),
    ('MS082', E'Sows confusion in the target''s mind, making them doubt any information and even their own memories.\n- The target is Dazed: they cannot take actions, and attacks against them have DC 10. The effect ends if the target is hit.\n- To end the effect on their turn, the target must roll 1d10 under their INT.'),
    ('MS083', E'Ignites the target.\n- Deals one-time damage.\n- 100% chance to set the target on fire.'),
    ('MS084', 'Strengthens the target''s will, allowing them to make a new check against the effects of any spell currently affecting them.'),
    ('MS085', E'Creates a bright white light that forces one target to speak the truth.\n- Each round, the target makes a new Defense check.\n- On a failure, the target must answer truthfully to any question asked.'),
    ('MS086', E'Creates a portal for 1 round.\n- Size: 1×2 meters\n- Range: unlimited\n- Any items can be carried through\n- If the portal shuts while something is passing through, it inflicts the critical wound "lost limb" or cuts an item in half\n- Destination: familiar places only.'),
    ('MS087', E'Allows you to receive an answer to one question. It cannot be a prediction of the future.\n- The GM sets the DC based on how secret the information is.'),
    ('MS088', E'Cuts the bonds of life that tie the target to this world.\n- The target becomes Dying, as if they had taken lethal damage.\n- Allies may save the target with (First Aid) or Healing Touch at DC 16, restoring HP to its previous state.\nDying: all stats are reduced to 1/3 of normal. Each round the target rolls 1d10 under their base WILL; on a failure they die permanently.'),
    ('MS089', E'Sets the target on fire with bright white flame with red flashes.\n- Deals double Burning damage.\n- Can only be extinguished by magic or by being fully submerged in water for 3 rounds.\n- Anything that touches this flame suffers normal Burning.\n(Burning rules: 5 damage to each body part each round; armor absorbs damage but loses 1 SP; it takes a turn to put out the flames.'),
    ('MS090', E'Calls the spirit of Freya into the priest''s body, creating a glow around them.\n- Targets become immune to Fear.\n- Targets gain +25 HP.\n- If a target leaves the invocation''s area, the effect persists for 1d6 rounds unless they return to the area.\n- Faith in Freya is not required.\n- The priest may end the effect on targets at will.'),
    ('MS091', E'Puts targets into a deep coma during which their wounds heal.\n- Number of targets equals the caster''s (Spell Casting) skill value.\n- Targets do not react to anything.\n- After the coma, targets wake with full HP.\n- All temporary residual penalties from critical wounds healed before the invocation are removed.'),
    ('MS092', E'Allows you to spend Luck points as Kreve''s blessing.\n- During the invocation, the Luck points spent at the start apply to any roll the priest makes.\n- At the priest''s choice, the effect can be a bonus or a penalty to any roll within the area.\n- Maximum Luck invested is limited to 3× the priest''s (Spell Casting) skill value.'),
    ('MS093', E'An aura of the White Flame appears around the priest.\n- Lighting becomes Bright Light, so everyone suffers:\n* +2 to DCs of skill checks\n* -3 to (Awareness)\n* -2 to (Attack) and (Defense) if looking toward the priest\n- Melts any ice\n- Dispels any water spells\n- New water spells can only be created if they win an opposed (Spell Casting) check\n- Creatures vulnerable to the Sun suffer double vulnerability effects.'),
    ('MS177', E'Creates a glowing rune on a melee weapon, making it lighter and better balanced.\n- The weapon gains the Balanced effect for the duration.'),
    ('MS178', E'Blesses the target with divine insight.\n- Grants +2 to one skill.\n- The target must have at least 1 rank in that skill.\n- Can be used once per day.'),
    ('MS179', E'Wraps the target''s mind in false thoughts that conceal the truth.\n- The target gains +2 to (Deceit) checks.\n- The target cannot be forced to speak the truth by magic.\n- You cannot spy on the target via telepathy.\n- Magical investigation does not reveal the spell unless someone succeeds on an (Awareness) check at DC 20.'),
    ('MS180', E'Calls upon divine power, draining the target''s will to resist.\n- The target loses 2d6 STA.\n- If the target''s Energy Threshold is 1 or higher, they lose an additional 2d6 STA.'),
    ('MS181', E'Calls an aspect of a deity, making the priest''s posture imposing.\n- Your voice can be heard from far away.\n- +4 to (Intimidation).\n- Alternatively, you may make up to 6 targets within 10 m immune to fear.'),
    ('MS182', E'Grants divine providence.\n- The first time you loot anything, you (or the GM) roll twice and take the higher result.\n- This applies to each item found from the same source (e.g., when looting a monster, roll twice for each loot entry).'),
    ('MS183', E'Marks the target with a symbol of decay, preventing healing.\n- The target cannot regain HP from any source, including natural healing.'),
    ('MS184', E'Reacts to attempts to scry you or anyone within 10 m of you.\n- Triggers on Hydromancy, Pyromancy, etc.\n- You learn that you were targeted and you see the scryer''s face.\n- For the scryer to realize they were caught, they must succeed on an (Education) or (Magical Knowledge) check at DC 20.\n- You are notified if the scryer realizes they were caught.'),
    ('MS185', E'Enters the target''s mind and alters their memories. Effect depends on STA invested:\n* 14: causes retrograde amnesia, blocking memories\n* 16: allows you to implant fabricated memories\nThe target gains +5 to Defense if they have not previously been subjected to memory blocking.'),
    ('MS186', E'Hurls a magical spear of golden light.\n- The spear travels in a straight line through multiple targets; each takes the same damage if they fail their Defense.\n- Demons also take damage and are forced out of the body.\n- Demons hit by this invocation cannot use abilities in the next round.'),
    ('MS187', E'Summons up to 10 wild horses and empowers them with magic.\n- The horses remain for the next hour.\n- For each horse, choose one of two variants: "Horse" or "Warhorse".\n- Warhorse tack does not improve SP.\n- Chosen creatures gain +5 to (Riding) when using these horses.'),
    ('MS188', E'Transforms you into a Giant Bear.\n- All items merge into the form.\n- You gain the Giant Bear''s abilities, but lose professional abilities and magic.\n- Your stats and skills are replaced by the Giant Bear''s values if they are higher than yours.\n- Damage and critical wounds carry over both ways when changing form. HP does not drop below 1.'),
    ('MS189', E'Marks the target with river water, making them your champion.\n- The champion gains resistance to all sources of damage: damage that gets past armor is halved.\n- The champion gains +5 to all rolls.'),
    ('MS190', E'Blesses a feast with revitalizing effects. Requirements:\n1) The feast must be for at least 20 people (no upper limit).\n2) The feast must be cooked from local products.\nThose who eat gain:\n* 6d6 HP restored\n* Immediate treatment of all critical wounds (post-treatment penalties still remain until healed)\n* Removal of Poison\n* Cure of Diseases'),
    ('MS191', E'Commands the target''s body to heal itself.\n- The target fully heals one critical wound (including post-treatment penalties), or removes the penalty from an already treated wound.\n- The wound is treated as if it had never happened (including regrowing limbs, eyes, etc.).'),
    ('MS192', E'Fills your mind with flashes of possible futures.\n- Roll 1d10 until you get 3 results that are not 1 or 10; write those numbers down.\n- During the day, if someone near you rolls one of those numbers on a d10, you may replace their result with a critical failure without spending an action.'),
    ('MS193', E'Blocks the connection to elemental planes, negating all magic.\n- Only targets chosen by you (or those who successfully resisted this invocation) can use any form of magic.\n- This invocation cannot be dispelled.'),
    ('MS194', E'Marks up to 5 people with a blessing of moonlight.\n- They do not suffer penalties from having HP below the Wound Threshold (i.e., their REF/DEX/INT/WILL are not halved) or from the Dying state (i.e., their stats are not reduced to 1/3).\n- The first time their HP would drop below 1, it instead remains at 1.\n- Lasts until the next dawn.'),
    ('MS195', E'Allows you to brew an elixir from plant ingredients.\n- If all ingredients in the elixir are plants, you may roll (Spell Casting) instead of (Alchemy) when crafting and recovering it.'),
    ('MS196', E'Effect depends on what the druid marks:\n- Spoiled food or drink becomes fresh and tasty again.\n- Feed crops become twice as filling.\n- Soil becomes twice as productive in one of two ways:\n* plants grow twice as large, or\n* crops ripen twice as fast.'),
    ('MS197', E'Makes your words inspirational.\n- You gain +4 to (Leadership).\n- Choose one:\n* Whisper to one target within 10 meters.\n* Make your voice loud enough to be heard from afar.'),
    ('MS198', E'Allows you to control a tree''s roots.\n- Roots have 15 HP.\n- You may change the roots'' attack target.\nRoot actions:\n* Grab: the target cannot move and suffers -2 to all physical actions. Escape by rolling Defense once per turn vs a new (Spell Casting) check, or by cutting the roots.\n* Trip: knocks the target prone; they suffer -2 to Attack and Defense until they spend movement to stand.\n* Disarm: knocks the target''s weapon away by (1d6)/2 meters, or (at -3 to Spell Casting) grab it with a root (but not use it).'),
    ('MS199', E'Summons the nearest wild animal.\n- The beast arrives in 1d6 rounds.\n- The beast is friendly and helps as long as the druid does not betray or abuse it.\n- When the invocation ends, the beast becomes neutral.\n- Can be used once per day in the same area.\n- The summoned beast depends on STA invested:\n* 2: small (bird, snake, cat…)\n* 5: medium (wolf, panther, boar…)\n* 10: large (bear, bull, horse…'),
    ('MS200', E'Infects food and drinks with bacteria.\n* 5: the consumer gets Disease for 1 hour.\n* 10: the consumer gets Poisoned.\nDisease: -2 to all actions, -25% STA; the GM may call for Endurance checks at DC 14 (on failure: Nausea). Cured by Healing Touch at DC 15 and a night''s rest.\nNausea: every 3 rounds, if a 1d10 roll is not under BODY, you lose your turn from vomiting.\nPoisoned: the target takes 3 damage per turn. To remove, roll Endurance at DC 15, spending an action.'),
    ('MS201', E'Grants the target immense strength.\n- Melee attacks cannot be parried.\n- Melee attacks deal double destructive damage to weapons, shields, and armor.\n- The target is immune to effects that knock them prone.'),
    ('MS202', E'Marks up to 6 targets as either "safe" or "prey".\n* "Safe" targets appear friendly to beasts and monsters become neutral.\n* "Prey" targets are perceived by predators and monsters as a target to attack.\n- The marks look identical, but can be distinguished with an (Education) check at DC 16.'),
    ('MS203', E'By sacrificing an oak-and-mistletoe staff, you create a 2-meter totem with 20 HP that links you to nature.\n- Grants +4 Focus, reducing spell STA costs by 4.\n- Removes the Focus bonus from the Oak & Mistletoe ritual.\n- All animals are friendly.\n- Additional bonus depends on terrain.\n- You can have only one active totem; creating a new one turns the old one into a normal plant.\nAdditional terrain bonuses:\n* Plains: the druid''s SPD becomes 12.\n* Mountains: resistance to bludgeoning, slashing, and piercing.\n* Underground: improved night vision and +4 to (Stealth).\n* Forest: regeneration 3 HP/turn for 1 hour when consuming a fruit from the totem area.\n* Swamp: immunity to Poison and Disease.\n* Coast: can breathe underwater and no penalties for combat/maneuvers in water.\n* Desert: immunity to heat, always able to find water; once per day fully restore STA by drinking water from the totem area.\n* Tundra: immunity to snow/ice conditions; immunity to Burning and Freezing; resistance to fire and ice damage.'),
    ('MS204', E'Nature rages around the druid.\n- Requires a full-round action each round.\n- The target always rolls Defense against the druid''s (Spell Casting) check.\n- The effect depends on terrain:\n* Plains: either spawn one tornado within 10 m, or direct an existing one within the storm. The tornado (4 m cube) moves 10 m/turn, deals 4d6 torso damage, and pushes the target 10 m (GM chooses direction) on contact and failed defense via (Athletics).\n* Mountains: lightning strike on a target in the storm. On failure: 6d6 torso damage and 50% chance to ignite. Defense via (Dodge/Escape) or (Athletics).\n* Underground: spawn a stalactite/stalagmite strike for 5d6 damage; the growth remains as cover with 20 SP. Defense via (Dodge/Escape), (Athletics), or (Block).\n* Forest: either spawn a root mass with (Brawling) base 16 or your (Spell Casting) base; it doesn''t move but attacks within 2 m. Or control one root mass to grab, immobilize, suffocate, disarm, or trip a target.\n* Swamp: spawn a swamp-gas cloud (radius 6 m). Targets get Disease on contact (defense via (Endurance)). The cloud lasts until the invocation ends. If it contacts fire, it explodes for 5d6 torso damage and 75% chance to ignite.\n* Coast: spawn a waterspout with two jets, range 20 m, dealing 3d6 damage and pushing 6 m. Defense via (Dodge/Escape) or (Athletics).\n* Desert: spawn a cloud of burning sands (radius 6 m) for 1 round. Targets on contact are Blinded for 5 rounds and suffer Burning. Defense via (Dodge/Escape), (Athletics), or (Resist Magic)).\n* Tundra: encase one target in ice (defense via (Dodge/Escape), (Athletics), or (Resist Magic)). Ice prevents actions. Remove with Strength check DC 16, or if an ally deals 10 damage to the ice (or 5 fire damage); excess damage carries into the target.'),
    ('MS205', E'Summons a great oak that calms hearts.\n- Beasts become obedient.\n- Combatants lose initiative and cannot take hostile actions.\n- Suppresses prejudice, removing penalties from Social Standing or monstrous heritage.\n- Each turn a target may make a Defense check.\n- The invocation stops affecting a target after they attack.'),
    ('MS206', E'Creates a blizzard that blinds everyone in the area and creates Snow and Ice conditions.\n- Chosen allies are not blinded, are immune to snow and ice, and their attacks have a 50% chance to freeze.\nFreezing: the target''s body becomes sluggish and their clothing is coated with ice. The target suffers -3 SPD and -1 REF. The ice can be broken with a Strength check at DC 16, spending an action.'),
    ('MS207', E'Attunes you (and optionally allies) to the trees in the area.\n- By touching a tree, you can see through all trees in the area and focus on a specific spot.\n- You and your allies can pass through any tree in the area and emerge from another tree.\n- Allies cannot see through trees, but can indicate where they want to go.'),
    ('MS208', E'Summons up to 10 ravens (if any are within half a mile).\nWhile the ravens are within 20 m:\n* you have a telepathic link with them\n* they are intelligent and obey commands\n* some stats and skills are enhanced\n* by touching a raven you can view its memories\n* the ravens always know where you are'),
    ('MS209', E'A bowl with glowing magical water grows from a touched tree.\n- Up to 20 people who drink from it gain for one day:\n* +4 to Initiative and Awareness\n* immunity to Stunned, Dazed, and Hallucinations\n* ability to see through illusions\n* if their Energy Threshold is above 0, it increases by +4, but (Resist Magic) suffers -4\n- After the spell ends, the tree returns to normal, leaving an engraved druidic symbol.\n- A creature can benefit from this no more than once per week.')
),
ins_i18n AS (
INSERT INTO i18n_text (id, entity, entity_field, lang, text)
SELECT * FROM (
-- cult/circle
SELECT ck_id('witcher_cc.magic.invocation.cult_or_circle.'||rd.ms_id),
'magic',
           'invocation_cults',
           'ru',
           rd.cult_ru
      FROM raw_data rd
     WHERE nullif(rd.cult_ru,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.invocation.cult_or_circle.'||rd.ms_id),
           'magic',
           'invocation_cults',
           'en',
           rd.cult_en
      FROM raw_data rd
     WHERE nullif(rd.cult_en,'') IS NOT NULL
    UNION ALL
    -- names
    SELECT ck_id('witcher_cc.magic.invocation.name.'||rd.ms_id),
           'magic',
           'invocation_names',
           'ru',
           rd.name_ru
      FROM raw_data rd
     WHERE nullif(rd.name_ru,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.invocation.name.'||rd.ms_id),
           'magic',
           'invocation_names',
           'en',
           rd.name_en
      FROM raw_data rd
     WHERE nullif(rd.name_en,'') IS NOT NULL
    UNION ALL
    -- effects (effect_1 + effect_2 already merged; HTML stripped)
    SELECT ck_id('witcher_cc.magic.invocation.effect.'||rd.ms_id),
           'magic',
           'invocation_effects',
           'ru',
           regexp_replace(replace(replace(rd.effect_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.effect_ru,'') IS NOT NULL
    UNION ALL
    -- effects EN (from manual translations)
    SELECT ck_id('witcher_cc.magic.invocation.effect.'||iee.ms_id),
           'magic',
           'invocation_effects',
           'en',
           iee.text_en
      FROM invocation_effects_en iee
  ) foo
  ON CONFLICT (id, lang) DO UPDATE
    SET text = EXCLUDED.text
)
INSERT INTO wcc_magic_invocations (
  ms_id, dlc_dlc_id,
  magic_type_id,
  level_id, form_id, effect_time_unit_id,
  cult_or_circle_id,
  name_id, effect_id,
  distance, zone_size,
  stamina_cast, stamina_keeping,
  damage,
  effect_time_value,
  defense_ids
)
SELECT rd.ms_id
     , rd.dlc_dlc_id
     , ck_id(rd.magic_type_key) AS magic_type_id
     , CASE WHEN nullif(rd.level_key,'') IS NOT NULL THEN ck_id(rd.level_key) ELSE NULL END AS level_id
     , CASE WHEN nullif(rd.form_key,'') IS NOT NULL THEN ck_id(rd.form_key) ELSE NULL END AS form_id
     , CASE
         WHEN rd.effect_time_unit_key LIKE 'time.unit.%' THEN ck_id(rd.effect_time_unit_key)
         ELSE NULL
       END AS effect_time_unit_id
     , CASE WHEN nullif(rd.cult_ru,'') IS NOT NULL OR nullif(rd.cult_en,'') IS NOT NULL THEN ck_id('witcher_cc.magic.invocation.cult_or_circle.'||rd.ms_id) ELSE NULL END AS cult_or_circle_id
     , ck_id('witcher_cc.magic.invocation.name.'||rd.ms_id) AS name_id
     , ck_id('witcher_cc.magic.invocation.effect.'||rd.ms_id) AS effect_id
     , nullif(rd.distance,'')
     , nullif(rd.zone_size,'')
     , nullif(rd.stamina_cast,'')
     , nullif(rd.stamina_keeping,'')
     , nullif(rd.damage,'')
     , CASE
         WHEN nullif(rd.effect_time_value,'') IS NULL THEN NULL
         WHEN rd.effect_time_unit_key LIKE 'time.unit.%' THEN nullif(rd.effect_time_value,'')
         WHEN nullif(rd.effect_time_unit_key,'') IS NOT NULL THEN (nullif(rd.effect_time_value,'') || ' ' || rd.effect_time_unit_key)
         ELSE nullif(rd.effect_time_value,'')
       END AS effect_time_value
     , ARRAY_REMOVE(ARRAY[
         CASE btrim(rd.defense_1)
           WHEN 'Уклонение' THEN ck_id('skill.dodge')
           WHEN 'Атлетика' THEN ck_id('skill.athletics')
           WHEN 'Блокирование' THEN ck_id('skill.blocking')
           WHEN 'Сопротивление магии' THEN ck_id('skill.resist_magic')
           WHEN 'Сопротивление убеждению' THEN ck_id('skill.resist_coercion')
           WHEN 'СЛ от ведущего' THEN ck_id('skill.gm_dc')
           WHEN 'Воля*3' THEN ck_id('parameter.will_x3')
           ELSE NULL
         END,
         CASE btrim(rd.defense_2)
           WHEN 'Уклонение' THEN ck_id('skill.dodge')
           WHEN 'Атлетика' THEN ck_id('skill.athletics')
           WHEN 'Блокирование' THEN ck_id('skill.blocking')
           WHEN 'Сопротивление магии' THEN ck_id('skill.resist_magic')
           WHEN 'Сопротивление убеждению' THEN ck_id('skill.resist_coercion')
           WHEN 'СЛ от ведущего' THEN ck_id('skill.gm_dc')
           WHEN 'Воля*3' THEN ck_id('parameter.will_x3')
           ELSE NULL
         END
       ], NULL)::uuid[] AS defense_ids
  FROM raw_data rd
ON CONFLICT (ms_id) DO UPDATE
SET
  dlc_dlc_id = EXCLUDED.dlc_dlc_id,
  magic_type_id = EXCLUDED.magic_type_id,
  level_id = EXCLUDED.level_id,
  form_id = EXCLUDED.form_id,
  effect_time_unit_id = EXCLUDED.effect_time_unit_id,
  cult_or_circle_id = EXCLUDED.cult_or_circle_id,
  name_id = EXCLUDED.name_id,
  effect_id = EXCLUDED.effect_id,
  distance = EXCLUDED.distance,
  zone_size = EXCLUDED.zone_size,
  stamina_cast = EXCLUDED.stamina_cast,
  stamina_keeping = EXCLUDED.stamina_keeping,
  damage = EXCLUDED.damage,
  effect_time_value = EXCLUDED.effect_time_value,
  defense_ids = EXCLUDED.defense_ids;

-- <<< END sql/items/029_wcc_magic_invocations.sql

-- >>> BEGIN sql/items/030_wcc_magic_rituals.sql

\echo '030_wcc_magic_rituals.sql'
-- Magic rituals from temp TSV

CREATE TABLE IF NOT EXISTS wcc_magic_rituals (
  ms_id                 varchar(10) PRIMARY KEY,  -- e.g. 'MS104'
  dlc_dlc_id            varchar(64) NOT NULL REFERENCES wcc_dlcs(dlc_id),

  level_id              uuid NULL,                -- ck_id('level.*')
  form_id               uuid NULL,                -- ck_id('magic.form.*')
  effect_time_unit_id   uuid NULL,                -- ck_id('time.unit.*')
  preparing_time_unit_id uuid NOT NULL,           -- always time.unit.round (per rules)

  name_id               uuid NOT NULL,            -- ck_id('witcher_cc.magic.ritual.name.'||ms_id)
  effect_id             uuid NOT NULL,            -- ck_id('witcher_cc.magic.ritual.effect.'||ms_id)
  how_to_remove_id      uuid NULL,                -- ck_id('witcher_cc.magic.ritual.how_to_remove.'||ms_id)

  dc                    text NULL,
  preparing_time_value  integer NULL,
  ingredients           jsonb NULL,               -- [{"id":"<uuid>","qty":"<text|null>"}, ...]

  zone_size             text NULL,
  stamina_cast          text NULL,
  stamina_keeping       text NULL,
  effect_time_value     text NULL
);

WITH raw_data (
  ms_id, dlc_dlc_id,
  level_key,
  name_ru, name_en,
  effect_ru,
  how_to_remove_ru,
  dc,
  preparing_time_value,
  ingredients_raw,
  form_key,
  zone_size,
  stamina_cast, stamina_keeping,
  effect_time_value, effect_time_unit_key
) AS ( VALUES
  ('MS104', 'core', 'level.novice', 'Ритуал очищения', 'Cleansing Ritual', 'Очищает цель от ядов и болезней. - Избавляет на выбор с разной <b>Сл</b>:   * <b>Сл:12</b> - Алкоголь и нарктоики   * <b>Сл:15</b> - Яд и масла   * <b>Сл:18</b> - Болезни - Не может излечить Бич Катреоны.', '', '12-18', '5', 'I080 (1), I059 (1), I275 (2), I090 (2), T027 (1)', 'magic.form.direct', '', '3', '', '', ''),
  ('MS105', 'core', 'level.novice', 'Гидромантия', 'Hydromancy', 'Позволяет видеть на воде события послдних 2 дней.   * <b>Сл:15</b> - прошлые события   * <b>Сл:18</b> - текущие события - Маг в месте текущих событий может заметить слежку, пробросив <i>(Магические познания)</i> против вашего <i>(Проведения ритуалов)</i>', '', '15-18', '5', 'I262 (1), I069 (1), I027 (2), I064 (2), I077 (2), I073 (1)', 'magic.form.self', '', '5', '2', '', ''),
  ('MS106', 'core', 'level.novice', 'Магическое сообщение', 'Magical Message', 'Записывает в носитель сообщение в виде голограммы мага в полный рост. - Длительность до 5 минут. - Можно воспроизвести 1-3 раза (по желанию мага). - При записи на совершенный самоцвет запись как живая.', '', '12', '5', 'I027 (1), I078 (1), I005 (1), T039 (1)', 'magic.form.direct', '', '3', '', '', ''),
  ('MS107', 'core', 'level.novice', 'Пиромантия', 'Pyromancy', 'Позволяет видеть в пламени текущие события. - Маг в месте слежки может заметить её, пробросив <i>(Магические познания)</i> против вашего <i>(Проведения ритуалов)</i>', '', '15', '5', 'I263 (1), I027 (2), I001 (2), I058 (5), I059 (2), I013 (2)', 'magic.form.self', '', '5', '5', '', ''),
  ('MS108', 'core', 'level.novice', 'Ритуал жизни', 'Ritual of Life', 'Создает круг, исцеляющий круг.  - Действует на 1 цель  - Лечит 3 ПЗ в ход для цели внутри.  - Если цель покидает круг, он исчезает.', '', '15', '5', 'I275 (2), I001 (2), I013 (2), I098 (2)', 'magic.form.zone_circle', '', '5', '', '10', 'time.unit.round'),
  ('MS109', 'core', 'level.novice', 'Магический ритуал', 'Ritual of Magic', 'Создаёт круг, наполненный магией:  - Первая вошедшая цель, способ-ная к магии, получает к <b>Энергии</b> бонус +<i>(Проведение ритуалов)/2</i>.  - Действует только на 1 цель.  - Альтернатива: истощить круг, получив (1d6)/2 пятой эссенции', '', '15', '5', 'I275 (2), I005 (2), I086 (2), I089 (1)', 'magic.form.zone_circle', '', '3', '', '5', 'time.unit.hour'),
  ('MS110', 'core', 'level.novice', 'Сосуд заклятия', 'Spell Jar', '<align="left">Создает в запечатанном гляняном сосуде вихрь. - Срок годности ограничен. - При разбитии срабатывает случай-ное заклинание (1d10/2):   * Тюрьма Тальфрина   * Зефир   * Танио Ильхар   * Туман Дормина   * Статическая буря</align>', '', '15', '5', 'I041 (5), I027 (1), I011 (2), I275 (1), I013 (1), I067 (2), I089 (1)', 'magic.form.self', '', '5', '', '1d6', 'time.unit.day'),
  ('MS111', 'core', 'level.novice', 'Спиритический сеанс', 'Spirit Seance', E'Призывает дух умершего с его разумом и памятью, включая причину смерти.\n - Прогнать духа можно по его желанию или уничтожив.\n - Говорить с ним можно в месте захоронения.\n - Призывает и всех родственников ближе 20м.\n - Дух может вселиться в цель. Защита - бросок <i>(Сопротивления магии)</i> против <i>(Сотворения заклинаний)</i> сразу и каждые 1d6 ходов с той же <b>Сл</b>. При провале дух контролирует тело. Бонус +5 к <i>(Сопротивлению магии)</i> если поведение неприемлемо и +10, если опасно для жизни.', '', '12', '5', 'I264 (1), I098 (1), I062 (2), I100 (2), I086 (2)', 'magic.form.direct', '', '5', '', '', ''),
  ('MS112', 'core', 'level.novice', 'Телекоммуникация', 'Telecommunication', 'Позволяет общаться с другим обладателем такого устройства.  - Оба участника должны провести ритуал одновременно.', '', '0', '5', 'T112 (1)', 'magic.form.self', '{inf}', '3', '', '1', 'time.unit.hour'),
  ('MS113', 'core', 'level.journeyman', 'Освящение', 'Consecrate', 'Создает в обе стороны непрони-цаемый круг для чудовищ.  - Пройти в 1 сторону можно пробросив <i>(Сопротивление магии)</i> против броска <i>(Проведения ритуалов)</i> при сотворении барьера.  - Блокирует внутри магию чудовищ, но не физические снаряды.  - Металл должен соответствовать уязвимости чудовища  - Работает пока не рассеян', '', '18', '10', 'I027 (5), I089 (2), I275 (4), I042 (5), I040 (1)', 'magic.form.zone_circle', '0-10', '12', '', '', ''),
  ('MS114', 'core', 'level.journeyman', 'Магический барьер', 'Magic Barrier', 'Создает материальный барьер из света. - Барьер имеет 50ПЗ. - Барьер непроницаем для материальных объектов, но не бестелесных сущностей. - Возможно телепортироваться внутрь и наружу. - Можно остановить обмен воздухом, тогда его хватит на 20-[количество целей внутри] ходов. - Можно восполнять ПЗ барьера по 5ПЗ за 1 <b>ВЫН</b>.', '', '18', '10', 'I027 (5), I089 (2), I275 (4)', 'magic.form.zone_circle', '10', '10', '2', '', ''),
  ('MS115', 'core', 'level.journeyman', 'Онейромантия', 'Oneiromancy', 'Позволяет увидеть во сне истину.   * <b>Сл:15</b> - прошлые события   * <b>Сл:18</b> - текущие события - Маг в месте слежки может заметить её, пробросив <i>(Магические познания)</i> против вашего <i>(Проведения ритуалов)</i> - Можно поделиться сном с другими в количестве <i>(Проведения ритуалов)</i>, но для этого они должны ответить на несколько личных вопросов. - Сон длится до конца ритуала.', '', '15-18', '10', 'I265 (1)', 'magic.form.self', '', '8', '', '1d10', 'time.unit.round'),
  ('MS116', 'core', 'level.master', 'Артефактная компрессия', 'Artifact Compression', 'Превращает цель в нефритовую фигурку в 10 раз меньше оригинала на дистанции 10м. - Цель получает 6d6 урона в корпус при провале <i>(Стойкости)</i> со <b>Сл:15</b> - Цель не стареет, но имеет 20% ПЗ. - Можно отломить голову или конечность броском <i>(Силы)</i> со <b>Сл:14</b> или нанеся 5 урона. Эффекты соответствуют крит.ране после декомпрессии. - Расколдованная цель <b><i>дезориенти-рована</i></b>.', '', '18', '10', 'T039 (1), I027 (5), I089 (2), I041 (4)', 'magic.form.direct', '', '16', '', '', ''),
  ('MS117', 'core', 'level.master', 'Сотворение голема', 'Golem Crafting', 'Создает простого голема, исполняющие приказы создателя. - Не может использовать мелкую моторику. - Не может исполнять точные детализированные приказы. - Не думает, исполняет приказ до отмены или своей смерти.', '', '20', '10', 'I044 (10), I275 (2), T039 (1), I006 (10), I089 (5), I027 (2)', 'magic.form.direct', '', '15', '', '', ''),
  ('MS118', 'core', 'level.master', 'Интерактивная иллюзия', 'Interactive Illusion', 'Создает управляемую иллюзию рядом с магом. - Иллюзия ощущается реальной на вид, ощупь, звук и запах. - Если иллюзия атакует, то цель бросает <i>(Сопротивление магии)</i> или <i>(Стойкость)</i> со <b>Сл:12</b>. При успехе иллюзия раскрыта, при провале цель бросает испытание <i>(Устойчивости)</i>. При повторном провале цель <b><i>дезориентирована</i></b> - Работает пока не рассеяна', '', '18', '10', 'I081 (3), T039 (1), I027 (5), I089 (1), I005 (2)', 'magic.form.zone_circle', '20', '12', '', '', ''),
  ('MS212', 'exp_toc', 'level.novice', 'Создание хрустального черепа', 'Create Crystal Skull', 'Превращает череп кошки, собаки, птицы или змеи в хрустальный. - Его можно активировать, превратив в животное из которого он сделан. - Животное выполняет мысленные приказы, которые слышит пока рядом. - При смерти животного череп деактивируется, но его можно зарядить тем же ритуалом с [2] пятой эссенции.', '', '14', '10', 'I266, I027 (5), I267, I027 (2)', 'magic.form.self', '', '5', '', '', ''),
  ('MS213', 'exp_toc', 'level.novice', 'Наполнить трофей', 'Imbue Trophy', E'Зачаровывает трофей из монстра, которого помог убить пользователь. Эффект при ношении зависит от чудовища:\n - <b>Бес</b>: +2 к броскам <i>(Сотворения заклинаний)</i> и <i>(Сопротивления магии)</i>. \n - <b>Брукса</b>: Вы общаетесь телепатией на 20м. \n - <b>Вендниго</b>: Иммунитет к болезням.\n - <b>Виверна</b>: Эффект к атакам Отравление (25%) \n - <b>Гаркаин</b>: +1 к спас.броску от Оглушения. \n - <b>Главоглаз</b>: Иммунитет к яду. \n - <b>Голем</b>: Иммунитет к кровотечению.\n - <b>Грифон</b>: При получении крит.раны бросайте d10 дважды и выберите результат.\n - <b>Игоша</b>: Получаете соц.статус Опасение. Если статус уже был, то эффекты удваиваются.\n - <b>Катакан</b>: Эффект к атакам Кровотечение (25%)\n - <b>Кладбищенская баба</b>: +2 к броскам <i>(Проведения Ритуалов)</i> и <i>(Наложению Порчи)</i>.\n - <b>Куролиск</b>: Эффект к атакам Ослепление (10%)\n - <b>Леший</b>: Можете общаться с животными и подчинить их после словесного боя. Но вредить себе зверь не будет.\n - <b>Мантикора</b>: +2 к Сл сопротивления и снятию ваших ядов.\n - <b>Медведь</b>: -2 штраф людям к попыткам вырваться из вашего захвата.\n - <b>Моровая дева</b>: Вас окружают мухи. Штраф к броскам врагов -2 рядом и болезнь (10%). Вам штраф -2 к <i>(Соблазнению)</i>, <i>(Убеждению)</i>, <i>(Внешнему виду)</i>\n - <b>Оборотень</b>: +2 к броскам <i>(Силы)</i> и <i>(Выживания)</i>\n - <b>Ослизг</b>: +2 к <i>(Сотворению заклинаний)</i> для огенной магии.\n - <b>Пантера</b>: Скорость лазания х2.\n - <b>Полуденица</b>: Иммунитет к страху.\n - <b>Скальный тролль</b>: +1 к множителю дистанции для метательного оружия.\n - <b>Суккуб</b>: +1 к соц.статусу.\n - <b>Тролль</b>: Пьянеете в 2 раза дольше и без похмелья.\n - <b>Туманник</b>: +2 к броскам <i>(Скрытности)</i> и <i>(Ловкости рук)</i>.\n - <b>Утковол</b>: Трупоед всегда выберет другую цель, если она есть.\n - <b>Феникс</b>: Минус 50% к шансу загореться <i>(не меньше нуля)</i>.\n - <b>Хим</b>: Минимум 4ед урона всегда проходят через броню врагов.\n - <b>Химера</b>: Раз в день выбираете сопротивление 1 виду урона от оружия.\n - <b>Циклоп</b>: Вместо <b><i>дезориентации</i></b> от магии вы атакуете ближайшую живую цель в следующем раунде.\n - <b>Шарлей</b>: +2 к <i>(Сотворению заклинаний)</i> для земляной магии.\n - <b>Элементаль Земляной</b>: Разрушающий урон по ПБ или Н удваивается.\n - <b>Элементаль Ледяной</b>: Эффект к атакам Заморозка (25%)\n - <b>Элементаль Огненный</b>: Эффект к атакам Горение (25%)', '', '12', '10', 'I268, I027 (1), I089 (1), I030 (10), I028 (1), I025 (2)', '', '', '3', '', '', ''),
  ('MS214', 'exp_toc', 'level.novice', 'Тиромантия', 'Tyromancy', E'Позволяет узнать повлекут ли действия положительный или отрицательный результат. Сложность зависит от сыра (1d6 мастер кидает тайно):\n   * Стандартный сыр: <b>Сл:</b>[13 + 1d6]\n   * Высококачественный сыр: <b>Сл:</b>[13 - 1d6]\n Если пробросить <i>(Проведение ритуалов)</i> с этой <b>Сл</b>, то ГМ должен правдиво ответить. - При неудаче ГМ даст случайный ответ. - Если результат разносторонний, то ГМ даст результат, который наступит раньше.', '', '7-19', '5', 'I269 (2)', '', '', '2', '', '', ''),
  ('MS215', 'exp_toc', 'level.novice', 'Спорная подвеска', 'Wagerer''s Pendant', E'Создает подвеску, которая отключает любые эффекты порч уже имеющихся и новых.\n - При снятии подвески эффекты возвращаются.\n - Если к концу действия ритуала на пользователе еще будут активные порчи, подвеска расколется и пользователь, как и цели в пределах 2м получат ряд новых порч по решению ГМа.', '', '14', '10', 'I005 (2), I014 (1), I100 (2), I020 (2), I275 (2), I026 (5), I001 (2)', '', '', '6', '', '7', 'time.unit.day'),
  ('MS216', 'exp_toc', 'level.journeyman', 'Живой доспех', 'Animate Armor', E'"Оживляет" набор доспехов, исполняющие приказы создателя.\n - Выполняет простые приказы (как пёс).\n - Не думает, исполняет приказ в точности до отмены или своей смерти.\n - Если разрушить ПБ корпуса, то следующий удар в корпус "убьёт" доспех, уничтожив сердце голема.\n - Двимеритовая бомба дает штраф -2 ко всем броскам и не дает пользоваться "Перегрузкой".', '', '18', '10', 'I280 (1), I281 (1), I282 (1), I027 (3), I089 (3), I120 (1)', 'magic.form.direct', '', '14', '', '', ''),
  ('MS217', 'exp_toc', 'level.journeyman', 'Маяк неестественного', 'Beacon of the Unnatural', E'Создает мрачный тотем, который привлекает всех монстров в радиусе 1.6км для строительства гнезда в этом месте.\n - Каждый год радиус влияния растет на 1.6км. \n - Рост тотема 2м, прочность 20ПЗ.', '', '18', '15', 'I270 (1), I006 (4), T057 (1), I014 (5), I027 (1)', 'magic.form.direct', '', '14', '', '', ''),
  ('MS218', 'exp_toc', 'level.journeyman', 'Туман прошлого', 'Fog of the Past', E'Создает стеклянную конструкцию, окруженную свечами, которая показывает наиболее эмоцио-нальное событие из прошлого в месте создания.\n - Событие в ведении может длиться до 5 минут.\n - Видение повторяется раз за разом до конца ритуала.', '', '18', '10', 'I005 (5), I069 (1), I274 (5), I074 (2)', 'magic.form.direct', '', '10', '', '20', 'м'),
  ('MS219', 'exp_toc', 'level.journeyman', 'Волшебная гостевая книга', 'Magical Guestbook', E'Создает невидимую завесу на арке или дверной раме.\n - Записывает лица любых прошедших, которые вы можете получить телепатически по запросу.\n - Телепатически само предупреждает вас, если прошел кто-то конкретный, кого вы указали при создании завесы.\n - Для телепатической связи вы должны быть в пределах 100м.\n - После конца ритуала, все записи хранятся в глиняной фигурке, которую может считать любой, способный к магии, пока фигурка цела.', '', '16', '10', 'I275 (2), I002 (2), I041 (1), I027 (1)', 'magic.form.direct', '', '8', '', '1', 'time.unit.day'),
  ('MS220', 'exp_toc', 'level.master', 'Создание места силы', 'Create Place of Power', 'Создаёт Место Силы на пересечении двух Лей-линий с одинаковым элементом. - При крит.провале маг:   * Получает стихийный смешанный эффект   * Фокусирующие предметы при себе взрывается на 1d10 в радиусе 2м.   * Используемые камни взрываются, нанося 7d6 урона в радиусе 6м.', '', '20', '20', 'T110, I044 (40)', 'magic.form.direct', '', '18', '', '', ''),
  ('MS221', 'exp_toc', 'level.master', 'Зачарованный амулет', 'Enchant Amulet', E'Создает амулет, позволяющий использовать 1-4 спеллов и инвокаций, не знакомых пользователю  - При создании нужно знать каждую вложенную магию и потратить цену <b>ВЫН</b> каждой. Для активных нужно потратить по 4*<b>ВЫН</b> цены поддержки. Причем, любой предмет фокусировки бесполезен при создании.\n- При создании, если вложено больше 1 магии, нужно выбрать один негативный эффект:   * Штраф -5 к максимальным ПЗ.   * Штраф -10 к максимальной <b>ВЫН</b>.   * Штраф -1 к <b>ИНТ</b>, <b>РЕА</b>, <b>Воле</b>. Всегда болит голова. Эти штрафы сохраняются еще 24ч после снятия амулета. - Амулет дает фокусировку (2). Нельзя использовать любой другой предмет фокусировки при использовании магии амулета. - Перегрузка невозможна, нужно иметь достаточно <b>Энергии</b> для использования магии из амулета. - Жрецы и друиды могут использовать спеллы магов, но не наоборот.', '', '18', '15', 'T036 (1), T110 (1), T039 (1), I027 (2)', 'magic.form.self', '', '', '', '', ''),
  ('MS236', 'exp_toc', 'level.master', 'Голубой сон Ханмарвина (Некромантия)', 'Hanmarvyn''s Blue Dream (Necromancy)', 'Позволяет одному человеку в пределах 4м стать свидетелем последних 10 минут жизни трупа. Цель должна пройти проверку <i>(Выносливости)</i> со <b>Сл:24</b> или окажется присмерти. На время ритуала цель теряет сознание и переживает воспоминания умершего как свои собственные, чувствуя его эмоции. Под воздействием галлюциногена длительность увеличивается до 20 минут.', '', '18', '10', 'I273 (1), I027 (10), I069 (2), I074 (3), I075 (2), I078 (1), I113 (2), I098 (1), I099 (3), I122 (2)', 'magic.form.direct', '', '16', '', '10', 'time.unit.minute'),
  ('MS237', 'exp_toc', 'level.journeyman', 'Оживить труп (Некромантия)', 'Reanimate Corpse (Necromancy)', 'Насильственно возвращает душу в мёртвое тело. Труп ведёт себя как живой, но испытывает мучительную боль, не может двигаться и получает штраф -3 к сопротивлению принуждению. Для ответов на вопросы нужны неповреждённые голосовой аппарат (лёгкие, голосовые связки, рот, язык) и мозг минимум на 50%. Пытка в словесной дуэли не даёт бонусов, так как труп уже в невообразимой боли.', '', '18', '10', 'I279 (1), I275 (4), I027 (5), I274 (5), I059 (2), I122 (5), I074 (2)', 'magic.form.direct', '', '10', '3', '', ''),
  ('MS238', 'exp_toc', 'level.master', 'Синтез Кадфана (Некромантия)', 'Cadfan''s Synthesis (Necromancy)', 'Частично оживляет множество трупов, связывая их в одно амальгамированное существо - Амальгаму Трупов. Существо выполняет ваши команды, двигается и действует как голем, но не способно к высшему мышлению.', '', '22', '15', 'I278 (10), I275 (5), I030 (10), I069 (1), I076 (2), I081 (3), I027 (10), I274 (10), I059 (5), I122 (5), I074 (5)', 'magic.form.direct', '', '16', '', 'постоянное', ''),
  ('MS239', 'exp_toc', 'level.journeyman', 'Создать маяк душ (Некромантия)', 'Create Soul Beacon (Necromancy)', 'Создаёт тотем высотой 1м с черепом (10 ПЗ), усиливающий способности некроманта в пределах 6м. Только один маяк действует одновременно. Бонусы зависят от черепа: <b>Человек/Эльф:</b> -3 к Сл и стоимости ВЫН ритуалов некромантии, при провале/перегрузке бросок 1d10-2 вместо 1d10 на таблицу Беспокойных Духов. <b>Зверь/Чудовище:</b> +2 к Атаке и Защите существ, созданных некромантией, а также Отслеживание по запаху и Ночное зрение для человека в Голубом Сне Ханмарвина.', '', '16', '10', 'I277 (1), I001 (10), I027 (2), I089 (3), I012 (5), I044 (2), I020 (3), I122 (2)', 'magic.form.direct', '', '10', '', '1', 'time.unit.day'),
  ('MS240', 'exp_toc', 'level.novice', 'Неконтролируемый призыв (Гоэтия)', 'Uncontrolled Summoning (Goetia)', E'<b>Эффект:</b> Этот ритуал призыва невероятно опасен. Призванный демон не связан каким-либо кодексом поведения и не контролируется игроками. Он может напасть на них или отказаться от любой сделки без последствий. В призыве может появиться демон любого вида, в том числе старший демон. Этот ритуал является причиной большинства смертей, связанных с гоэтией.\n \n<b>Процесс:</b> Назначьте главного призывателя, который возглавит пение. Пусть они встанут вперед, а остальная часть группы будет позади них полукругом. Начертите мелом круг на земле, чтобы направить демона к вашему ритуалу. Выберите три случайных слога из своего сердца (Генератор истинного имени демона на стр. 143) и повторяйте их, визуализируя желание вашего сердца, по одному слогу за раз, не переставая, пока демон не появится.', '', '10', '10', 'I275 (1)', 'magic.form.direct', '', '0', '', 'мгновенно', ''),
  ('MS241', 'exp_toc', 'level.novice', 'Контролируемый призыв (Гоэтия)', 'Controlled Summoning (Goetia)', E'<b>Эффект:</b> Позволяет игрокам выбирать вид демона и возможность вызвать более могущественного демона. Без защиты (например, мантия из козьей шкуры) ритуал невероятно опасен и часто смертелен.\n \n<b>Процесс:</b> В миску с маслом добавьте дымную пыль и эссенцию призрака, смешав в густую пасту. Начертите этой пастой круг и поместите по краям пять незажженных свечей. Добавьте в круг предмет, привлекающий демона: для диавола - свежесрезанная плоть (больше плоти может призвать старшего диавола), для мари лвид - свежая еда и эль (пир на 100 крон для старшего), для касглидда - письмо с обещанием взаимной выгоды (большая выгода для старшего). Повторите имя демона пять раз. Если знаете настоящее имя, оно заставит демона призвать. Иначе выберите три слога из своего сердца (Генератор на стр. 143), которые звучат как настоящее имя. После каждого повторения должна загореться одна свеча. Когда все пять зажгутся, появится демон.', '', '16', '15', 'I274 (5), I074 (2), I089 (3), I008 (2)', 'magic.form.direct', '', '0', '', 'мгновенно', ''),
  ('MS242', 'exp_toc', 'level.novice', 'Ритуал Имени (Гоэтия)', 'Ritual of Naming (Goetia)', E'<b>Эффект:</b> Позволяет узнать истинное имя конкретного демона. После извлечения из огня имя можно безопасно записать. При провале проверки Проведения ритуалов уголь сгорает, а настоящее имя демона выжигается на вашей коже, отмечая вас люцифугом. Демон всегда будет знать ваше местоположение, пока вы носите эту метку, и может явиться вам на своих условиях.\n \n<b>Процесс:</b> Разожгите костер из костей зверя, угля и сухих дров (огонь должен гореть яркооранжевым). Нанесите смесь угля, пятой эссенции и собственной крови на открытую кожу. Удерживая ветку лещины, погрузите обработанную кожу в огонь. Огонь безвреден для вас и должен гореть добела некоторое время. Пока горит огонь, думайте о демоне, имя которого хотите узнать. Когда огонь погаснет, истинное имя появится в корке угля на вашей коже.', '', '18-24', '20', 'I002 (10), I006 (20), I014 (10), I089 (3), I276 (1)', 'magic.form.direct', '', '0', '', 'мгновенно', '')
),
ritual_effects_en (ms_id, text_en) AS (
  VALUES
    ('MS104', E'Cleanses the target of poisons and diseases.\n- Removes (choose one, with different DCs):\n* DC 12 — alcohol and drugs\n* DC 15 — poison and oils\n* DC 18 — diseases\n- Cannot cure the Catriona Plague.'),
    ('MS105', E'Allows you to see events from the last 2 days on the surface of water.\n* DC 15 — past events\n* DC 18 — current events\n- A mage at the location of the current events may notice they are being watched by rolling (Magical Knowledge) vs your (Ritual Crafting).'),
    ('MS106', E'Records a message into a medium as a full-height hologram of the mage.\n- Up to 5 minutes long.\n- Can be played back 1–3 times (at the mage''s choice).\n- If recorded into a perfect gemstone, the recording looks lifelike.'),
    ('MS107', E'Allows you to see current events in a flame.\n- A mage at the watched location may notice the scrying by rolling (Magical Knowledge) vs your (Ritual Crafting).'),
    ('MS108', E'Creates a healing circle.\n- Affects 1 target.\n- Heals 3 HP per turn for a target inside the circle.\n- If the target leaves the circle, it disappears.'),
    ('MS109', E'Creates a circle filled with magic.\n- The first target to enter who is capable of magic gains a bonus to Energy equal to (Ritual Crafting)/2.\n- Affects only 1 target.\n- Alternative: drain the circle to gain (1d6)/2 Fifth Essence.'),
    ('MS110', E'Creates a vortex inside a sealed clay jar.\n- Limited shelf life.\n- When the jar is broken, a random spell triggers (1d10/2):\n* Talfryn''s Prison\n* Zephyr\n* Tanio Ilchar\n* Dormyn''s Fog\n* Static Storm'),
    ('MS111', E'Summons the spirit of the dead with its mind and memories, including the cause of death.\n- The spirit can be dismissed at its will or destroyed.\n- You can speak with it at the burial site.\n- Also summons all relatives within 20 m.\n- The spirit may possess a target. Defense: roll (Resist Magic) vs (Spell Casting) immediately and every 1d6 turns at the same DC. On a failure, the spirit controls the body.\nThe target gets +5 to (Resist Magic) if the behavior is unacceptable and +10 if it is life-threatening.'),
    ('MS112', E'Allows communication with another owner of the same device.\n- Both participants must perform the ritual simultaneously.'),
    ('MS113', E'Creates a one-way (both directions) impenetrable circle for monsters.\n- To pass through in one direction, a creature rolls (Resist Magic) vs the (Ritual Crafting) roll used to create the barrier.\n- Blocks monster magic inside, but not physical projectiles.\n- The metal used must match the monster''s vulnerability.\n- Lasts until dispelled.'),
    ('MS114', E'Creates a solid barrier of light.\n- The barrier has 50 HP.\n- Impenetrable to material objects, but not to incorporeal entities.\n- Teleportation in and out is possible.\n- You may stop air exchange; then the air lasts 20 - [number of targets inside] turns.\n- You may restore the barrier by 5 HP for each 1 STA.'),
    ('MS115', E'Allows you to see the truth in a dream.\n* DC 15 — past events\n* DC 18 — current events\n- A mage at the watched location may notice the scrying by rolling (Magical Knowledge) vs your (Ritual Crafting).\n- You may share the dream with up to (Ritual Crafting) other people, but they must answer several personal questions.\n- The dream lasts until the end of the ritual.'),
    ('MS116', E'Compresses the target into a jade figurine 10× smaller than the original (range 10 m).\n- If the target fails an Endurance check at DC 15, they take 6d6 damage to the torso.\n- The target does not age, but has only 20% HP.\n- You may snap off a head or limb with a Strength check at DC 14, or by dealing 5 damage. The effects correspond to critical wounds after decompression.\n- The released target is Dazed.'),
    ('MS117', E'Creates a simple golem that obeys the creator''s commands.\n- Cannot use fine motor skills.\n- Cannot follow precise, highly detailed orders.\n- Does not think; it follows orders until canceled or until it is destroyed.'),
    ('MS118', E'Creates a controllable illusion next to the mage.\n- The illusion feels real: sight, touch, sound, and smell.\n- If the illusion attacks, the target rolls (Resist Magic) or (Endurance) at DC 12.\nOn success the illusion is revealed; on failure the target makes a Stability test. On a second failure the target is Dazed.\n- Lasts until dispelled.'),
    ('MS212', E'Turns the skull of a cat, dog, bird, or snake into a crystal skull.\n- You can activate it to turn it into the animal it was made from.\n- The animal follows mental commands it can hear while nearby.\n- When the animal dies, the skull deactivates, but can be recharged with the same ritual using [2] Fifth Essence.'),
    ('MS213', E'Enchants a trophy from a monster that the user helped kill. The worn effect depends on the monster:\n- Demon: +2 to (Spell Casting) and (Resist Magic) rolls.\n- Bruxa: you can communicate telepathically within 20 m.\n- Wendigo: immunity to diseases.\n- Wyvern: attacks gain Poison (25%).\n- Garkain: +1 to saves vs Stun.\n- Fiend: immunity to poison.\n- Golem: immunity to bleeding.\n- Griffin: when you take a critical wound, roll d10 twice and take one result.\n- Igosha: you gain the social standing "Feared"; if you already had it, the effects double.\n- Katakan: attacks gain Bleeding (25%).\n- Grave Hag: +2 to (Ritual Crafting) and (Hex Weaving).\n- Cockatrice: attacks gain Blinded (10%).\n- Leshen: you can speak with animals and can dominate them after a verbal duel; animals will not harm themselves.\n- Manticore: +2 to the DC to resist and remove your poisons.\n- Bear: enemies suffer -2 when attempting to break out of your grapple.\n- Plague Maiden: flies swarm around you. Enemies nearby take -2 to rolls and may contract Disease (10%). You suffer -2 to (Seduction), (Persuasion), and Appearance.\n- Werewolf: +2 to (Strength) and (Wilderness Survival) rolls.\n- Ozzrel: +2 to (Spell Casting) for fire magic.\n- Panther: climbing speed ×2.\n- Noonwraith: immunity to fear.\n- Rock Troll: +1 to the range multiplier for thrown weapons.\n- Succubus: +1 social standing.\n- Troll: you get drunk twice as slowly and without a hangover.\n- Foglet: +2 to (Stealth) and (Sleight of Hand).\n- Graveir: a corpse-eater will always choose another target if one exists.\n- Phoenix: -50% to the chance to ignite (minimum 0).\n- Hym: a minimum of 4 damage always bypasses enemy armor.\n- Chimera: once per day you choose resistance to one weapon damage type.\n- Cyclops: instead of being Dazed by magic, you attack the nearest living target next round.\n- Shaelmaar: +2 to (Spell Casting) for earth magic.\n- Earth Elemental: destructive damage to SP or HP is doubled.\n- Ice Elemental: attacks gain Freezing (25%).\n- Fire Elemental: attacks gain Burning (25%).'),
    ('MS214', E'Lets you learn whether an action will have a positive or negative outcome. The DC depends on the cheese (1d6, rolled secretly by the GM):\n* Standard cheese: DC [13 + 1d6]\n* High-quality cheese: DC [13 - 1d6]\nIf you succeed on (Ritual Crafting) at that DC, the GM must answer truthfully.\n- On a failure, the GM gives a random answer.\n- If the outcome is mixed, the GM gives the outcome that will happen sooner.'),
    ('MS215', E'Creates a pendant that suppresses all active and newly applied hex effects.\n- When the pendant is removed, the effects return.\n- If, by the end of the ritual''s duration, the wearer still has active hexes, the pendant cracks and the wearer (and targets within 2 m) gain several new hexes at the GM''s discretion.'),
    ('MS216', E'"Animates" a suit of armor that obeys the creator''s commands.\n- Follows simple commands (like a dog).\n- Does not think; follows orders until canceled or destroyed.\n- If the torso SP is destroyed, the next hit to the torso "kills" the armor by destroying the golem''s heart.\n- A dimeritium bomb gives -2 to all rolls and prevents using "Overcharge".'),
    ('MS217', E'Creates a grim totem that attracts all monsters within 1.6 km to build nests in the area.\n- Each year, the radius increases by 1.6 km.\n- The totem is 2 m tall and has 20 HP.'),
    ('MS218', E'Creates a glass construction surrounded by candles that shows the most emotional event from the past at the place of casting.\n- The scene may last up to 5 minutes.\n- The vision repeats over and over until the ritual ends.'),
    ('MS219', E'Creates an invisible veil on an arch or door frame.\n- Records the faces of anyone who passes through; you can receive them telepathically on request.\n- Warns you telepathically if a specific person (named during creation) passes through.\n- You must be within 100 m for the telepathic link.\n- After the ritual ends, all records are stored in a clay figurine; any magic user can read it while the figurine remains intact.'),
    ('MS220', E'Creates a Place of Power at the intersection of two Ley Lines of the same element.\nOn a critical failure the mage:\n* gains a random mixed elemental effect\n* any focusing items they carry explode for 1d10 damage in a 2 m radius\n* the stones used explode, dealing 7d6 damage in a 6 m radius'),
    ('MS221', E'Creates an amulet that allows the user to cast 1–4 spells and invocations the user does not know.\n- To create it, you must know each embedded magic and pay the full STA cost of each. For active effects, you must also pay 4*STA of each sustain cost. Any focusing item is useless during creation.\n- If more than 1 magic is embedded, choose one negative effect:\n* -5 to maximum HP\n* -10 to maximum STA\n* -1 to INT, REF, and WILL; constant headache\nThese penalties also remain for 24 hours after removing the amulet.\n- The amulet provides Focusing (2).\n- You cannot use any other focusing item when casting from the amulet.\n- Overcharge is impossible; you must have enough Energy to use the magic from the amulet.\n- Priests and druids can use mage spells, but not vice versa.'),
    ('MS236', 'Allows one person within 4m to witness the last 10 minutes of a corpse''s life. The target must make a DC:24 Endurance check or fall into a dying state. For the ritual''s duration, the target falls unconscious and experiences the corpse''s memories as their own, feeling that person''s emotions. Under the influence of a Hallucinogen, duration increases to 20 minutes.'),
    ('MS237', 'Forcibly returns a soul to its dead body. The corpse acts as though alive but is in excruciating pain, cannot move, and suffers -3 to Resist Coercion checks. To answer questions, it needs intact vocal apparatus (lungs, vocal cords, mouth, tongue) and at least 50% of its brain. Torture in Verbal Combat gives no bonuses as the corpse is already in unimaginable pain.'),
    ('MS238', 'Partially animates many corpses, binding them into a single amalgamated creature - a Corpse Amalgam. The creature follows your commands, moves and acts like a golem, but is no longer capable of higher thought.'),
    ('MS239', 'Creates a 1m tall totem with a skull (10 HP) that enhances a Necromancer''s abilities within 6m. Only one beacon works at a time. Bonuses depend on the skull: <b>Human/Elderfolk:</b> -3 to DC and STA cost of necromancy rituals, roll 1d10-2 instead of 1d10 on Restless Spirits table on fumble/overdraw. <b>Beast/Monster:</b> +2 to Attack and Defense for creatures created by necromancy, plus Scent Tracking and Night Vision for a person in Hanmarvyn''s Blue Dream.'),
    ('MS240', E'<b>Effect:</b> This summoning ritual is incredibly dangerous. The summoned demon is not bound by any code of conduct and is not controlled by the players. It may attack them or go back on any deal made with them, with no consequences. A demon of any species, including greater demons, may appear. This ritual is responsible for most deaths associated with goetia.\n\n<b>Process:</b> Designate a chief summoner to lead the chant. Have the chief summoner stand forward, with the rest of your group behind them in a semicircle. Scribe a chalk circle into the ground before them to guide the demon. Pick three syllables from your heart (the Demon True Name Generator on Pg.143) at random. Chant these syllables one at a time, without ceasing, while visualizing your heart''s desire, until a demon appears.'),
    ('MS241', E'<b>Effect:</b> This ritual allows players to choose the demon species and whether to summon a more powerful version. It is incredibly dangerous, and often deadly, without specific protections (e.g., a Goatskin Mantle) or protections tailored to the summoned demon.\n\n<b>Process:</b> Mix infused dust and essence of wraith into a thick paste in a bowl of oil. Spread this paste into a circle. Place five unlit candles equally spread outside the circle. Add an item beloved by the specific demon species to be summoned into the circle. For Bes: participants offer freshly cut flesh. More flesh can summon a greater bes. For Mari Lywd: fill the circle with fresh food and ale. To attract a greater mari lywd, prepare a feast (100 crowns). For Casglydd: place a letter of introduction in the circle, promising mutual benefit. To attract a greater casglydd, over-promise in the letter. Chant the demon''s name five times. If the true name is known, it forces the summoning. Otherwise, pick three syllables "from your heart" (referencing a "Demon True Name Generator on Pg.143"), which sounds like a true name and attracts a demon. After each repetition of the chant, one candle lights itself. When all five are lit, the demon appears.'),
    ('MS242', E'<b>Effect:</b> This ritual allows the player to learn the true name of a specific demon. Once removed from the fire, the name can be safely recorded to save for later. If you fail the Ritual Crafting check: Upon removing your skin from the fire, you find the coal had burned off during the ritual and the true name of a demon has been burned into your skin, marking you with a Lucifuge. You may have discovered the true name of a demon, but it will forever know where you are while you bear this mark, and may appear to you on its own terms, as it wishes.\n\n<b>Process:</b> Create a bonfire of beast bones, coal, and dry wood. The fire must be hot enough to burn bright orange. Rub a mixture of coal, fifth essence, and your own blood onto your exposed skin to protect it. While holding a branch of hazel, submerge the treated skin into the fire. The fire will be harmless to you, and should burn white hot for a while before going out. While the fire burns hot, think of a demon whose true name you wish to discover. When the fire expires, remove your skin from the fire. The true name of the demon should appear in the crust of the coal coating your skin.')
),
ins_i18n AS (
INSERT INTO i18n_text (id, entity, entity_field, lang, text)
SELECT * FROM (
SELECT ck_id('witcher_cc.magic.ritual.name.'||rd.ms_id),
'magic',
           'ritual_names',
           'ru',
           rd.name_ru
      FROM raw_data rd
     WHERE nullif(rd.name_ru,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.ritual.name.'||rd.ms_id),
           'magic',
           'ritual_names',
           'en',
           rd.name_en
      FROM raw_data rd
     WHERE nullif(rd.name_en,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.ritual.effect.'||rd.ms_id),
           'magic',
           'ritual_effects',
           'ru',
           regexp_replace(replace(replace(rd.effect_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.effect_ru,'') IS NOT NULL
    UNION ALL
    -- effects EN (from manual translations)
    SELECT ck_id('witcher_cc.magic.ritual.effect.'||ree.ms_id),
           'magic',
           'ritual_effects',
           'en',
           ree.text_en
      FROM ritual_effects_en ree
    UNION ALL
    SELECT ck_id('witcher_cc.magic.ritual.how_to_remove.'||rd.ms_id),
           'magic',
           'ritual_how_to_remove',
           'ru',
           regexp_replace(replace(replace(rd.how_to_remove_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.how_to_remove_ru,'') IS NOT NULL
    UNION ALL
    SELECT ck_id('witcher_cc.magic.ritual.how_to_remove.'||rd.ms_id),
           'magic',
           'ritual_how_to_remove',
           'en',
           regexp_replace(replace(replace(rd.how_to_remove_ru, chr(11), E'\n'), chr(13), ''), '<[^>]+>', '', 'g')
      FROM raw_data rd
     WHERE nullif(rd.how_to_remove_ru,'') IS NOT NULL
  ) foo
  ON CONFLICT (id, lang) DO UPDATE
    SET text = EXCLUDED.text
)
INSERT INTO wcc_magic_rituals (
  ms_id, dlc_dlc_id,
  level_id, form_id,
  effect_time_unit_id,
  preparing_time_unit_id,
  name_id, effect_id, how_to_remove_id,
  dc,
  preparing_time_value,
  ingredients,
  zone_size,
  stamina_cast, stamina_keeping,
  effect_time_value
)
SELECT rd.ms_id
     , rd.dlc_dlc_id
     , CASE WHEN nullif(rd.level_key,'') IS NOT NULL THEN ck_id(rd.level_key) ELSE NULL END AS level_id
     , CASE WHEN nullif(rd.form_key,'') IS NOT NULL THEN ck_id(rd.form_key) ELSE NULL END AS form_id
     , CASE
         WHEN rd.effect_time_unit_key LIKE 'time.unit.%' THEN ck_id(rd.effect_time_unit_key)
         ELSE NULL
       END AS effect_time_unit_id
     , ck_id('time.unit.round') AS preparing_time_unit_id
     , ck_id('witcher_cc.magic.ritual.name.'||rd.ms_id) AS name_id
     , ck_id('witcher_cc.magic.ritual.effect.'||rd.ms_id) AS effect_id
     , CASE WHEN nullif(rd.how_to_remove_ru,'') IS NOT NULL THEN ck_id('witcher_cc.magic.ritual.how_to_remove.'||rd.ms_id) ELSE NULL END AS how_to_remove_id
     , nullif(rd.dc,'')
     , NULLIF(rd.preparing_time_value,'')::int
     , CASE
         WHEN rd.ingredients_raw IS NULL OR trim(rd.ingredients_raw) = '' THEN NULL
         ELSE (
           SELECT
             CASE
               WHEN jsonb_agg(comp.obj ORDER BY comp.pos) IS NULL THEN NULL
               ELSE jsonb_agg(comp.obj ORDER BY comp.pos)
             END
           FROM (
             SELECT
               pieces.pos,
               jsonb_build_object(
                 'id',
                 (
                   CASE
                     WHEN pieces.code ~ '^I[0-9]{3}$' THEN ck_id('witcher_cc.items.ingredient.name.'||pieces.code)
                     WHEN pieces.code ~ '^T[0-9]{3}$' THEN ck_id('witcher_cc.items.general_gear.name.'||pieces.code)
                     ELSE NULL
                   END
                 )::text,
                 'qty',
                 pieces.qty
               ) AS obj
             FROM (
               SELECT
                 part.ord * 10 AS pos,
                 CASE
                   WHEN (regexp_match(trim(part.part_raw), '\((\d+)\)\s*$')) IS NOT NULL 
                   THEN (regexp_match(trim(part.part_raw), '\((\d+)\)\s*$'))[1]::int
                   ELSE NULL
                 END AS qty,
                 trim(regexp_replace(trim(part.part_raw), '\s*\([^)]*\)\s*$', '')) AS code
               FROM (
                 SELECT token AS part_raw, ord
                 FROM regexp_split_to_table(rd.ingredients_raw, '\s*,\s*') WITH ORDINALITY AS s(token, ord)
               ) part
             ) pieces
             WHERE pieces.code IS NOT NULL AND pieces.code <> '' AND pieces.code ~ '^[IT][0-9]{3}$'
           ) comp
           WHERE (comp.obj->>'id') IS NOT NULL
         )
       END AS ingredients
     , nullif(rd.zone_size,'')
     , nullif(rd.stamina_cast,'')
     , nullif(rd.stamina_keeping,'')
     , CASE
         WHEN nullif(rd.effect_time_value,'') IS NULL THEN NULL
         WHEN rd.effect_time_unit_key LIKE 'time.unit.%' THEN nullif(rd.effect_time_value,'')
         WHEN nullif(rd.effect_time_unit_key,'') IS NOT NULL THEN (nullif(rd.effect_time_value,'') || ' ' || rd.effect_time_unit_key)
         ELSE nullif(rd.effect_time_value,'')
       END AS effect_time_value
  FROM raw_data rd
ON CONFLICT (ms_id) DO UPDATE
SET
  dlc_dlc_id = EXCLUDED.dlc_dlc_id,
  level_id = EXCLUDED.level_id,
  form_id = EXCLUDED.form_id,
  effect_time_unit_id = EXCLUDED.effect_time_unit_id,
  preparing_time_unit_id = EXCLUDED.preparing_time_unit_id,
  name_id = EXCLUDED.name_id,
  effect_id = EXCLUDED.effect_id,
  how_to_remove_id = EXCLUDED.how_to_remove_id,
  dc = EXCLUDED.dc,
  preparing_time_value = EXCLUDED.preparing_time_value,
  ingredients = EXCLUDED.ingredients,
  zone_size = EXCLUDED.zone_size,
  stamina_cast = EXCLUDED.stamina_cast,
  stamina_keeping = EXCLUDED.stamina_keeping,
  effect_time_value = EXCLUDED.effect_time_value;

-- <<< END sql/items/030_wcc_magic_rituals.sql

